// Saveur N°5 — Recettes France (209 recettes)
RECIPES.push(
{id:"AC001",co:"France",cat:"Accompagnement",sous:"Pommes de terre",nom:"Gratin de Pommes de Terre Sarladaises",chef:"Tradition périgourdine",bp:6,prep:20,cui:60,diff:1,qual:5,ig:[["Pommes de terre à chair ferme",1200,"g"],["Graisse de canard",80,"g"],["Ail",4,"gousses"],["Persil plat haché",3,"cs"],["Sel poivre",1,"qs"]],et:"1. Four 190°C. Éplucher et trancher les pommes de terre en rondelles de 3mm (mandoline). NE PAS rincer.\n2. Faire fondre la graisse de canard dans une grande poêle. Ajouter les pommes de terre + ail haché fin.\n3. Remuer délicatement pour enrober chaque tranche.\n4. Verser dans un plat à gratin. Tasser légèrement. Saler, poivrer.\n5. Four 190°C 50-60 min. Parsemer de persil en sortant du four.",vin:"Pécharmant rouge ou Bergerac",notes:"La graisse de canard est irremplaçable. Elle donne une saveur et un croustillant impossible à obtenir avec du beurre ou de l'huile."},
{id:"AC002",co:"France",cat:"Accompagnement",sous:"Légumes",nom:"Haricots Verts Fins à la Française",chef:"Tradition française",bp:4,prep:10,cui:10,diff:1,qual:4,ig:[["Haricots verts extra-fins",500,"g"],["Beurre",30,"g"],["Échalotes",2,"pièces"],["Fleur de sel",1,"qs"],["Gros sel pour l'eau",20,"g"]],et:"1. Grande casserole d'eau bouillante très salée (comme de l'eau de mer).\n2. Cuire les haricots 5-6 min — ils doivent rester verts et légèrement croquants.\n3. Plonger IMMÉDIATEMENT dans un grand bol d'eau glacée. Égoutter après 1 min.\n4. Au moment de servir : fondre beurre dans une poêle. Suer échalotes ciselées 2 min.\n5. Ajouter les haricots. Sauter 2 min à feu vif. Fleur de sel. Servir sans attendre.",vin:"Accompagnement universel",notes:"Le choc thermique eau bouillante → eau glacée fixe la couleur verte. Ne jamais couvrir les haricots pendant la cuisson."},
{id:"AC003",co:"France",cat:"Accompagnement",sous:"Riz",nom:"Riz Pilaf",chef:"Tradition française classique",bp:4,prep:5,cui:20,diff:1,qual:4,ig:[["Riz long grain basmati",300,"g"],["Beurre",30,"g"],["Oignon",1,"pièce"],["Bouillon de volaille chaud",55,"cl"],["Bouquet garni",1,"pièce"],["Sel",1,"qs"]],et:"1. Four 180°C ou casserole à couvercle épais.\n2. Suer l'oignon haché finement dans le beurre sans colorer.\n3. Ajouter le riz. Nacrer 2 min en remuant : les grains doivent devenir translucides.\n4. Verser le bouillon chaud d'un coup (ratio 1,8:1). Bouquet garni. Sel.\n5. Porter à frémissement. Couvrir hermétiquement. Four 18 min ou feu très doux 18 min. Ne jamais soulever le couvercle. Égrener au beurre.",vin:"Accompagnement de viandes et poissons en sauce",notes:"Le nacrage est l'étape clé. Il imperméabilise les grains et empêche la surcuisson."},
{id:"AC004",co:"France",cat:"Accompagnement",sous:"Purée",nom:"Purée de Pommes de Terre Robuchon",chef:"Tradition française — Joël Robuchon",bp:4,prep:20,cui:30,diff:2,qual:5,ig:[["Pommes de terre Ratte ou BF15",1000,"g"],["Beurre très froid en dés",250,"g"],["Lait entier chaud",20,"cl"],["Gros sel",20,"g"],["Sel fin poivre blanc",1,"qs"]],et:"1. Cuire les pommes de terre entières non pelées dans l'eau très salée. Elles sont cuites quand la lame passe sans résistance.\n2. Peler immédiatement à chaud. Passer au moulin à légumes (grille fine) — JAMAIS au mixeur.\n3. Dessécher la purée sur feu vif en remuant 2 min.\n4. Incorporer le beurre froid en dés UN PAR UN en fouettant vigoureusement entre chaque.\n5. Incorporer le lait chaud en filet en fouettant. Assaisonner. Passer au tamis fin si désiré.",vin:"Accompagnement de tous les plats mijotés",notes:"La purée Robuchon contient 1 part de beurre pour 2 parts de pommes de terre. C'est la plus riche et la plus onctueuse du monde. Le moulin à légumes est indispensable."},
{id:"AC005",co:"France",cat:"Accompagnement",sous:"Légumes",nom:"Ratatouille de Légumes Confits",chef:"Tradition provençale",bp:6,prep:30,cui:90,diff:2,qual:5,ig:[["Aubergines",2,"pièces"],["Courgettes",3,"pièces"],["Poivrons rouges",2,"pièces"],["Tomates mûres",4,"pièces"],["Oignons",2,"pièces"],["Ail",4,"gousses"],["Huile d'olive",10,"cs"],["Thym romarin basilic",1,"qs"]],et:"1. Cuire chaque légume SÉPARÉMENT dans l'huile d'olive jusqu'à très fondant. Saler entre chaque.\n2. Suer oignons + ail jusqu'à presque confiture.\n3. Ajouter tomates concassées + herbes. Compoter 15 min.\n4. Réunir délicatement tous les légumes dans la sauce tomate. Mélanger très doucement.\n5. Cuire ensemble 20 min à feu très doux. Rectifier. Basilic frais.",vin:"Rosé de Provence ou Côtes du Rhône blanc",notes:"La cuisson séparée de chaque légume est la différence entre une ratatouille et une soupe de légumes."},
{id:"AS_FR01",co:"France",cat:"Assaisonnement",sous:"Sel aromatisé",nom:"Sel aux Herbes de Provence",chef:"Tradition provençale",bp:4,prep:10,cui:0,diff:1,qual:4,ig:[["Gros sel de mer",200,"g"],["Thym séché",2,"cs"],["Romarin séché",1,"cs"],["Sarriette séchée",1,"cs"],["Lavande cullinaire séchée",0.5,"cs"],["Laurier poudre",0.5,"cc"],["Fenouil graine",0.5,"cc"]],et:"1. Sécher légèrement les herbes quelques heures à T° ambiante si elles ne le sont pas assez.\n2. Mixer grossièrement les herbes séchées avec le laurier + fenouil.\n3. Mélanger avec le gros sel. Ne pas mixer le sel.\n4. Répartir dans des bocaux hermétiques.\n5. Laisser sécher et infuser 1 semaine avant utilisation.",vin:"Grillades, légumes, poissons",notes:"Ce sel se conserve 1 an. Idéal en cadeau gastronomique. Utiliser généreusement sur les grillades."},
{id:"FR001",co:"France",cat:"Entrée",sous:"Soupe / Velouté",nom:"Soupe d'Artichaut à la Truffe Noire",chef:"Guy Savoy",bp:4,prep:30,cui:30,diff:3,qual:4,ig:[["Fonds d'artichaut",6,"pièces"],["Échalotes",2,"pièces"],["Beurre",20,"g"],["Bouillon de volaille maison",100,"cl"],["Truffe noire fraîche hachée",50,"g"],["Jus de truffe",2.5,"cl"],["Huile de truffe",2.5,"cl"],["Parmesan 24 mois râpé",150,"g"],["Crème fleurette 35% MG",30,"cl"]],et:"1. Tourner les artichauts, tailler en dés, eau citronnée.\n2. Suer les échalotes au beurre 5 min sans coloration.\n3. Ajouter fonds égouttés, nacrer 3 min.\n4. Mouiller bouillon, frémir 20 min.\n5. Mixer fin, passer au chinois fin.\n6. Incorporer truffe hachée + jus + huile de truffe. Assaisonner.\n7. Espuma parmesan : crème bouillie + parmesan hors feu, verser dans siphon ISI 2 cartouches.\n8. Service : velouté dans bols préchauffés + espuma + lamelles de truffe fraîche.",vin:"Chablis 1er Cru Montée de Tonnerre ou Meursault Charmes",notes:"Plat signature de Guy Savoy depuis +30 ans. Ne jamais faire bouillir après ajout de la truffe. Le parmesan compense le sel."},
{id:"FR002",co:"France",cat:"Entrée",sous:"Soupe / Velouté",nom:"Soupe aux Truffes Noires VGE",chef:"Paul Bocuse",bp:4,prep:45,cui:60,diff:4,qual:4,ig:[["Noilly Prat",4,"cs"],["Jus de truffe",4,"cs"],["Consommé double de bœuf maison",80,"cl"],["Truffes noires fraîches",100,"g"],["Foie gras en dés",80,"g"],["Blanc de poulet cuit en dés",80,"g"],["Brunoise de légumes étuvée",80,"g"],["Pâte feuilletée pur beurre",250,"g"],["Jaunes d'œufs pour dorure",2,"pièces"]],et:"1. Consommé double maison : bouillon de poule + légumes, clarifier, filtrer.\n2. Pocher le blanc de poulet 6 min, tailler en dés.\n3. Étuver légumes en brunoise au beurre, feu doux 8 min.\n4. Tailler les truffes en lamelles fines.\n5. Dans chaque bol : 1 cs Noilly Prat + brunoise + foie gras + poulet + truffes + consommé à 1,5 cm du bord.\n6. Découper des disques de feuilletage Ø = bol +3 cm. Dorer intérieur à l'œuf battu. Souder sur le bol.\n7. Dorer le dessus. Enfourner 200°C 20 min jusqu'à belle coloration dorée.",vin:"Champagne Bollinger RD ou Riesling Cuvée Frédéric Émile Trimbach",notes:"Créé le 25 fév. 1975 à l'Élysée pour la remise de la Légion d'honneur de Bocuse par VGE."},
{id:"FR003",co:"France",cat:"Entrée",sous:"Terrine / Charcuterie fine",nom:"Terrine de Foie Gras au Torchon",chef:"Alain Ducasse",bp:8,prep:30,cui:25,diff:4,qual:4,ig:[["Foie gras de canard Extra déveiné frais",500,"g"],["Sel fin",8,"g"],["Poivre blanc moulu",2,"g"],["Sucre semoule",2,"g"],["Porto blanc ou Sauternes",5,"cl"],["Armagnac",5,"cl"],["Noix de muscade",1,"pincée"]],et:"1. Sortir le foie gras du frigo 30 min. Retirer les veines principales.\n2. Mélanger sel + poivre + sucre + muscade. Assaisonner les 2 faces.\n3. Arroser d'Armagnac et Porto, masser délicatement. Filmer, réfrigérer 12 h minimum.\n4. Rouler dans le torchon de lin en boudin serré, ficeler les extrémités.\n5. Pocher dans eau frémissante à 70°C exactement pendant 20 min. NE PAS bouillir.\n6. Laisser refroidir dans l'eau 30 min, réfrigérer 48 h minimum.\n7. Servir tranché avec fleur de sel, pain brioché grillé et confiture de figues.",vin:"Sauternes Château d'Yquem ou Monbazillac Cuvée Prestige",notes:"Le foie gras doit être de catégorie Extra. La cuisson à 70°C garantit une texture fondante. Se conserve 5–6 jours au frigo."},
{id:"FR004",co:"France",cat:"Entrée",sous:"Poisson / Mer",nom:"Saint-Jacques Poêlées, Mâche et Truffe Noire",chef:"Alain Ducasse",bp:4,prep:20,cui:5,diff:3,qual:4,ig:[["Saint-Jacques de plongée calibre 20/30",16,"pièces"],["Truffe noire fraîche",50,"g"],["Mâche ou épinards pousses",80,"g"],["Huile de truffe pour vinaigrette",3,"cs"],["Vinaigre de xérès",1,"cs"],["Beurre clarifié",40,"g"]],et:"1. Préparer la vinaigrette truffe : émulsionner huile de truffe + vinaigre de xérès + sel + poivre.\n2. Nettoyer et sécher les Saint-Jacques sur papier absorbant.\n3. Chauffer poêle en inox ou fonte à feu très vif. Ajouter beurre clarifié.\n4. Saisir Saint-Jacques côté plat 1 min 30 sans les toucher, retourner, 45 sec. Dorées en surface, nacrées à cœur.\n5. Assaisonner de fleur de sel et poivre blanc.\n6. Assaisonner la mâche avec la vinaigrette truffe.\n7. Dresser : lit de mâche + Saint-Jacques + râpée de truffe noire fraîche.",vin:"Chablis Grand Cru Bougros ou Puligny-Montrachet",notes:"Ne jamais surcharger la poêle – cuire 4 Saint-Jacques à la fois max. La truffe doit être râpée au dernier moment."},
{id:"FR005",co:"France",cat:"Plat",sous:"Crustacés",nom:"Homard Breton à l'Armoricaine",chef:"Alain Ducasse",bp:4,prep:40,cui:40,diff:4,qual:4,ig:[["Homards bretons vivants 700 g pièce",2,"pièces"],["Échalotes",4,"pièces"],["Ail en chemise",4,"gousses"],["Tomates mûres concassées",400,"g"],["Cognac fine champagne",10,"cl"],["Vin blanc sec Muscadet",25,"cl"],["Estragon frais",1,"branche"],["Thym",2,"branches"],["Beurre fin",30,"g"],["Huile d'olive",3,"cs"],["Piment de Cayenne",1,"pincée"]],et:"1. Blanchir homards vivants 1 min dans eau salée bouillante. Égoutter. Détacher têtes et pattes. Décortiquer les queues ; concasser têtes et pattes.\n2. Suer carapaces concassées dans huile d'olive à feu vif 8 min.\n3. Ajouter échalotes + ail écrasé, dorer 2 min.\n4. Déglacer au cognac – flamber. Réduire à sec.\n5. Mouiller vin blanc, réduire de moitié.\n6. Ajouter tomates + herbes + piment de Cayenne. Compoter 5 min.\n7. Couvrir d'eau, cuire 20 min à feu moyen. Passer au chinois. Réduire jusqu'à texture sirupeuse.\n8. Sauter queues et pinces de homard au beurre mousseux 2–3 min. Napper de sauce.",vin:"Chablis Grand Cru Valmur ou Chassagne-Montrachet",notes:"Publié dans Ma Bretagne – Éditions Alain Ducasse. Flambage au cognac essentiel pour la profondeur aromatique."},
{id:"FR006",co:"France",cat:"Plat",sous:"Poisson",nom:"Escalope de Saumon à l'Oseille",chef:"Pierre & Jean Troisgros",bp:4,prep:20,cui:10,diff:3,qual:4,ig:[["Saumon sauvage filet",600,"g"],["Oseille fraîche équeutée",200,"g"],["Échalotes hachées",3,"pièces"],["Sancerre ou Chablis",15,"cl"],["Noilly Prat",5,"cl"],["Fumet de poisson maison",15,"cl"],["Crème fraîche double 40% MG",20,"cl"],["Beurre fin très froid",50,"g"],["Jus de citron",1,"cc"]],et:"1. Escaloper le filet de saumon en tranches de biais. Aplatir entre 2 feuilles de papier sulfurisé huilé. Réserver au frais.\n2. Sauce : échalotes + Sancerre + vermouth + fumet, réduire feu doux jusqu'à quasi évaporation.\n3. Ajouter crème fraîche, réduire légèrement.\n4. Jeter l'oseille dans la sauce 20 secondes – mouvement de rotation (ne pas fouetter).\n5. Hors feu, incorporer le beurre froid en dés en rotation. Quelques gouttes de citron. Réserver au chaud.\n6. Chauffer grande poêle anti-adhésive à sec à feu vif. Saisir les escalopes 20 sec d'un côté, retourner, 15 sec. Le saumon doit être sous-cuit.\n7. Répartir la sauce dans les assiettes chaudes. Poser les escalopes dessus. Servir sans attendre.",vin:"Pouilly-Fumé Henri Bourgeois ou Sancerre Rouge léger",notes:"Créé en 1962 à Roanne – plat révolutionnaire de la Nouvelle Cuisine. Le saumon ne doit jamais être pleinement cuit."},
{id:"FR007",co:"France",cat:"Plat",sous:"Viande – Mijotés",nom:"Bœuf Bourguignon",chef:"Paul Bocuse",bp:8,prep:30,cui:180,diff:3,qual:4,ig:[["Paleron ou gîte à la noix en cubes 80 g",2000,"g"],["Pinot noir de Bourgogne",75,"cl"],["Cognac",20,"cl"],["Lardons demi-sel blanchis",200,"g"],["Petits oignons grelots",200,"g"],["Champignons de Paris en quartiers",300,"g"],["Carottes en rondelles",3,"pièces"],["Échalotes émincées",4,"pièces"],["Ail écrasé",4,"gousses"],["Concentré de tomates",2,"cs"],["Fond brun de veau",20,"cl"],["Beurre fin",40,"g"]],et:"1. Dorer les cubes de bœuf en petites quantités dans la cocotte. Réserver. Suer carottes + échalotes 5 min. Singer 1 cs farine, 2 min.\n2. Remettre la viande. Flamber au cognac. Mouiller avec Pinot noir + fond de veau. Ajouter concentré de tomates, bouquet garni, zeste d'orange, ail écrasé. Porter à frémissement.\n3. Enfourner à 135°C pendant 2h30–3h.\n4. À mi-cuisson : glacer les oignons grelots. Sauter les champignons au beurre. Ajouter lardons + oignons + champignons en fin de cuisson.\n5. Retirer le bouquet garni. Réduire à découvert si la sauce est trop liquide.",vin:"Gevrey-Chambertin Vieilles Vignes ou Pommard 1er Cru",notes:"Ne jamais bouillir – toujours frémir. Le paleron est supérieur au filet pour ce plat. Se bonifie réchauffé le lendemain."},
{id:"FR008",co:"France",cat:"Plat",sous:"Viande – Rôtis",nom:"Gigot d'Agneau de 7 Heures",chef:"Alain Ducasse",bp:6,prep:30,cui:420,diff:3,qual:4,ig:[["Gigot d'agneau des Pyrénées",2500,"g"],["Vin blanc sec",75,"cl"],["Fond de veau",50,"cl"],["Têtes d'ail entières non pelées",2,"pièces"],["Oignons en quartiers",3,"pièces"],["Carottes en rondelles",4,"pièces"],["Branches de céleri",2,"pièces"],["Thym",3,"branches"],["Laurier",2,"feuilles"],["Romarin",1,"branche"],["Huile d'olive",4,"cs"]],et:"1. Ficeler le gigot pour le maintenir compact. Saisir sur toutes les faces dans une cocotte ovale à huile d'olive très chaude.\n2. Ajouter légumes + ail + herbes autour du gigot.\n3. Mouiller avec vin blanc + fond de veau jusqu'à mi-hauteur. Saler, ajouter quelques grains de poivre.\n4. Poser le couvercle, luter si possible (pâte farine + eau pour rendre hermétique).\n5. Enfourner à 120°C pendant 7 h exactement. Ne pas ouvrir pendant la cuisson.\n6. La viande doit être confite et se détacher à la fourchette. Filtrer et réduire le jus pour la sauce.",vin:"Gigondas ou Bandol rouge ou Cahors Clos Triguedina",notes:"La cuisson 7 heures transforme totalement la texture. L'os se retire à la main. Ne jamais ouvrir la cocotte avant la fin."},
{id:"FR009",co:"France",cat:"Plat",sous:"Volaille",nom:"Poularde de Bresse à la Crème d'Estragon",chef:"Paul Bocuse",bp:6,prep:20,cui:70,diff:3,qual:4,ig:[["Poularde de Bresse Label Rouge AOC",2000,"g"],["Estragon frais",1,"bouquet"],["Beurre fin",50,"g"],["Crème fraîche épaisse 40% MG",50,"cl"],["Jaunes d'œufs",3,"pièces"]],et:"1. Farcir l'intérieur de la poularde avec l'estragon frais + sel de Guérande + noix de beurre. Brider. Assaisonner l'extérieur.\n2. Poser dans cocotte ovale en fonte, ajouter ½ bouteille d'eau.\n3. Cuisson four à 150°C, 55 min à couvert. Arroser toutes les 15 min.\n4. Sauce : récupérer le jus de cuisson, réduire 5 min. Ajouter crème fraîche, mélanger.\n5. Hors feu impérativement : lier avec les jaunes d'œufs + un peu de crème chaude en fouettant (liaison à la nappe, 80°C max). Incorporer beurre. Poivrer, goûter.\n6. Dresser en taillant la volaille en salle. Napper de sauce. Garnir de feuilles d'estragon blanchies.",vin:"Meursault ou Puligny-Montrachet Les Pucelles ; rouge léger : Volnay",notes:"La poularde de Bresse AOC est irremplaçable. Surtout ne jamais lier la sauce sur feu vif."},
{id:"FR010",co:"France",cat:"Plat",sous:"Accompagnement",nom:"Purée de Pommes de Terre – La Légendaire",chef:"Joël Robuchon",bp:4,prep:15,cui:35,diff:3,qual:4,ig:[["Pommes de terre Ratte ou BF15",1000,"g"],["Beurre fin très froid en dés",250,"g"],["Lait entier",25,"cl"]],et:"1. Laver les pommes de terre avec leur peau. Recouvrir d'eau froide. Saler 10 g/L. Cuire à frémissement 20–25 min.\n2. Égoutter. Éplucher encore tièdes.\n3. Remettre dans casserole vide sur feu très doux 5 min en remuant.\n4. Passer au moulin à légumes grille fine – JAMAIS de mixeur.\n5. Chauffer le lait entier à ébullition. Incorporer le beurre très froid en dés progressivement en fouettant vigoureusement.\n6. Verser le lait chaud progressivement jusqu'à onctuosité voulue. Assaisonner.\n7. Passer au tamis fin pour une finesse ultime. Servir immédiatement.",vin:"Accompagnement universel",notes:"250 g de beurre pour 1 kg de pommes de terre : ce n'est pas une erreur. Les Rattes de Jouy-le-Châtel sont les meilleures."},
{id:"FR011",co:"France",cat:"Plat",sous:"Poisson",nom:"Sole Meunière au Beurre Noisette",chef:"Joël Robuchon",bp:4,prep:15,cui:12,diff:2,qual:4,ig:[["Soles entières préparées 400–500 g pièce",4,"pièces"],["Beurre fin",100,"g"],["Farine T45",50,"g"],["Huile de tournesol",2,"cs"],["Citron non traité",1,"pièce"],["Câpres",2,"cs"],["Persil plat ciselé",1,"bouquet"]],et:"1. Fariner légèrement les soles des deux côtés, secouer l'excédent.\n2. Chauffer dans une grande poêle l'huile de tournesol + une noix de beurre à feu moyen-vif. Déposer les soles côté peau foncée en premier.\n3. Cuire 3–4 min jusqu'à belle dorure. Retourner délicatement, cuire encore 3–4 min.\n4. Réserver les soles sur assiettes chauffées. Assaisonner de fleur de sel.\n5. Vider la poêle, essuyer légèrement. Mettre le reste du beurre à feu moyen. Laisser fondre et prendre couleur noisette. ARRÊTER LE FEU dès la couleur atteinte.\n6. Ajouter le jus du citron + câpres dans le beurre noisette hors feu.\n7. Verser le beurre noisette sur les soles. Parsemer de persil ciselé. Servir immédiatement.",vin:"Muscadet de Sèvre et Maine sur Lie ou Chablis Premier Cru",notes:"La sole doit être très fraîche. Le beurre noisette doit être arrêté au bon moment – il continue de cuire dans la poêle chaude."},
{id:"FR012",co:"France",cat:"Plat",sous:"Abats / Spécialités",nom:"Foie Gras Poêlé aux Pommes Caramélisées",chef:"Alain Ducasse",bp:4,prep:15,cui:10,diff:3,qual:4,ig:[["Tranches de foie gras frais 80 g x 2 cm",4,"pièces"],["Pommes Reine des Reinettes",2,"pièces"],["Beurre clarifié",40,"g"],["Beurre fin",40,"g"],["Sucre de canne",30,"g"],["Vinaigre balsamique vieux 15 ans",4,"cs"]],et:"1. Sortir le foie gras 20 min à l'avance. Assaisonner des deux côtés de fleur de sel et poivre.\n2. Couper les pommes en tranches épaisses (1 cm). Caraméliser au beurre + sucre, 2 min chaque côté. Réserver au chaud.\n3. Chauffer une poêle en fonte à feu TRÈS vif (sans matière grasse). Saisir le foie gras 45 sec–1 min par face : surface caramélisée, intérieur rosé et fondant.\n4. Déglacer la poêle au vinaigre balsamique. Réduire 30 sec.\n5. Dresser : pommes en éventail + escalope de foie gras dessus + réduction balsamique. Fleur de sel au dernier moment.",vin:"Sauternes Château d'Yquem ou Gewurztraminer Vendanges Tardives",notes:"Le foie gras ne doit cuire que très peu (T° intérieure cible 55°C). Toujours du foie gras Extra."},
{id:"FR013",co:"France",cat:"Plat",sous:"Abats / Spécialités",nom:"Ris de Veau Braisé aux Champignons des Bois",chef:"Alain Ducasse",bp:4,prep:60,cui:40,diff:4,qual:4,ig:[["Ris de veau de lait extra dégorgés 12 h",600,"g"],["Girolles fraîches ou cèpes",300,"g"],["Échalotes",4,"pièces"],["Beurre fin",60,"g"],["Vin blanc sec",10,"cl"],["Fond blanc de veau",25,"cl"],["Crème fleurette 35% MG",10,"cl"],["Jus de citron",1,"cs"],["Persil plat ciselé",0.5,"bouquet"]],et:"1. Dégorger les ris de veau 12 h dans l'eau froide légèrement vinaigrée au frigo. Renouveler l'eau 2 fois.\n2. Pocher les ris dans l'eau salée froide, porter à frémissement, cuire 10 min. Égoutter, rafraîchir. Parer : retirer la fine membrane extérieure.\n3. Presser les ris sous un poids 30 min au frigo pour les raffermir.\n4. Dans une sauteuse, faire fondre 30 g de beurre à feu moyen-vif. Faire dorer les ris pressés sur toutes les faces 4–5 min jusqu'à belle croûte caramélisée. Réserver.\n5. Dans la même sauteuse, suer les échalotes ciselées. Ajouter les champignons, faire sauter à feu vif.\n6. Déglacer au vin blanc, réduire. Ajouter le fond de veau, frémir 5 min.\n7. Ajouter la crème, réduire légèrement. Remettre les ris pour les terminer 5 min dans la sauce.\n8. Monter la sauce au beurre hors feu. Jus de citron, persil ciselé.",vin:"Meursault ou Chassagne-Montrachet blanc",notes:"Le ris de veau de lait est le plus noble des abats français. L'étape de dégorgeage et pressurage est indispensable pour une texture ferme."},
{id:"FR014",co:"France",cat:"Plat",sous:"Viande – Rôtis",nom:"Côte de Bœuf Charolais, Sauce Bordelaise",chef:"Joël Robuchon",bp:4,prep:20,cui:30,diff:3,qual:4,ig:[["Côte de bœuf charolais 3 cm d'épaisseur",1000,"g"],["Échalotes grises ciselées",4,"pièces"],["Bordeaux rouge Saint-Émilion",30,"cl"],["Fond brun de veau maison",20,"cl"],["Beurre fin très froid",60,"g"],["Moelle de bœuf dégorgée et pochée",60,"g"],["Sel de Guérande et poivre noir",1,"qs"]],et:"1. Sortir la côte de bœuf du frigo 1 h avant. Assaisonner généreusement sel de Guérande + poivre noir.\n2. Préchauffer le four à 200°C avec la grille.\n3. Dans une poêle en fonte très chaude : saisir la côte de bœuf 3–4 min sur chaque face. Saisir également les 2 extrémités.\n4. Enfourner à 200°C pendant 12–15 min pour une cuisson saignante (T° intérieure 52°C) ou 18–20 min pour rosée (57°C). REPOS : laisser reposer 10 min sur une grille.\n5. Sauce bordelaise : réduire vin rouge + échalotes + thym + laurier jusqu'à 3 cs. Ajouter le fond de veau, réduire de moitié. Passer au chinois fin. Monter au beurre froid hors feu. Ajouter les tranches de moelle pochées.",vin:"Saint-Émilion Grand Cru ou Pomerol ou Pauillac",notes:"Le repos de la viande après cuisson est aussi important que la cuisson elle-même. La côte de bœuf charolais est supérieure à l'Angus."},
{id:"FR015",co:"France",cat:"Plat",sous:"Viande – Mijotés",nom:"Canard à l'Orange à l'Ancienne",chef:"Paul Bocuse",bp:4,prep:25,cui:90,diff:4,qual:4,ig:[["Canard de Barbarie 2 kg",1,"pièce (2 kg)"],["Oranges non traitées",3,"pièces"],["Sucre",50,"g"],["Vinaigre de vin blanc",3,"cs"],["Cognac",5,"cl"],["Fond brun de veau",30,"cl"],["Cointreau",2,"cs"],["Beurre fin",30,"g"]],et:"1. Préchauffer le four à 200°C. Assaisonner l'intérieur et l'extérieur du canard. Brider.\n2. Prélever les zestes de 2 oranges en julienne fine. Les blanchir 3 fois dans l'eau bouillante pour supprimer l'amertume. Réserver.\n3. Presser le jus des 3 oranges. Réserver.\n4. Rôtir le canard à 200°C pendant 20 min pour colorer, puis réduire à 170°C et cuire 50 min en arrosant toutes les 15 min.\n5. Sauce bigarade : caraméliser à sec le sucre jusqu'à caramel ambré. Déglacer avec le vinaigre. Ajouter le jus d'orange + jus de cuisson dégraissés + fond de veau. Frémir 10 min.\n6. Déglacer la plaque de rôtissage au cognac, flamber. Ajouter au fond de sauce. Passer au chinois fin.\n7. Monter la sauce au beurre hors feu. Ajouter Cointreau + zestes blanchis.",vin:"Pinot Gris Alsace Grand Cru ou Volnay rouge léger",notes:"Le blanchiment des zestes 3 fois est impératif pour supprimer l'amertume. La sauce doit être légèrement acidulée."},
{id:"FR016",co:"France",cat:"Plat",sous:"Végétarien / Légumes",nom:"Tian de Légumes Provençaux",chef:"Alain Ducasse",bp:4,prep:30,cui:60,diff:2,qual:4,ig:[["Courgettes vertes",3,"pièces"],["Courgettes jaunes",2,"pièces"],["Tomates cœur de bœuf bien mûres",3,"pièces"],["Aubergines",2,"pièces"],["Oignons doux des Cévennes",3,"pièces"],["Ail",6,"gousses"],["Thym frais",6,"branches"],["Romarin frais",2,"branches"],["Huile d'olive extra-vierge",8,"cs"]],et:"1. Préchauffer le four à 180°C.\n2. Éplucher et émincer les oignons en rondelles fines. Les faire fondre à feu doux dans 3 cs d'huile d'olive + thym + romarin pendant 20 min. Étaler dans le fond d'un grand plat à gratin huilé.\n3. Trancher en rondelles très fines et régulières (3–4 mm) : courgettes vertes et jaunes, tomates, aubergines.\n4. Alterner les rondelles de légumes debout dans le plat en les serrant et en les inclinant légèrement.\n5. Glisser des gousses d'ail entre les légumes. Parsemer de thym frais. Arroser généreusement d'huile d'olive. Saler, poivrer.\n6. Couvrir de papier aluminium. Enfourner 30 min. Retirer le papier, enfourner encore 30 min jusqu'à légère caramélisation.",vin:"Provence rosé Château Miraval ou Bandol rosé",notes:"Les légumes doivent être tranchés très régulièrement (mandoline recommandée). Les courgettes jaunes apportent la dimension visuelle gastronomique."},
{id:"FR017",co:"France",cat:"Dessert",sous:"Tarte",nom:"Tarte Tatin aux Pommes",chef:"Pierre Hermé",bp:6,prep:30,cui:90,diff:3,qual:4,ig:[["Sucre semoule pour caramel",200,"g"],["Beurre demi-sel froid en dés pour caramel",130,"g"],["Pommes Golden ou Braeburn",1500,"g"],["Farine T55 pour pâte brisée",250,"g"],["Beurre demi-sel pommade pour pâte",125,"g"],["Œuf pour pâte brisée",1,"pièce"],["Sucre glace pour pâte brisée",50,"g"]],et:"1. Pâte brisée sucrée : sabler farine + beurre pommade. Ajouter sucre glace, sel, œuf. Amalgamer sans pétrir. Disque, filmer, réfrigérer 1 h.\n2. Caramel à sec dans le moule (feu moyen) : fondre le sucre progressivement. Quand ambré, hors feu, incorporer beurre froid en dés en fouettant.\n3. Disposer les quartiers de pommes serrés verticalement sur le caramel.\n4. Enfourner 180°C – 45–55 min. Tiédir 15 min.\n5. Abaisser la pâte en disque + 3 cm. Poser sur les pommes, rentrer les bords.\n6. Enfourner à nouveau 25–30 min à 180°C jusqu'à dorure.\n7. Sortir du four, retourner AUSSITÔT sur plat. Servir tiède avec crème fraîche épaisse.",vin:"Cidre brut de Bretagne ou Calvados fin ou Sauternes",notes:"Ne jamais utiliser de pommes Granny Smith. Retourner impérativement avant que le caramel refroidisse (max 15 min après sortie du four)."},
{id:"FR018",co:"France",cat:"Dessert",sous:"Macaron / Petite pâtisserie",nom:"Macaron Ispahan (Rose – Framboise – Litchi)",chef:"Pierre Hermé",bp:10,prep:90,cui:12,diff:5,qual:4,ig:[["Poudre d'amandes tamisée pour coques",150,"g"],["Sucre glace tamisé pour coques",150,"g"],["Blancs d'œufs vieillis (1) pour coques",55,"g"],["Sucre semoule pour sirop",150,"g"],["Eau pour sirop",37,"g"],["Blancs d'œufs vieillis (2) pour coques",55,"g"],["Chocolat blanc Ivoire Valrhona pour ganache",270,"g"],["Crème fleurette 35% pour ganache",90,"g"],["Eau de rose de qualité pour ganache",2,"cs"],["Beurre fin pour ganache",30,"g"],["Framboises fraîches garniture",200,"g"],["Litchis frais en dés garniture",100,"g"]],et:"Coques :\n1. Tamiser amandes + sucre glace. Mélanger avec blancs (1) pour obtenir la pâte d'amandes.\n2. Cuire sucre + eau à 118°C. Monter blancs (2) en neige, verser sirop en filet en battant jusqu'à refroidissement (meringue italienne).\n3. Incorporer la meringue en 3 fois au tant pour tant en macaronnant jusqu'à ruban brillant. Ajouter colorant.\n4. Pocher des disques de 3 cm sur Silpat. Laisser croûter 30–45 min.\n5. Cuire 12 min à 160°C (chaleur tournante, porte entrouverte). Refroidir avant décollage.\nGanache :\n6. Bouillir la crème, verser sur chocolat blanc en 3 fois en émulsionnant. Ajouter eau de rose puis beurre. Filmer au contact. Réfrigérer 2 h.\nMontage :\n7. Pocher la ganache sur une coque, disposer framboises + litchi au centre. Recouvrir. Réfrigérer 24 h avant dégustation.",vin:"Champagne Rosé de Saignée ou Blanc de Blancs Grand Cru",notes:"Les blancs doivent être vieillis 3–5 jours à T° ambiante. Humidité = ennemi du macaron. Élu Meilleur Pâtissier du Monde 2016."},
{id:"FR019",co:"France",cat:"Dessert",sous:"Crème / Entremets",nom:"Crème Brûlée Classique à la Vanille",chef:"Guy Savoy",bp:6,prep:20,cui:60,diff:2,qual:4,ig:[["Jaunes d'œufs frais",8,"pièces"],["Sucre semoule",80,"g"],["Crème liquide entière 35% MG",80,"cl"],["Gousses de vanille de Tahiti",2,"pièces"],["Cassonade pour caramélisation",60,"g"]],et:"1. Préchauffer le four à 100°C.\n2. Fendre les gousses, gratter les graines. Infuser dans la crème + gousses à 80°C pendant 30 min. Filtrer.\n3. Fouetter jaunes + sucre sans blanchir (ne pas incorporer d'air).\n4. Verser la crème infusée tiède sur les jaunes en remuant. Filtrer à nouveau, écumer la mousse.\n5. Remplir les ramequins plats. Cuire au bain-marie à 100°C – 55 min (55°C à cœur).\n6. Réfrigérer au moins 4 h (idéalement 12 h).\n7. Saupoudrer de fine couche homogène de cassonade. Caraméliser au chalumeau en mouvements circulaires. Servir immédiatement.",vin:"Sauternes Château Suduiraut ou Muscat de Beaumes-de-Venise",notes:"La cuisson basse température est le secret d'une texture soyeuse parfaite. Caraméliser toujours à la commande – jamais à l'avance."},
{id:"FR020",co:"France",cat:"Dessert",sous:"Chocolat",nom:"Fondant au Chocolat Noir",chef:"Paul Bocuse",bp:6,prep:20,cui:25,diff:2,qual:4,ig:[["Chocolat noir 70% cacao Valrhona Guanaja",200,"g"],["Beurre doux",150,"g"],["Poudre d'amandes",80,"g"],["Œufs entiers blancs et jaunes séparés",4,"pièces"],["Sucre semoule",100,"g"]],et:"1. Préchauffer four à 180°C. Beurrer et fariner un moule à manqué 20 cm.\n2. Faire fondre au bain-marie chocolat + beurre. Incorporer la poudre d'amandes. Tiédir.\n3. Fouetter jaunes + moitié du sucre jusqu'à blanchiment.\n4. Monter blancs en neige ferme. À mi-parcours, ajouter le reste du sucre pour les serrer.\n5. Incorporer les jaunes blanchis au mélange chocolaté. Puis incorporer délicatement les blancs en neige en 3 fois.\n6. Verser dans le moule. Cuire 20–25 min à 180°C. Le cœur doit rester légèrement tremblotant.\n7. Démouler tiède. Servir avec crème anglaise ou glace vanille Bourbon.",vin:"Banyuls Rimage ou Maury ; thé Darjeeling premier flush",notes:"Valrhona Guanaja 70% idéal. Ne pas trop cuire : le fondant doit rester moelleux au centre."},
{id:"FR021",co:"France",cat:"Dessert",sous:"Tarte",nom:"Tarte au Citron Meringuée",chef:"Pierre Hermé",bp:8,prep:60,cui:30,diff:4,qual:4,ig:[["Farine T55 pour pâte sablée",250,"g"],["Beurre pommade pour pâte",125,"g"],["Sucre glace pour pâte",80,"g"],["Poudre d'amandes pour pâte",30,"g"],["Œuf pour pâte",1,"pièce"],["Œufs pour crème de citron",4,"pièces"],["Sucre pour crème de citron",200,"g"],["Beurre froid pour crème de citron",200,"g"],["Jus de citron jaune pour crème",15,"cl"],["Zestes de citrons non traités pour crème",3,"pièces"],["Blancs d'œufs pour meringue italienne",3,"pièces"],["Sucre pour meringue italienne",200,"g"],["Eau pour meringue italienne",5,"cl"]],et:"Pâte sablée :\n1. Sabler beurre pommade + farine + sucre glace + poudre d'amandes. Ajouter l'œuf, amalgamer sans travailler. Disque, filmer, réfrigérer 1 h.\n2. Foncer un moule à tarte de 26 cm. Piquer. Cuire à blanc 20 min à 170°C. Retirer les haricots, dorer encore 5 min. Refroidir.\nCrème de citron :\n3. Réunir dans un cul de poule : œufs + sucre + jus et zestes de citron. Fouetter sur bain-marie frémissant jusqu'à épaississement (82°C).\n4. Laisser tiédir à 50°C. Incorporer le beurre froid en dés en fouettant jusqu'à émulsion brillante. Verser dans le fond de tarte. Réfrigérer 2 h.\nMeringue italienne :\n5. Cuire le sucre + eau à 121°C. Monter les blancs en neige. Verser le sirop en filet en continuant à battre jusqu'à refroidissement complet.\n6. Pocher la meringue sur la tarte. Dorer au chalumeau en mouvements circulaires.",vin:"Limoncello très frais ou thé vert Darjeeling ou Champagne Blanc de Blancs",notes:"La crème de citron de Pierre Hermé est la plus réputée au monde. La quantité de beurre est la clé de son extrême onctuosité."},
{id:"FR022",co:"France",cat:"Dessert",sous:"Soufflé",nom:"Soufflé au Grand Marnier",chef:"Michel Guérard",bp:4,prep:25,cui:12,diff:5,qual:4,ig:[["Lait entier pour crème pâtissière",25,"cl"],["Jaunes d'œufs",4,"pièces"],["Blancs d'œufs",6,"pièces"],["Sucre semoule",80,"g"],["Farine T45",25,"g"],["Beurre fin",20,"g"],["Grand Marnier",4,"cs"]],et:"1. Préchauffer le four à 190°C (chaleur fixe, jamais chaleur tournante pour les soufflés).\n2. Chemiser 4 ramequins individuels de beurre pommade en allant toujours du bas vers le haut. Remplir de sucre semoule, faire tourner, éliminer l'excédent. Réfrigérer.\n3. Crème pâtissière de base : porter le lait à ébullition. Fouetter jaunes + sucre jusqu'à blanchiment. Ajouter la farine tamisée. Verser le lait bouillant, mélanger. Cuire 3 min en remuant jusqu'à épaississement. Incorporer le beurre hors feu. Laisser tiédir à 50°C.\n4. Incorporer le Grand Marnier dans la crème pâtissière tiède.\n5. Monter les blancs en neige ferme. Incorporer 1/4 des blancs vigoureusement dans la crème pour la détendre. Puis incorporer le reste très délicatement en soulevant.\n6. Remplir les ramequins jusqu'au bord. Lisser avec une spatule. Passer le pouce sur le bord du moule pour créer une petite rainure (aide le soufflé à monter droit).\n7. Enfourner à 190°C pendant 11–12 min SANS OUVRIR LE FOUR. Saupoudrer de sucre glace à la sortie. Servir IMMÉDIATEMENT.",vin:"Champagne demi-sec ou Champagne Blanc de Blancs",notes:"Le soufflé ne pardonne aucun retard au service. La rainure du pouce sur le bord du moule est le secret pour un soufflé qui monte droit."},
{id:"FR023",co:"France",cat:"Sauce / Base",sous:"Fond / Sauce de base",nom:"Sauce Béarnaise",chef:"Michel Guérard",bp:4,prep:20,cui:20,diff:4,qual:4,ig:[["Jaunes d'œufs",4,"pièces"],["Beurre clarifié tiède",250,"g"],["Vinaigre de vin blanc",5,"cl"],["Vin blanc sec",5,"cl"],["Échalotes ciselées",3,"pièces"],["Estragon frais feuilles",1,"bouquet"],["Cerfeuil frais",0.5,"bouquet"]],et:"1. Réduction : vinaigre + vin blanc + échalotes + tiges d'estragon + poivre concassé. Réduire aux 3/4. Filtrer. Laisser tiédir.\n2. Dans casserole à fond épais, fouetter les jaunes d'œufs avec la réduction tiède et 1 cs d'eau froide.\n3. Placer sur bain-marie frémissant (60°C max). Fouetter constamment jusqu'au ruban : la sauce doit tripler de volume.\n4. Hors du bain-marie, incorporer le beurre clarifié tiède EN FILET CONTINU en fouettant énergiquement.\n5. Assaisonner. Ajouter feuilles d'estragon et cerfeuil ciselés.\n6. Servir immédiatement ou maintenir au bain-marie tiède, couvert, max 30 min.",vin:"Accompagnement : entrecôte, filet de bœuf, poissons grillés",notes:"Si la sauce tourne : 1 cs d'eau froide dans un bol propre, incorporer la sauce en filet. Ne jamais dépasser 65°C."},
{id:"FR025",co:"France",cat:"Plat",sous:"Poisson – Lyon",nom:"Quenelles de Brochet Sauce Nantua",chef:"Paul Bocuse (tradition lyonnaise)",bp:4,prep:45,cui:40,diff:4,qual:4,ig:[["Chair de brochet fraîche sans arêtes",300,"g"],["Beurre fin",120,"g"],["Farine T45",80,"g"],["Œufs entiers",3,"pièces"],["Lait entier",15,"cl"],["Crème fleurette 35% MG – farce",10,"cl"],["Écrevisses ou crevettes décortiquées – sauce",150,"g"],["Cognac – sauce",4,"cs"],["Crème fleurette – sauce",30,"cl"],["Fond de bisque ou fumet",20,"cl"],["Beurre fin – sauce",30,"g"],["Sel fin, poivre blanc, muscade",1,"qs"]],et:"Panade :\n1. Porter lait + beurre à ébullition. Verser la farine d'un coup. Dessécher sur feu doux jusqu'à ce que la pâte se détache des parois. Refroidir complètement.\nFarce :\n2. Mixer la chair de brochet avec la panade refroidie. Incorporer les œufs un par un. Ajouter la crème bien froide en filet. Assaisonner sel fin + poivre blanc + muscade. Réfrigérer 1 h.\nFormage :\n3. Façonner les quenelles à la cuillère à soupe (deux cuillères pour un ovale régulier) ou à la poche.\n4. Pocher dans eau frémissante salée 12–15 min. Elles doublent de volume. Égoutter.\nSauce Nantua :\n5. Saisir les écrevisses au beurre. Flamber au cognac. Ajouter fond de bisque + crème, réduire 10 min. Mixer finement, passer au chinois. Monter au beurre hors feu.\n6. Disposer les quenelles pochées dans un plat à gratin. Napper de sauce Nantua. Gratiner au four à 200°C pendant 15 min.",vin:"Mâcon-Villages blanc ou Pouilly-Fuissé ou Meursault",notes:"La quenelle lyonnaise est la recette la plus technique de la cuisine des bouchons. La panade doit être parfaitement refroidie avant d'incorporer le poisson. Les quenelles se tiennent grâce à l'amidon de la panade, pas aux œufs."},
{id:"FR026",co:"France",cat:"Plat",sous:"Abats – Lyon",nom:"Tablier de Sapeur à la Gribiche",chef:"Tradition des bouchons lyonnais",bp:4,prep:30,cui:15,diff:3,qual:4,ig:[["Gras-double (panse de bœuf cuite) en tranches 1 cm",800,"g"],["Moutarde de Dijon – marinade",3,"cs"],["Vin blanc sec – marinade",15,"cl"],["Vinaigre de vin – marinade",2,"cs"],["Chapelure fine",100,"g"],["Œufs battus – panure",2,"pièces"],["Beurre clarifié",60,"g"],["Œufs durs – gribiche",3,"pièces"],["Cornichons hachés – gribiche",4,"pièces"],["Câpres – gribiche",2,"cs"],["Estragon + cerfeuil + persil – gribiche",1,"bouquet"],["Moutarde – gribiche",1,"cc"],["Huile de tournesol – gribiche",12,"cl"],["Vinaigre de vin – gribiche",1,"cs"]],et:"1. Mariner le gras-double 2 h dans moutarde + vin blanc + vinaigre. Égoutter, sécher.\n2. Sauce gribiche : écraser les jaunes d'œufs durs avec la moutarde. Monter à l'huile comme une mayonnaise. Ajouter blancs d'œufs hachés + cornichons + câpres + herbes ciselées + vinaigre. Assaisonner.\n3. Paner le gras-double : farine → œuf battu → chapelure.\n4. Faire frire dans le beurre clarifié à feu moyen 4–5 min de chaque côté jusqu'à dorure croustillante.\n5. Égoutter sur papier absorbant. Servir chaud avec la sauce gribiche bien fraîche.",vin:"Mâcon rouge léger ou Beaujolais Villages ou Côtes du Rhône rouge",notes:"Le tablier de sapeur est l'un des plats les plus typiques des bouchons lyonnais. 'Tablier de sapeur' désigne le grand tablier de cuir des sapeurs-pompiers du XIXe s. Le gras-double doit être acheté déjà blanchi et cuit chez le tripier."},
{id:"FR027",co:"France",cat:"Plat",sous:"Viande – Alsace",nom:"Choucroute Garnie à l'Alsacienne",chef:"Tradition alsacienne",bp:8,prep:30,cui:180,diff:2,qual:4,ig:[["Choucroute crue lavée et égouttée",1500,"g"],["Riesling d'Alsace",50,"cl"],["Bouillon de volaille",30,"cl"],["Lard fumé demi-sel en bloc",300,"g"],["Palette de porc fumée",600,"g"],["Saucisses de Strasbourg",8,"pièces"],["Saucisses de Montbéliard ou de Morteau",2,"pièces"],["Knack ou cervelas",4,"pièces"],["Pommes de terre à chair ferme",1000,"g"],["Oignons piqués de clou de girofle",2,"pièces"],["Baies de genévrier",10,"pièces"],["Grains de poivre noir",10,"pièces"],["Feuilles de laurier",2,"pièces"],["Thym",2,"branches"],["Saindoux ou graisse d'oie",2,"cs"]],et:"1. Dans une grande cocotte en fonte, faire fondre le saindoux à feu moyen. Y faire revenir les oignons 5 min.\n2. Ajouter la choucroute lavée. Bien mélanger avec la graisse.\n3. Poser le lard fumé + la palette fumée sur la choucroute. Ajouter genévrier + poivre + laurier + thym + clou de girofle.\n4. Mouiller avec le Riesling + bouillon. Porter à frémissement. Couvrir.\n5. Cuire à feu très doux 2 h 30 à 3 h (ou au four à 150°C).\n6. 30 min avant la fin : ajouter les pommes de terre pelées entières. Cuire jusqu'à tendreté.\n7. 15 min avant la fin : plonger les saucisses dans la choucroute. NE PAS FAIRE BOUILLIR les saucisses (elles éclatent).\n8. Dresser la choucroute au centre d'un grand plat. Disposer harmonieusement les viandes et pommes de terre autour.",vin:"Riesling d'Alsace Vendanges Tardives ou Pinot Blanc d'Alsace ; bière d'Alsace Kronenbourg 1664 très froide",notes:"La choucroute doit cuire longtemps et doucement. Le Riesling est indispensable – jamais de vin blanc ordinaire. La palette et le lard fumés donnent leur saveur à la choucroute pendant la cuisson."},
{id:"FR028",co:"France",cat:"Plat",sous:"Viande – Alsace",nom:"Baeckeoffe (Potée Alsacienne aux Trois Viandes)",chef:"Tradition alsacienne",bp:6,prep:30,cui:180,diff:2,qual:4,ig:[["Épaule d'agneau désossée en cubes",400,"g"],["Porc (échine ou épaule) en cubes",400,"g"],["Bœuf (paleron) en cubes",400,"g"],["Pommes de terre à chair ferme en rondelles épaisses",1200,"g"],["Oignons émincés",4,"pièces"],["Poireaux en rondelles",2,"pièces"],["Carottes en rondelles",3,"pièces"],["Riesling d'Alsace",75,"cl"],["Genévrier",8,"baies"],["Thym, laurier",1,"qs"],["Sel, poivre",1,"qs"],["Pâte de lut (farine + eau)",1,"qs"]],et:"1. MARINADE (J-1) : mélanger les 3 viandes avec le Riesling + oignons + genévrier + thym + laurier + poivre. Mariner 12 h au frigo.\n2. Préchauffer le four à 180°C.\n3. Dans la terrine en terre cuite (obligatoire – le baeckeoffe se cuit dans une terrine en terre d'Alsace) : alterner couches de pommes de terre + légumes + viandes marinées. Terminer par une couche de pommes de terre.\n4. Verser la marinade filtrée sur le tout.\n5. Préparer la pâte de lut : farine + eau, pétrir. Rouler en boudin. Poser sur le pourtour du couvercle de la terrine pour créer un joint hermétique.\n6. Couvrir et luter hermétiquement avec la pâte.\n7. Enfourner à 180°C pendant 3 h. NE PAS OUVRIR pendant la cuisson.\n8. Apporter la terrine lutée à table. Casser la pâte devant les convives.",vin:"Riesling d'Alsace Grand Cru ou Pinot Gris d'Alsace",notes:"Le baeckeoffe (baecke = four du boulanger, offe = four en alsacien) était traditionnellement préparé par les femmes alsaciennes le lundi matin et déposé chez le boulanger pendant qu'elles faisaient la lessive. Le four du boulanger refroidissait doucement la cuisson."},
{id:"FR029",co:"France",cat:"Plat",sous:"Viande – Périgord",nom:"Confit de Canard aux Pommes Sarladaises",chef:"Tradition du Périgord",bp:4,prep:30,cui:150,diff:3,qual:4,ig:[["Cuisses de canard",4,"pièces"],["Gros sel",80,"g"],["Graisse de canard",800,"g"],["Ail",6,"gousses"],["Thym, laurier",1,"qs"],["Pommes de terre Ratte ou BF15 – sarladaises",1000,"g"],["Ail – sarladaises",4,"gousses"],["Graisse de canard – sarladaises",4,"cs"],["Persil plat – sarladaises",0.5,"bouquet"]],et:"Confit (J-1) :\n1. Frotter généreusement les cuisses avec le gros sel + thym + laurier + ail écrasé. Couvrir, réfrigérer 12 h (salaison).\n2. Rincer abondamment les cuisses. Sécher soigneusement.\n3. Faire fondre la graisse de canard à feu doux dans une cocotte. Plonger les cuisses dans la graisse (elles doivent être entièrement immergées). Porter à 85°C.\n4. Confire à 85°C pendant 2 h 30 à 3 h. La chair doit se détacher facilement de l'os sans se défaire.\n5. Laisser refroidir dans la graisse. Conserver au frigo (se conserve 1 mois).\nSarladaises :\n6. Trancher les PDT en rondelles fines. Sécher sur torchon.\n7. Dans une sauteuse, chauffer la graisse de canard à feu moyen. Ajouter les rondelles de PDT, saler, cuire 20–25 min en retournant régulièrement jusqu'à dorées et fondantes.\n8. Ajouter l'ail haché + persil en fin de cuisson.\nService :\n9. Sortir les cuisses de la graisse. Les faire croustiller skin-down dans une poêle très chaude pendant 5–7 min jusqu'à peau croustillante et lacquée. Servir avec les sarladaises.",vin:"Cahors Malbec (Clos de Gamot) ou Bergerac rouge ou Pécharmant",notes:"Le confit de canard préparé en avance est infiniment meilleur. La cuisson à 85°C (pas plus) est la clé d'un confit fondant. La peau doit être rendue parfaitement croustillante au service."},
{id:"FR030",co:"France",cat:"Plat",sous:"Poisson – Bretagne",nom:"Cotriade Bretonne (Bouillabaisse de Bretagne)",chef:"Tradition bretonne – Finistère",bp:6,prep:30,cui:45,diff:3,qual:4,ig:[["Congre en tronçons",400,"g"],["Lieu jaune ou merlan en morceaux",400,"g"],["Grondin ou rascasse",300,"g"],["Moules fraîches grattées",500,"g"],["Pommes de terre à chair ferme",600,"g"],["Oignons",2,"pièces"],["Poireaux",2,"pièces"],["Carottes",2,"pièces"],["Ail",4,"gousses"],["Bouquet garni",1,"pièce"],["Beurre breton demi-sel",40,"g"],["Pain de campagne grillé",6,"tranches"],["Vinaigre de vin rouge",3,"cs"],["Sel, poivre",1,"qs"]],et:"1. Dans une grande marmite, faire fondre le beurre. Suer à feu doux : oignons + poireaux + carottes + ail émincés 10 min.\n2. Ajouter les PDT pelées entières ou en demi. Mouiller à hauteur avec l'eau. Porter à frémissement. Cuire 15 min.\n3. Ajouter le bouquet garni + sel + poivre. Ajouter les poissons à chair ferme (congre). Frémir 5 min.\n4. Ajouter les poissons à chair plus tendre (lieu, grondin). Frémir encore 8 min.\n5. Dans une casserole séparée, faire ouvrir les moules à feu vif 3 min. Réserver avec leur jus filtré.\n6. Ajouter les moules décoquillées + leur jus dans la marmite. Rectifier l'assaisonnement.\n7. Servir en 2 temps : d'abord le bouillon avec le pain de campagne grillé frotté à l'ail + vinaigre servi à part, puis les poissons et légumes.",vin:"Muscadet de Sèvre et Maine sur Lie ou Gros Plant du Pays Nantais ou bière bretonne Coreff",notes:"La cotriade est la bouillabaisse bretonne. Chaque pêcheur la préparait avec les poissons invendus de la journée. Le vinaigre servi à part dans un bol est la touche bretonne typique – chacun se sert selon son goût."},
{id:"FR031",co:"France",cat:"Dessert",sous:"Viennoiserie – Bretagne",nom:"Kouign-Amann (Gâteau au Beurre Breton)",chef:"Yves-René Scordia, Douarnenez 1860",bp:8,prep:30,cui:40,diff:3,qual:4,ig:[["Farine T45",500,"g"],["Levure de boulanger fraîche",20,"g"],["Eau tiède",30,"cl"],["Sel fin",8,"g"],["Beurre breton demi-sel très froid",250,"g"],["Sucre semoule",200,"g"]],et:"1. Pâte levée : diluer la levure dans l'eau tiède. Mélanger farine + sel. Former un puits, verser la levure. Pétrir 8 min jusqu'à pâte lisse et élastique. Laisser doubler de volume sous torchon (1 h).\n2. Étaler la pâte en rectangle de 30x40 cm.\n3. Poser les 250 g de beurre très froid (sorti du frigo) en lamelles sur les 2/3 de la pâte. Saupoudrer de la moitié du sucre sur le beurre.\n4. Replier en 3 (tour simple). Étaler de nouveau. Saupoudrer le reste du sucre. Replier en 3. Réfrigérer 20 min.\n5. Préchauffer le four à 200°C. Beurrer généreusement un moule à manqué de 28 cm.\n6. Étaler la pâte en rond, déposer dans le moule. Laisser reposer 20 min.\n7. Enfourner 35–40 min à 200°C jusqu'à couleur caramel foncé et caramel qui bouillonne sur les bords.\n8. Démouler IMMÉDIATEMENT (le caramel fige très vite). Retourner sur une grille.",vin:"Cidre brut de Bretagne (Kerisac ou Eric Bordelet) ou café breton",notes:"Le Kouign-Amann a été créé en 1860 à Douarnenez par accident : le boulanger Scordia avait peu de pâte levée et beaucoup de beurre breton demi-sel. 'Kouign' = gâteau, 'Amann' = beurre en breton. Il doit être mangé tiède, jamais froid."},
{id:"FR032",co:"France",cat:"Dessert",sous:"Gâteau – Bretagne",nom:"Far Breton aux Pruneaux d'Agen",chef:"Tradition bretonne",bp:6,prep:15,cui:50,diff:1,qual:4,ig:[["Pruneaux d'Agen dénoyautés",200,"g"],["Rhum ambré",3,"cs"],["Farine T45",200,"g"],["Sucre semoule",100,"g"],["Œufs entiers",4,"pièces"],["Lait entier",80,"cl"],["Beurre demi-sel fondu",30,"g"],["Sel",1,"pincée"]],et:"1. Faire macérer les pruneaux dans le rhum 1 h minimum (idéalement une nuit).\n2. Préchauffer le four à 180°C. Beurrer généreusement un plat en céramique rectangulaire.\n3. Dans un grand bol : tamiser farine + sel. Ajouter le sucre. Former un puits.\n4. Casser les œufs dans le puits. Fouetter en incorporant la farine progressivement.\n5. Verser le lait en filet tout en fouettant jusqu'à pâte lisse et fluide (comme une pâte à crêpes).\n6. Incorporer le beurre fondu tiède.\n7. Disposer les pruneaux macérés dans le fond du plat beurré. Verser la pâte dessus.\n8. Enfourner 50 min à 180°C. Le far doit être doré en surface et encore légèrement tremblotant au centre.\n9. Laisser tiédir avant de couper. Se mange tiède ou froid.",vin:"Cidre demi-sec de Bretagne ou Pineau des Charentes blanc ou thé au lait",notes:"Le far breton est le dessert traditionnel breton par excellence. La pâte doit être très liquide (plus liquide qu'une crêpe) pour une texture moelleuse et crémeuse. Les pruneaux d'Agen macérés dans le rhum sont indispensables."},
{id:"FR033",co:"France",cat:"Plat",sous:"Viande – Classique",nom:"Pot-au-Feu Classique",chef:"Paul Bocuse",bp:8,prep:30,cui:240,diff:2,qual:4,ig:[["Paleron de bœuf",800,"g"],["Plat de côtes demi-sel",400,"g"],["Queue de bœuf en tronçons",400,"g"],["Os à moelle",4,"pièces"],["Carottes",6,"pièces"],["Navets",4,"pièces"],["Poireaux ficelés",4,"pièces"],["Céleri branche",3,"branches"],["Oignons brûlés à sec",2,"pièces"],["Bouquet garni",1,"pièce"],["Grains de poivre noir",10,"pièces"],["Clou de girofle",2,"pièces"],["Gros sel",20,"g"]],et:"1. Départ à l'eau froide : mettre les viandes dans une grande marmite. Couvrir d'eau froide. Porter LENTEMENT à frémissement (30 min). Écumer méticuleusement l'écume grise pendant la montée en température – cette étape est cruciale pour un bouillon clair.\n2. Une fois l'écume blanche et propre, ajouter : oignons brûlés à sec (couleur caramel = couleur ambrée du bouillon) + bouquet garni + poivre + clou de girofle + gros sel.\n3. Frémir très doucement (95°C max, jamais bouillir) pendant 1h30.\n4. Ajouter les légumes coupés en morceaux réguliers. Frémir encore 1h30.\n5. Os à moelle : les ajouter 30 min avant la fin, ficelés dans une gaze pour ne pas les perdre. Cuire à frémissement doux.\n6. Vérifier la cuisson des viandes (elles doivent se couper à la cuillère). Rectifier l'assaisonnement.\n7. Servir en 2 temps : d'abord le bouillon en consommé avec vermicelles, puis les viandes et légumes.",vin:"Beaujolais Villages rouge ou Côtes du Rhône rouge léger",notes:"Le secret d'un grand pot-au-feu : le départ à l'eau froide et le frémissement doux. Un bouillon qui bout est un bouillon trouble. L'écumage pendant les 30 premières minutes est l'étape la plus importante pour la clarté du bouillon."},
{id:"FR034",co:"France",cat:"Plat",sous:"Viande – Classique",nom:"Blanquette de Veau à l'Ancienne",chef:"Joël Robuchon (d'après Escoffier)",bp:6,prep:30,cui:90,diff:3,qual:4,ig:[["Épaule de veau en cubes 5 cm",1200,"g"],["Petits oignons grelots",200,"g"],["Champignons de Paris boutons",300,"g"],["Carottes en rondelles",3,"pièces"],["Bouquet garni",1,"pièce"],["Bouillon de veau blanc",80,"cl"],["Crème fleurette 35% MG",25,"cl"],["Jaunes d'œufs",3,"pièces"],["Beurre fin",60,"g"],["Farine T45",50,"g"],["Jus de citron",1,"cs"],["Sel, poivre blanc",1,"qs"]],et:"1. Départ à l'eau froide : mettre le veau dans une casserole, couvrir d'eau froide. Porter à frémissement, blanchir 5 min. Égoutter, rincer sous l'eau froide. Sécher.\n2. Dans une cocotte, fondre 30 g de beurre. Singer le veau blanchi (farine) sur feu moyen 2 min.\n3. Mouiller avec le bouillon de veau tiède progressivement en fouettant pour éviter les grumeaux. Ajouter bouquet garni + carottes + sel + poivre blanc. Frémir à couvert 50 min à feu doux.\n4. Glacer à blanc les oignons grelots : eau + beurre + sel + sucre jusqu'à évaporation et légère brillance. Réserver.\n5. Sauter les champignons au beurre. Réserver.\n6. Retirer le veau. Réduire légèrement la sauce. Liaison : fouetter jaunes d'œufs + crème. Verser dans la sauce hors feu. Épaissir sans bouillir (83°C). Monter au beurre. Jus de citron.\n7. Remettre veau + oignons + champignons dans la sauce. Servir avec riz pilaf.",vin:"Meursault ou Chablis 1er Cru ou Saint-Véran",notes:"La blanquette est le plat emblématique de la cuisine bourgeoise française. 'Blanche' car le veau n'est jamais coloré. La liaison à la crème et aux jaunes d'œufs doit se faire hors feu – ne jamais faire bouillir après."},
{id:"FR035",co:"France",cat:"Sauce / Base",sous:"Sauces mères – Escoffier",nom:"Sauce Hollandaise",chef:"Auguste Escoffier",bp:4,prep:15,cui:15,diff:4,qual:4,ig:[["Jaunes d'œufs frais",4,"pièces"],["Beurre fin clarifié tiède",250,"g"],["Eau froide",2,"cs"],["Jus de citron",1,"cs"],["Sel fin, poivre blanc",1,"qs"],["Eau froide – sécurité",1,"cs"]],et:"1. Réduction : faire réduire 2 cs d'eau dans une casserole à fond épais jusqu'à 1 cs. Laisser refroidir légèrement.\n2. Ajouter les jaunes d'œufs dans la casserole avec la réduction tiède et 1 cs d'eau froide.\n3. Placer sur bain-marie frémissant (60°C MAX – jamais bouillir). Fouetter constamment jusqu'à sabayon : les jaunes triplent de volume, le fouet laisse des traces persistantes.\n4. Retirer du bain-marie. Incorporer le beurre clarifié tiède EN FILET TRÈS PROGRESSIF en fouettant continuellement. Ne pas aller trop vite.\n5. La sauce doit être crémeuse, dorée, nappante.\n6. Assaisonner sel fin + poivre blanc + quelques gouttes de jus de citron.\n7. Maintenir à 55–60°C au bain-marie tiède jusqu'au service.",vin:"Accompagnement : asperges, poisson poché, œufs benedict",notes:"Si la sauce tranche (devient grumeleuse) : prendre un bol propre, 1 cs d'eau tiède, incorporer la sauce tranchée en filet en fouettant. La sauce hollandaise est l'une des 5 grandes sauces mères de la cuisine française classique selon Escoffier."},
{id:"FR036",co:"France",cat:"Sauce / Base",sous:"Sauces mères – Escoffier",nom:"Beurre Blanc Nantais",chef:"Clémence Lefeuvre, La Buvette de la Marine, Saint-Julien-de-Concelles (1890)",bp:4,prep:10,cui:15,diff:4,qual:4,ig:[["Beurre fin très froid en dés",250,"g"],["Échalotes grises ciselées très finement",4,"pièces"],["Muscadet ou Gros Plant",10,"cl"],["Vinaigre de vin blanc",5,"cl"],["Sel fin, poivre blanc",1,"qs"],["Crème fleurette (facultatif – stabilise)",1,"cs"]],et:"1. Réduction : échalotes + vin blanc + vinaigre. Réduire à feu moyen jusqu'à presque sec (2 cs de liquide restant). Laisser tiédir à 50°C environ.\n2. Sur feu doux (source de chaleur minimale – le vrai beurre blanc se fait hors feu ou sur flamme très douce) : incorporer le beurre très froid en dés progressivement en fouettant vigoureusement.\n3. Ajouter le beurre dé par dé, en attendant que chaque dé soit incorporé avant d'en ajouter le suivant. La sauce doit rester crémeuse et émulsionnée, jamais liquide ni grasse.\n4. La température idéale de travail : 60–70°C. Trop chaud = la sauce se sépare en beurre fondu. Trop froid = elle ne s'émulsionne pas.\n5. Assaisonner sel fin + poivre blanc. Ne jamais passer au chinois (garder les échalotes).",vin:"Accompagnement : sandre, brochet, sole, homard, coquilles Saint-Jacques",notes:"Le beurre blanc est la sauce emblématique de la Loire. Créé par accident par Clémence Lefeuvre vers 1890 à Saint-Julien-de-Concelles. La 1 cs de crème en début de réduction stabilise l'émulsion et empêche le beurre de trancher – c'est la technique des professionnels."},
{id:"FR037",co:"France",cat:"Plat",sous:"Poisson – Provence",nom:"Bouillabaisse Marseillaise Classique",chef:"Tradition marseillaise – Grand Hôtel des Bains",bp:6,prep:60,cui:60,diff:4,qual:4,ig:[["Rascasse entière vidée",400,"g"],["Saint-Pierre ou grondin",400,"g"],["Congre",300,"g"],["Vive ou baudroie",300,"g"],["Moules",500,"g"],["Palourdes",300,"g"],["Langoustes ou grosses crevettes",2,"pièces"],["Tomates mûres concassées",400,"g"],["Oignon",1,"pièce"],["Poireaux",2,"pièces"],["Fenouil",1,"pièce"],["Ail",6,"gousses"],["Safran en pistils",1,"g"],["Pastis",4,"cs"],["Huile d'olive extra-vierge",8,"cs"],["Thym, laurier, zeste d'orange",1,"qs"],["Pain de campagne grillé",6,"tranches"],["Rouille maison",1,"qs"]],et:"1. Base : suer à l'huile d'olive dans une grande marmite : oignon + poireaux + fenouil + ail. Dorer légèrement. Ajouter tomates + thym + laurier + zeste d'orange.\n2. Ajouter les poissons à chair ferme (rascasse, congre, grondin). Mouiller à hauteur avec l'eau bouillante. Ajouter le safran + pastis. Cuire à gros bouillon 15 min.\n3. Retirer les poissons à chair ferme. Ajouter les poissons à chair tendre (saint-pierre, vive, baudroie). Cuire encore 8 min.\n4. Ajouter les coquillages + langoustes. Cuire 5 min.\n5. Rectifier l'assaisonnement. Passer une partie du bouillon au moulin à légumes pour le rendre corsé.\nRouille : mixer ail + jaunes d'œufs + safran + piment + huile d'olive en montant comme une mayonnaise.\n6. Servir en 2 services : d'abord le bouillon + rouille + croûtons frottes d'ail, puis les poissons et fruits de mer.",vin:"Cassis blanc (Clos Sainte-Magdeleine) ou Bandol blanc ou Bellet blanc de Nice",notes:"La vraie bouillabaisse marseillaise nécessite des poissons de roche méditerranéens. La charte de la bouillabaisse de Marseille (1980) stipule qu'elle doit contenir au minimum 4 poissons de roche différents. Le safran est incontournable."},
{id:"FR038",co:"France",cat:"Dessert",sous:"Viennoiserie – Alsace",nom:"Kougelhopf Alsacien aux Raisins et Amandes",chef:"Tradition alsacienne",bp:8,prep:30,cui:45,diff:3,qual:4,ig:[["Farine T45",500,"g"],["Levure de boulanger fraîche",25,"g"],["Lait entier tiède",20,"cl"],["Beurre fin pommade",150,"g"],["Sucre semoule",80,"g"],["Œufs entiers",3,"pièces"],["Sel fin",8,"g"],["Raisins secs macérés dans le kirsch 12 h",100,"g"],["Amandes entières émondées pour le moule",20,"pièces"],["Sucre glace pour la finition",30,"g"]],et:"1. Levain : diluer la levure dans le lait tiède avec 100 g de farine. Laisser lever 20 min.\n2. Dans le bol du robot : farine + sel + sucre. Ajouter le levain, puis les œufs un par un. Pétrir 5 min.\n3. Incorporer le beurre pommade en petits dés progressivement. Pétrir encore 8 min jusqu'à pâte lisse, brillante et se décollant des parois.\n4. Incorporer les raisins égouttés.\n5. Beurrer généreusement le moule à kougelhopf (moule en terre d'Alsace avec cheminée centrale). Disposer les amandes dans les cannelures.\n6. Remplir le moule à mi-hauteur. Laisser doubler de volume sous torchon (1h30 à 2h).\n7. Enfourner à 180°C pendant 40–45 min jusqu'à belle couleur dorée et la lame ressort sèche.\n8. Démouler immédiatement. Laisser refroidir. Saupoudrer de sucre glace.",vin:"Gewurztraminer vendanges tardives d'Alsace ou café et thé de l'Avent",notes:"Le moule en terre à cheminée centrale est indispensable pour le kougelhopf authentique – il permet une cuisson uniforme. Le kougelhopf est le gâteau du dimanche matin en Alsace et le gâteau de Noël par excellence."},
{id:"FR039",co:"France",cat:"Entrée",sous:"Soupe froide",nom:"Vichyssoise (Velouté Glacé Poireaux-Pommes de Terre)",chef:"Louis Diat (Ritz-Carlton NY, 1917)",bp:6,prep:25,cui:35,diff:2,qual:5,ig:[["Blancs de poireaux nettoyés",500,"g"],["Pommes de terre BF15 ou Charlotte",350,"g"],["Oignon doux des Cévennes",1,"pièce"],["Beurre fin",50,"g"],["Bouillon de volaille blanc maison",100,"cl"],["Crème fleurette 35% MG",30,"cl"],["Lait entier glacé",10,"cl"],["Ciboulette ciselée très finement",1,"bouquet"],["Sel fin, poivre blanc",1,"qs"]],et:"1. Émincer les blancs de poireaux et l'oignon en très fines lamelles. Bien laver à l'eau froide pour éliminer toute terre.\n2. Dans une cocotte à fond épais, fondre le beurre à feu doux. Suer poireaux + oignon SANS coloration pendant 12-15 min — ils doivent devenir translucides et fondants.\n3. Ajouter les pommes de terre épluchées en dés de 1 cm. Mouiller avec le bouillon de volaille blanc bien chaud. Saler légèrement.\n4. Frémir 25 min à découvert jusqu'à ce que les pommes de terre s'écrasent à la cuillère.\n5. Passer au blender de puissance pendant 4 min — la finesse est cruciale. Filtrer obligatoirement au chinois étamine.\n6. Refroidir rapidement sur bain de glace. Incorporer 20 cl de crème fleurette froide en fouettant. Réfrigérer 4 h minimum (idéalement 12 h).\n7. Au moment du service : détendre avec le lait glacé jusqu'à consistance d'une crème fluide. Rectifier sel + poivre blanc (assaisonner toujours plus qu'à chaud — le froid masque le goût).\n8. Servir dans des bols préalablement glacés au congélateur. Émulsionner les 10 cl de crème restants au fouet, déposer une quenelle au centre. Pluie de ciboulette finement ciselée.",vin:"Sancerre blanc Loire ou Chablis 1er Cru",notes:"Créée en 1917 par Louis Diat au Ritz-Carlton de New York, inspirée des soupes de poireaux que sa mère préparait à Vichy. Doit être servie GLACÉE — jamais tiède. Le passage au chinois étamine est non négociable pour la texture velours."},
{id:"FR040",co:"France",cat:"Entrée",sous:"Salade composée",nom:"Salade Niçoise Authentique (Charte de Nice)",chef:"Hélène Barale (gardienne de la tradition niçoise)",bp:4,prep:25,cui:10,diff:1,qual:5,ig:[["Tomates cœur de bœuf de Provence bien mûres",4,"pièces"],["Petits artichauts violets de Provence crus",4,"pièces"],["Fèves fraîches écossées (printemps) ou poivron rouge",200,"g"],["Concombre",1,"pièce"],["Oignon nouveau de Nice",2,"pièces"],["Cébettes",4,"tiges"],["Œufs frais bio extra-frais",4,"pièces"],["Filets d'anchois de Collioure à l'huile",12,"filets"],["Thon entier à l'huile d'olive (Ortiz ou Ramón Peña)",200,"g"],["Olives noires de Nice (cailletier)",80,"g"],["Basilic frais petites feuilles",1,"bouquet"],["Huile d'olive AOP Nice (Nicolas Alziari)",10,"cl"],["Sel de Camargue, poivre noir",1,"qs"],["Ail",1,"gousse"]],et:"1. Frotter le saladier en bois (ou en terre) avec la gousse d'ail coupée en deux. Cette étape parfume subtilement l'ensemble.\n2. Cuire les œufs : départ eau froide, 9 min après ébullition pour des jaunes coulants au centre. Refroidir aussitôt à l'eau glacée. Écaler avec délicatesse, couper en quartiers au dernier moment.\n3. Tomates : ne JAMAIS les peler ni les épépiner. Couper en quartiers généreux. Saler légèrement, laisser dégorger 10 min sur grille (le jus rendu sera précieux).\n4. Petits artichauts violets : retirer les feuilles externes, tourner au couteau, citronner. Émincer en fines lamelles à la mandoline. Au cœur sont meilleurs CRUS dans la vraie niçoise.\n5. Concombre : éplucher partiellement (alterner bandes pelées et non pelées), trancher en demi-rondelles fines.\n6. Oignon nouveau et cébettes : émincer très finement.\n7. Au printemps : écosser les fèves, blanchir 30 sec, retirer la seconde peau. À défaut : poivron rouge en lamelles.\n8. Dans le saladier ailé : disposer harmonieusement tomates + artichauts + concombre + fèves + oignon + cébettes. Saler, poivrer.\n9. Ajouter le thon en gros morceaux (jamais émietté), les filets d'anchois disposés en croisillon, les olives de Nice non dénoyautées.\n10. Arroser d'huile d'olive AOP Nice généreusement (PAS de vinaigre — sacrilège niçois). Saler à la fleur de sel.\n11. Couronner des quartiers d'œufs et des feuilles de basilic frais déchirées à la main. Servir IMMÉDIATEMENT.",vin:"Bellet rosé AOP (Château de Crémat) ou Bandol rosé",notes:"La vraie niçoise selon la charte d'Hélène Barale : aucun légume cuit sauf les œufs durs, JAMAIS de pommes de terre ni de haricots verts (hérésie introduite par Auguste Escoffier mais reniée à Nice), jamais de vinaigre, jamais de salade verte. Les artichauts violets crus sont la signature."},
{id:"FR041",co:"France",cat:"Plat",sous:"Légumes / Gratin",nom:"Gratin Dauphinois Authentique du Dauphiné",chef:"Anne-Sophie Pic (Maison Pic, Valence)",bp:6,prep:25,cui:90,diff:2,qual:5,ig:[["Pommes de terre Mona Lisa ou BF15",1500,"g"],["Crème fleurette 35% MG",60,"cl"],["Lait entier",30,"cl"],["Ail nouveau",2,"gousses"],["Beurre fin pour le plat",30,"g"],["Noix de muscade fraîche râpée",1,"qs"],["Sel fin de Guérande",10,"g"],["Poivre blanc du moulin",1,"qs"]],et:"1. Préchauffer le four à 150°C en chaleur statique (jamais tournante — dessèche les surfaces).\n2. Frotter énergiquement un plat à gratin en terre cuite ou en porcelaine de 30 cm avec une demi-gousse d'ail écrasée. Beurrer généreusement. L'ail n'apparaîtra plus que par son parfum.\n3. Éplucher les pommes de terre. Les laver — mais NE JAMAIS les rincer après tranchage : l'amidon retenu sur les rondelles est ce qui liera naturellement le gratin (pas de béchamel, jamais de fromage dans le vrai dauphinois).\n4. Trancher à la mandoline en rondelles régulières de 2-3 mm.\n5. Frémir 10 min dans un mélange crème + lait + sel + 12 tours de moulin de poivre blanc + 8 râpées de muscade fraîche + 2ème gousse d'ail écrasée. Cette précuisson permet aux pommes de terre de libérer leur amidon et garantit une cuisson homogène.\n6. Disposer dans le plat en couches successives bien tassées. Arroser de toute la crème infusée filtrée jusqu'à affleurement (la crème ne doit pas dépasser).\n7. Enfourner à 150°C pendant 1 h 15 - 1 h 30. Le dessus doit être doré profond, le centre fondant.\n8. Laisser reposer 10 min avant de servir — la texture se stabilise.",vin:"Crozes-Hermitage rouge (vallée du Rhône Nord)",notes:"La règle absolue selon Anne-Sophie Pic : JAMAIS de fromage (gruyère, comté…) dans un vrai gratin dauphinois — ce qui en contient est un gratin savoyard. La cuisson lente à 150°C est la signature, le four tournant est interdit. La précuisson dans la crème infusée est le secret professionnel pour une texture parfaite."},
{id:"FR042",co:"France",cat:"Plat",sous:"Légumes / Confit",nom:"Ratatouille Confite à la Niçoise (Légumes Cuits Séparément)",chef:"Alain Ducasse (Le Louis XV, Monaco)",bp:6,prep:45,cui:120,diff:3,qual:5,ig:[["Aubergines violettes longues fermes",3,"pièces"],["Courgettes vertes fermes",4,"pièces"],["Poivrons rouges charnus",2,"pièces"],["Poivrons jaunes",1,"pièce"],["Tomates cœur de bœuf bien mûres",6,"pièces"],["Oignons doux des Cévennes",2,"pièces"],["Ail nouveau",6,"gousses"],["Huile d'olive AOP Nice",20,"cl"],["Bouquet garni (thym, laurier, romarin frais)",1,"pièce"],["Basilic frais — feuilles entières",1,"bouquet"],["Sucre",1,"pincée"],["Sel fin, poivre noir du moulin",1,"qs"]],et:"1. Méthode Ducasse : chaque légume est cuit SÉPARÉMENT pour préserver son identité, sa texture, sa couleur — c'est ce qui distingue radicalement la ratatouille gastronomique de la ratatouille familiale.\n2. Tomates : monder (incision en croix, ébouillanter 30 sec, refroidir, peler). Épépiner, couper en concassé. Confire à feu doux 30 min dans 2 cs d'huile d'olive avec ail haché + bouquet garni + 1 pincée de sucre — jusqu'à compote concentrée et colorée. Réserver tiède.\n3. Oignons : émincer finement. Fondre à feu très doux dans 3 cs d'huile d'olive 25 min jusqu'à compote dorée et fondante. Réserver.\n4. Poivrons : peler à l'économe (geste du chef, élimine l'amertume), épépiner, tailler en losanges réguliers de 2 cm. Sauter à feu vif dans 3 cs d'huile 8 min — ils doivent rester légèrement fermes au cœur. Réserver.\n5. Courgettes : tailler en cubes de 2 cm avec la peau. Sauter à feu vif dans 3 cs d'huile bien chaude 5-6 min jusqu'à coloration mais cœur al dente. Saler en fin de cuisson seulement (sinon elles rendent). Réserver.\n6. Aubergines : tailler en cubes de 2 cm avec la peau. Saler 30 min dans une passoire pour faire dégorger l'amertume. Sécher. Sauter à feu très vif dans 4 cs d'huile bien chaude — ne pas surcharger la poêle, sinon elles bouillent. Cuire 8 min jusqu'à coloration dorée. Réserver.\n7. Assemblage final : dans une cocotte basse, mélanger délicatement à la spatule TOUS les légumes confits avec la compotée de tomates et la compotée d'oignons. Réchauffer à feu doux 10 min couvercle entrouvert.\n8. Hors feu, ajouter les feuilles de basilic frais entières, un filet d'huile d'olive crue. Rectifier sel + poivre.\n9. Idéalement : préparer la veille. Réchauffer doucement le lendemain — la ratatouille est infiniment meilleure le 2ème jour.",vin:"Côtes de Provence rosé (Domaine Tempier) ou Bandol rouge",notes:"Méthode signature d'Alain Ducasse à Monaco : chaque légume préserve sa texture et son identité. À l'opposé de la ratatouille mijotée tous légumes ensemble qui devient une bouillie. Le pelage à l'économe des poivrons est un geste de chef qui change radicalement le résultat."},
{id:"FR043",co:"France",cat:"Plat",sous:"Viande mijotée",nom:"Daube Provençale aux Olives Noires et Zeste d'Orange",chef:"Reine Sammut (La Fenière, Lourmarin)",bp:6,prep:40,cui:240,diff:3,qual:5,ig:[["Joue de bœuf ou paleron de Charolais en cubes 5 cm",1500,"g"],["Couenne de porc fraîche en larges bandes",150,"g"],["Vin rouge de Provence corsé (Bandol)",75,"cl"],["Cognac",5,"cl"],["Lardons fumés artisanaux non blanchis",200,"g"],["Carottes en gros bâtonnets",4,"pièces"],["Oignons piqués de 2 clous de girofle",2,"pièces"],["Tomates pelées concassées",400,"g"],["Olives noires de Nyons en saumure",150,"g"],["Zeste d'orange séché ou frais (orange amère)",1,"pièce"],["Ail",6,"gousses"],["Bouquet garni (thym, laurier, romarin, queue de persil)",1,"pièce"],["Baies de genièvre",6,"pièces"],["Champignons de Paris frais",250,"g"],["Huile d'olive AOP Provence",4,"cs"],["Farine T45",2,"cs"]],et:"MARINADE (J-2, 24 h minimum) :\n1. Dans une terrine en grès, couvrir la viande de vin rouge + cognac + carottes + oignons piqués + ail écrasé + bouquet garni + zeste d'orange + genièvre + 1 cs huile d'olive. Filmer, réfrigérer 24 h en retournant 2 fois.\n2. Égoutter la viande dans une passoire au-dessus d'un saladier (récupérer la marinade). Sécher minutieusement chaque morceau au papier absorbant — étape capitale pour une bonne saisie.\nCUISSON (J-1) :\n3. Dans une cocotte en fonte, faire fondre les lardons à feu moyen jusqu'à coloration. Réserver. Dans la graisse, dorer les morceaux de viande en plusieurs fois (ne jamais surcharger), 5 min par côté. Réserver.\n4. Dans la même cocotte, faire revenir les légumes égouttés de la marinade 8 min. Singer (saupoudrer farine), cuire 2 min en remuant.\n5. Tapisser le fond avec les couennes de porc côté gras dessous (elles enrichiront la sauce de gélatine).\n6. Remettre viande + lardons. Mouiller avec la marinade filtrée + tomates concassées. Compléter avec un peu d'eau si nécessaire pour couvrir aux 3/4.\n7. Porter à frémissement à découvert. Couvrir hermétiquement (luter avec pâte farine-eau si possible).\n8. Enfourner à 130°C pendant 4 h. La viande doit être totalement fondante — se couper à la cuillère.\nFINITION :\n9. Sauter les champignons au beurre. Désaler les olives 5 min dans l'eau frémissante. Les ajouter à la daube avec les champignons 30 min avant la fin.\n10. Reposer la daube une nuit au frais. Le lendemain, dégraisser, réchauffer doucement. Servir avec des macaronis frais ou polenta crémeuse.",vin:"Bandol rouge (Domaine Tempier La Tourtine) ou Côtes de Provence rouge",notes:"Selon Reine Sammut : la couenne de porc qui tapisse le fond apporte la gélatine qui rend la sauce nappante. Le zeste d'orange amère (séché en hiver) est la signature provençale. La daube est INFINIMENT meilleure le surlendemain."},
{id:"FR044",co:"France",cat:"Plat",sous:"Poisson / Spécialité du Languedoc",nom:"Brandade de Morue Nîmoise (Émulsion à l'Huile d'Olive)",chef:"Pierre Gagnaire (Restaurant Pierre Gagnaire, Paris)",bp:6,prep:30,cui:25,diff:3,qual:5,ig:[["Filet de morue salée épaisse (cabillaud salé du Portugal)",800,"g"],["Huile d'olive AOP Nîmes (Picholine)",30,"cl"],["Lait entier",20,"cl"],["Pommes de terre BF15 cuites en robe des champs",250,"g"],["Ail nouveau",6,"gousses"],["Thym frais",2,"branches"],["Laurier",1,"feuille"],["Jus de citron jaune",1,"cs"],["Poivre blanc du moulin, muscade",1,"qs"],["Croûtons de pain de campagne grillés frottés à l'ail",1,"qs"],["Truffe noire fraîche râpée (variation luxueuse)",10,"g"]],et:"DESSALAGE (J-2, 36-48 h) :\n1. Plonger la morue salée dans une grande quantité d'eau froide. Réfrigérer. CHANGER L'EAU 4 fois en 36-48 h. La morue ne doit plus être salée du tout en bouche.\nPOCHAGE :\n2. Dans une casserole large, déposer la morue dessalée côté peau dessous, couvrir d'eau froide + thym + laurier. Porter LENTEMENT à 80°C — ne JAMAIS bouillir (la morue durcirait). Pocher 8 min.\n3. Égoutter délicatement. Retirer la peau et toutes les arêtes — opération minutieuse, ne laisser aucune. Effeuiller en gros morceaux.\n4. Cuire les pommes de terre en robe des champs à l'eau salée 30 min. Éplucher tièdes. Passer au moulin à légumes grille fine (jamais au mixeur — devient gomme).\nINFUSION :\n5. Faire infuser à feu très doux 10 min : ail écrasé en chemise + huile d'olive (mais ne pas frire l'ail — il doit confire). Filtrer.\n6. Faire chauffer le lait sans bouillir.\nÉMULSION (étape la plus technique) :\n7. Dans le mortier en marbre tiédi (ou à défaut une casserole large à fond épais sur feu très doux) : déposer la morue effeuillée. Pilonner pour la défaire en filaments fins.\n8. Incorporer les pommes de terre passées au moulin. Travailler à la spatule en bois en mouvements vigoureux.\n9. Verser EN FILET ALTERNATIVEMENT l'huile d'olive infusée tiède puis le lait chaud, en travaillant énergiquement comme pour une mayonnaise. Continuer jusqu'à émulsion lisse, blanche et nappante. Compter 10-12 minutes.\n10. Rectifier : poivre blanc (pas de sel — la morue en a), muscade, quelques gouttes de citron pour le tranchant.\n11. Dresser dans des cocottes individuelles. Ajouter une râpée de truffe noire fraîche (signature Pierre Gagnaire). Servir brûlant avec croûtons grillés.",vin:"Costières de Nîmes blanc (Roussanne / Marsanne)",notes:"La méthode Pierre Gagnaire : émulsion à chaud comme une mayonnaise tiède, à l'opposé de la brandade rustique mixée au robot. Les filaments de morue restent perceptibles, l'huile et le lait s'émulsionnent. Le mortier en marbre tiédi est l'outil traditionnel — à Nîmes, certaines familles ont leur 'mortier à brandade' depuis 4 générations."},
{id:"FR045",co:"France",cat:"Plat",sous:"Volaille",nom:"Poulet de Bresse Rôti à la Broche, Beurre de Pommes Caramélisées",chef:"Joël Robuchon",bp:4,prep:20,cui:90,diff:2,qual:5,ig:[["Poulet de Bresse AOC Label Rouge",1800,"g"],["Beurre fin pommade",80,"g"],["Beurre clarifié pour arrosage",60,"g"],["Échalotes confites",3,"pièces"],["Ail nouveau",6,"gousses"],["Citron jaune non traité",1,"pièce"],["Thym frais",4,"branches"],["Romarin frais",2,"branches"],["Estragon frais",1,"branche"],["Pommes Reine des Reinettes (jus)",1,"pièce"],["Sel de Guérande, poivre noir du moulin",1,"qs"],["Fleur de sel pour finition",1,"qs"]],et:"PRÉPARATION (J-1, 12 h à l'avance pour la peau croustillante) :\n1. Sortir le poulet de son emballage 12 h avant cuisson. Le placer sur grille au-dessus d'un plat dans le réfrigérateur, NU et NON COUVERT. La peau va se déshydrater — c'est le secret n°1 d'une peau ultra-croustillante. Geste signature de Robuchon.\nLE JOUR :\n2. Sortir le poulet 1 h avant cuisson : il doit être à température ambiante.\n3. Préchauffer le four à 230°C en convection statique avec une plaque vide à mi-hauteur.\n4. Décoller délicatement la peau de la poitrine et des cuisses avec les doigts (sans la déchirer) pour créer des poches.\n5. Mélanger beurre pommade + ail haché + thym effeuillé + estragon ciselé + zeste de citron + sel + poivre. Glisser ce beurre composé sous la peau, masser pour bien répartir.\n6. Saler généreusement la cavité. Y glisser : citron entier piqué de fourchette, ail en chemise, thym, romarin. Brider soigneusement avec ficelle pour cuisson uniforme.\n7. Frotter la peau avec sel de Guérande + poivre. Aucun beurre dehors (il brûlerait).\nCUISSON :\n8. Poser le poulet sur le côté droit dans un plat à rôtir lourd. 25 min à 230°C.\n9. Retourner sur le côté gauche. Arroser au beurre clarifié à la louche. 25 min à 230°C.\n10. Retourner sur le dos. Arroser. Réduire à 180°C. 25-30 min jusqu'à T° intérieure de 72°C dans la cuisse.\n11. Arroser TOUTES les 8 minutes (geste essentiel) avec le beurre clarifié + jus rendus.\nREPOS (étape capitale) :\n12. Sortir le poulet. Le poser sur une grille, BRÉCHET DESSOUS pour que les jus migrent vers la poitrine. Couvrir d'aluminium sans serrer. Reposer 15 min minimum (autant de temps que la dernière phase de cuisson).\nSAUCE MINUTE :\n13. Pendant le repos : déglacer le plat avec le jus de la pomme Reine des Reinettes pressée + 5 cl d'eau. Gratter les sucs au fouet. Réduire 3 min. Monter avec les échalotes confites. Filtrer.\nDÉCOUPE :\n14. Découper devant les convives. Servir avec la sauce, fleur de sel sur la peau craquante.",vin:"Meursault Charmes ou Châteauneuf-du-Pape blanc",notes:"Robuchon disait : 'Un grand poulet rôti se reconnaît à 3 choses : la peau craquante, la chair fondante, le jus parfumé.' Les 12 h de séchage à nu au frigo sont LE secret professionnel. Le repos brechet en bas dans le sens inverse de la cuisson redistribue les jus."},
{id:"FR046",co:"France",cat:"Plat",sous:"Légumineuses / Mijoté du Sud",nom:"Cassoulet de Toulouse Authentique (3 jours de cuisson)",chef:"Christian Constant (Le Violon d'Ingres, Paris)",bp:8,prep:120,cui:600,diff:4,qual:5,ig:[["Haricots Tarbais (lingots blancs IGP)",800,"g"],["Cuisses de canard confites maison",4,"pièces"],["Saucisses de Toulouse pur porc IGP",4,"pièces"],["Saucisson à cuire à l'ail",1,"pièce"],["Lard de poitrine fraîche en morceaux 5 cm",300,"g"],["Couenne de porc fraîche en larges bandes",200,"g"],["Os de jambon de Bayonne ou jarret salé",1,"pièce"],["Carottes",3,"pièces"],["Oignons piqués de 2 clous de girofle",2,"pièces"],["Tomates pelées concassées",400,"g"],["Ail",10,"gousses"],["Bouquet garni (thym, laurier, queue de persil)",1,"pièce"],["Graisse de canard",100,"g"],["Concentré de tomate",1,"cs"],["Poivre noir en grains, sel",1,"qs"]],et:"JOUR 1 — TREMPAGE :\n1. Tremper les haricots Tarbais dans 3 L d'eau froide pendant 12 h. Aucun bicarbonate.\nJOUR 2 — BOUILLON ET PRÉ-CUISSON DES HARICOTS :\n2. Égoutter les haricots, rincer. Couvrir d'eau froide neuve, porter à ébullition, blanchir 5 min, égoutter à nouveau (élimine les sucres flatulents).\n3. Préparer le bouillon : dans une grande marmite, mettre couennes ficelées en rouleau + os de jambon + lard frais + carottes + oignons piqués + ail (6 gousses) + bouquet garni. Couvrir de 4 L d'eau. Porter à frémissement, écumer méticuleusement. Cuire 1 h 30 à frémissement.\n4. Retirer le lard, le réserver. Ajouter les haricots dans le bouillon. Cuire 1 h 30 à frémissement TRÈS doux : ils doivent être tendres à cœur sans éclater. Réserver dans leur bouillon.\nJOUR 3 — MONTAGE ET CUISSON LONGUE :\n5. Faire dorer les saucisses de Toulouse à la graisse de canard 10 min. Réserver. Dorer le saucisson à cuire entier. Réserver. Dorer les cuisses de canard confites côté peau 5 min — la peau doit être croustillante.\n6. Ajouter ail haché (4 gousses) + tomates concassées + concentré dans la graisse. Compoter 10 min.\n7. MONTAGE dans une cassole en terre cuite vernissée de Mas-Saintes-Puelles (l'ustensile sacré qui donne son nom au plat) : tapisser le fond avec les couennes côté gras DESSUS. Première couche de haricots. Disposer cuisses de canard + saucisses + saucisson tranché + lard en morceaux. Recouvrir totalement de haricots.\n8. Mouiller à hauteur avec le bouillon chaud. Saupoudrer la surface de poivre noir.\nCUISSON LONGUE — 3 H au four :\n9. Enfourner à 150°C. Cuire 3 h SANS COUVRIR.\n10. Toutes les 30 min : casser la croûte qui se forme en l'enfonçant doucement dans les haricots avec le dos d'une cuillère en bois — Castelnaudary impose 7 fois, Toulouse 5 fois. Cette opération crée une croûte dorée toujours nouvelle qui parfume le plat. Si la surface s'assèche : ajouter louche de bouillon.\n11. À la 7ème croûte cassée : laisser la dernière croûte se former et dorer profondément. Le cassoulet est prêt quand cette ultime croûte est caramel foncé et que les haricots dessous sont fondants et nappés.\n12. Reposer 15 min à four éteint. Servir directement dans la cassole brûlante au centre de la table.",vin:"Cahors Malbec (Clos Triguedina) ou Madiran Tannat",notes:"Selon Christian Constant : la cassole en terre vernissée de Mas-Saintes-Puelles est NON NÉGOCIABLE — elle absorbe les graisses et libère sa porosité. La règle des 7 croûtes cassées (Castelnaudary) est sacrée. Aucun toulousain n'utilise de chapelure : la croûte se forme NATURELLEMENT par caramélisation des haricots. Préparer obligatoirement sur 3 jours."},
{id:"FR047",co:"France",cat:"Dessert",sous:"Crêpes flambées",nom:"Crêpes Suzette Flambées (Création de 1895)",chef:"Henri Charpentier (Café de Paris, Monte-Carlo, 1895)",bp:4,prep:30,cui:25,diff:3,qual:5,ig:[["Farine T45 tamisée",125,"g"],["Œufs entiers",3,"pièces"],["Lait entier frais",30,"cl"],["Crème fleurette 35% MG",5,"cl"],["Beurre noisette refroidi pour la pâte",30,"g"],["Sucre semoule",20,"g"],["Sel fin",1,"pincée"],["Bière blonde (allègement)",3,"cs"],["Beurre fin pour le beurre Suzette",100,"g"],["Sucre en morceaux frottés à l'orange",80,"g"],["Oranges non traitées (3 pour zestes + 4 pour jus)",4,"pièces"],["Citron jaune non traité",1,"pièce"],["Curaçao Triple Sec",4,"cs"],["Grand Marnier Cordon Rouge",4,"cs"],["Cognac VSOP pour flamber",4,"cs"]],et:"PÂTE À CRÊPES (J-1, repos 12 h) :\n1. Préparer un beurre noisette : faire fondre 30 g de beurre à feu moyen jusqu'à coloration ambrée et arôme de noisette. Filtrer. Refroidir.\n2. Tamiser farine + sucre + sel dans un saladier. Former un puits.\n3. Casser les œufs au centre. Mélanger en partant du centre en incorporant la farine progressivement.\n4. Verser le lait + crème en filet en fouettant pour éviter les grumeaux. Incorporer le beurre noisette refroidi.\n5. Ajouter la bière blonde (rend les crêpes plus aériennes — astuce de Charpentier).\n6. Filtrer impérativement au chinois pour éliminer toute trace de grumeau. Reposer 12 h au frais (gluten détendu = crêpes plus fines).\nBEURRE SUZETTE (étape signature) :\n7. Frotter ÉNERGIQUEMENT chaque morceau de sucre sur la peau d'orange jusqu'à ce qu'il soit imbibé d'huile essentielle (couleur orangée). C'est cette technique de 1895 qui parfume profondément.\n8. Mixer les sucres parfumés. Travailler avec le beurre pommade jusqu'à crème homogène. Ajouter zestes finement râpés de 2 oranges + zeste de 1/2 citron + 2 cs Grand Marnier + 2 cs Curaçao. Réserver.\nCUISSON DES CRÊPES :\n9. Chauffer une crêpière de 22 cm anti-adhésive à feu moyen. Passer un papier huilé. Verser une mini-louche de pâte, faire pivoter rapidement.\n10. Cuire 45 sec puis retourner d'un coup sec. 30 sec de l'autre côté. Empiler sous un torchon. Compter 12-16 crêpes pour 4 personnes.\nFLAMBAGE EN SALLE (théâtre Charpentier) :\n11. Au moment du service, dans une grande poêle en cuivre : faire fondre la moitié du beurre Suzette à feu moyen. Verser jus de 4 oranges + jus du citron. Réduire jusqu'à sirop ambré et nappant (3-4 min).\n12. Plier chaque crêpe en 4 (mouchoir). Passer chaque crêpe dans le sirop des deux côtés. Disposer en éventail dans la poêle.\n13. Au moment de servir : répartir le reste du beurre Suzette sur les crêpes. Verser cognac + Grand Marnier + Curaçao restants — RETIRER DU FEU.\n14. Approcher délicatement une flamme. Flamber en penchant légèrement la poêle. Arroser les crêpes avec la sauce flambée à la louche pendant que les flammes dansent.\n15. Servir IMMÉDIATEMENT, 3 crêpes par personne, nappées de sauce.",vin:"Champagne brut millésimé ou Sauternes",notes:"Anecdote de Charpentier (1895, Café de Paris Monte-Carlo) : à 14 ans, le jeune Henri prépare un dessert pour le Prince de Galles (futur Édouard VII). Le sirop s'enflamme accidentellement. Le Prince est conquis et propose de baptiser le dessert du nom de la jeune cliente présente : Suzette. Flamber TOUJOURS hors du feu pour contrôler. La technique du sucre frotté sur l'orange est non négociable."},
{id:"FR048",co:"France",cat:"Dessert",sous:"Chocolat / Mousse",nom:"Mousse au Chocolat Noir Intense (Recette Pierre Hermé)",chef:"Pierre Hermé",bp:6,prep:25,cui:5,diff:2,qual:5,ig:[["Chocolat noir Valrhona Guanaja 70% cacao",250,"g"],["Beurre fin pommade",30,"g"],["Œufs frais bio extra-frais — jaunes",6,"pièces"],["Œufs frais bio extra-frais — blancs",8,"pièces"],["Sucre semoule",30,"g"],["Crème fleurette 35% MG très froide",10,"cl"],["Sel fin",1,"pincée"],["Fleur de sel pour finition",1,"qs"]],et:"1. Sortir les œufs 1 h avant — ils doivent être à T° ambiante (les blancs montent mieux).\n2. Hacher finement le chocolat au couteau. Le faire fondre au bain-marie à 50°C maximum (ne JAMAIS dépasser — graisse perdue). Incorporer le beurre pommade hors feu en lissant à la maryse. Tiédir à 40°C.\n3. Crème montée : monter la crème très froide en chantilly souple (pas trop ferme, sinon mousse trop dense). Réserver au frais.\n4. Jaunes : fouetter au robot 5 min jusqu'à doublement de volume et ruban épais.\n5. Incorporer les jaunes au chocolat tiédi (40°C) à la maryse en mouvements circulaires. Le mélange doit rester souple.\n6. Blancs en neige : commencer vitesse moyenne, ajouter le sel à mi-parcours. Quand bec d'oiseau, ajouter le sucre EN PLUIE en augmentant à pleine vitesse jusqu'à neige ferme et brillante (ne pas trop monter — granuleux sinon).\nÉMULSION FINALE (technique Hermé) :\n7. Incorporer 1/4 des blancs vigoureusement dans le mélange chocolat-jaunes pour le détendre — ne pas chercher à préserver la mousse à cette étape.\n8. Ajouter la crème montée — soulever en mouvements amples du bas vers le haut.\n9. Incorporer le reste des blancs en 3 fois TRÈS DÉLICATEMENT à la maryse en soulevant et tournant le saladier — geste qui demande de la patience. Ne pas chercher la totale homogénéité — quelques traces blanches sont acceptables, signe d'une mousse aérée.\n10. Verser dans 6 verrines ou un grand saladier en porcelaine. Lisser à peine.\n11. Réfrigérer 6 h MINIMUM (idéalement 12 h) — la prise est lente mais essentielle.\n12. Avant de servir : pluie de fleur de sel. Optionnel : copeaux de chocolat noir râpés à la microplane, zeste d'orange.",vin:"Maury VDN ou Banyuls Grand Cru",notes:"Recette Pierre Hermé : la combinaison crème montée + blancs en neige + jaunes mousseux donne 3 textures qui s'expriment en bouche. Le Guanaja 70% est non négociable — Hermé l'a choisi pour sa profondeur sans amertume excessive. La fleur de sel exhausse le chocolat — découverte de Hermé en 2002."},
{id:"FR049",co:"France",cat:"Dessert",sous:"Gâteau / Limousin",nom:"Clafoutis aux Cerises Noires d'Itxassou (Tradition Limousine)",chef:"Anne-Sophie Pic (Maison Pic, Valence)",bp:6,prep:20,cui:50,diff:2,qual:5,ig:[["Cerises noires d'Itxassou ou Burlat NON dénoyautées",700,"g"],["Œufs entiers à T° ambiante",4,"pièces"],["Sucre semoule",100,"g"],["Sucre vanillé maison",1,"cs"],["Farine T45 tamisée",80,"g"],["Lait entier frais",30,"cl"],["Crème fleurette 35% MG",10,"cl"],["Beurre fin demi-sel pommade",40,"g"],["Kirsch d'Alsace",2,"cs"],["Vanille de Madagascar",1,"gousse"],["Sel fin",1,"pincée"],["Sucre cassonade pour caraméliser",30,"g"]],et:"PRÉPARATION :\n1. Préchauffer le four à 180°C (chaleur statique).\n2. Beurrer GÉNÉREUSEMENT un moule en céramique de 26 cm avec le beurre demi-sel pommade. Saupoudrer de cassonade en faisant tourner pour bien chemiser. Cette caramélisation des bords est la signature limousine traditionnelle.\nLES CERISES (étape clé : NE PAS DÉNOYAUTER) :\n3. Laver et équeuter les cerises. Les sécher minutieusement.\n4. Disposer les cerises ENTIÈRES NON DÉNOYAUTÉES dans le moule en une seule couche serrée.\n5. Arroser de kirsch. Laisser macérer 10 min — l'alcool s'imprègne.\nAPPAREIL (technique Anne-Sophie Pic — pâte à crêpes enrichie) :\n6. Fendre la gousse de vanille, gratter les graines. Infuser dans le lait + crème chauffés à 70°C pendant 15 min hors feu. Filtrer.\n7. Dans un saladier : tamiser farine + sel + sucre vanillé. Former un puits.\n8. Casser les œufs au centre. Ajouter le sucre semoule. Fouetter en partant du centre en incorporant la farine progressivement.\n9. Verser le lait infusé tiède EN FILET en fouettant constamment. Pâte fluide et lisse — ABSOLUMENT pas de grumeaux.\n10. Filtrer au chinois sur les cerises. La pâte doit affleurer mais pas couvrir totalement les cerises (elles doivent émerger légèrement).\nCUISSON :\n11. Enfourner immédiatement à 180°C, grille au tiers inférieur. Cuire 45-50 min — surface dorée profonde, centre encore légèrement tremblotant (il finira de prendre en refroidissant).\n12. La lame plantée doit ressortir avec quelques traces fondantes de pâte autour des cerises.\nFINITION :\n13. Sortir du four. Saupoudrer immédiatement de cassonade (légère caramélisation à la chaleur résiduelle).\n14. Tiédir 30 min — le clafoutis se mange TIÈDE selon la tradition limousine, jamais brûlant ni froid.\n15. Servir directement dans le plat avec une cuillère, accompagné d'une boule de glace vanille de Madagascar (Pic) ou d'une crème fraîche d'Isigny.",vin:"Maury VDN rouge ou Banyuls jeune",notes:"Selon Anne-Sophie Pic : ne JAMAIS dénoyauter les cerises ! Les noyaux libèrent un parfum d'amande amère subtil pendant la cuisson — c'est l'âme du vrai clafoutis. Le sucre cassonade dans le moule beurré crée une croûte caramélisée signature du Limousin. Avertir les convives de la présence des noyaux."},
{id:"FR050",co:"France",cat:"Dessert",sous:"Tarte / Pâtisserie",nom:"Tarte aux Fraises Mara des Bois, Crème d'Amande et Vanille",chef:"Cédric Grolet (Le Meurice, Paris)",bp:8,prep:90,cui:40,diff:4,qual:5,ig:[["Farine T55 — pâte sucrée",250,"g"],["Beurre fin pommade — pâte sucrée",150,"g"],["Sucre glace tamisé — pâte sucrée",95,"g"],["Poudre d'amandes — pâte sucrée",30,"g"],["Sel fin — pâte sucrée",2,"g"],["Œuf entier — pâte sucrée",1,"pièce"],["Beurre fin pommade — crème d'amande",75,"g"],["Sucre glace — crème d'amande",75,"g"],["Poudre d'amandes — crème d'amande",75,"g"],["Œuf entier — crème d'amande",1,"pièce"],["Lait entier — crème pâtissière",25,"cl"],["Vanille de Tahiti — crème pâtissière",1,"gousse"],["Jaunes d'œufs — crème pâtissière",3,"pièces"],["Sucre semoule — crème pâtissière",60,"g"],["Maïzena — crème pâtissière",25,"g"],["Beurre fin — crème pâtissière",20,"g"],["Mascarpone — crème diplomate",50,"g"],["Fraises Mara des Bois fraîches de Plougastel",600,"g"],["Gelée neutre pour brillance",3,"cs"],["Pistache fraîche concassée — finition",20,"g"]],et:"PÂTE SUCRÉE (J-1) :\n1. Crémer beurre pommade + sucre glace + sel à la feuille du robot 2 min (sans aérer).\n2. Ajouter poudre d'amandes + œuf. Mélanger 30 sec.\n3. Ajouter farine d'un coup. Mélanger jusqu'à AMALGAMATION — pas plus (gluten = pâte caoutchouteuse). Frasser 3 fois à la paume sur le plan de travail (geste de chef pour homogénéiser).\n4. Étaler entre 2 feuilles de papier sulfurisé en disque de 3 mm. Réfrigérer 12 h.\nFONÇAGE ET CUISSON À BLANC :\n5. Foncer un cercle de 22 cm beurré sur Silpat. Replier proprement les bords à l'équerre. Réfrigérer 1 h. Piquer le fond.\n6. Cuire à blanc 18 min à 165°C SANS billes (la pâte sucrée bien refroidie et bien foncée se tient). Le fond doit être doré pâle et sec au toucher.\nCRÈME D'AMANDE :\n7. Crémer beurre + sucre. Ajouter poudre d'amandes + œuf. Mélanger sans monter.\n8. Étaler une fine couche (4 mm) sur le fond de tarte précuit.\n9. Cuire à 170°C 12-15 min jusqu'à belle dorure. Refroidir totalement.\nCRÈME PÂTISSIÈRE :\n10. Infuser vanille fendue et grattée dans le lait à 80°C, 20 min hors feu. Filtrer.\n11. Blanchir jaunes + sucre. Incorporer maïzena tamisée.\n12. Verser le lait infusé bouillant sur les jaunes en fouettant. Reverser en casserole, cuire à 85°C en remuant constamment 2-3 min jusqu'à épaississement.\n13. Hors feu : incorporer beurre. Filmer au contact, refroidir rapidement.\nCRÈME DIPLOMATE (technique Grolet) :\n14. Détendre la crème pâtissière froide au fouet. Incorporer le mascarpone — texture brillante et nappante.\nMONTAGE (le jour même, 2 h max avant service) :\n15. Pocher la crème diplomate à la poche douille lisse en spirale sur le fond cuit jusqu'à 5 mm sous le bord.\n16. Choisir les plus belles fraises Mara des Bois (parfum incomparable de fraise des bois). Équeuter, ne jamais laver (eau = parfum perdu — essuyer délicatement). Couper en deux dans le sens de la longueur.\n17. Disposer les fraises en rosace concentrique très serrée, pointe dirigée vers le centre. Les plus petites au centre, les plus grandes à l'extérieur.\n18. Lustrer chaque fraise au pinceau avec gelée neutre tiédie — brillance professionnelle.\n19. Décorer la circonférence d'éclats de pistache fraîche concassée + fleur de sel imperceptible.\n20. Servir dans les 2 heures — la pâte sucrée perd son croustillant après.",vin:"Champagne rosé brut (Billecart-Salmon) ou Beerenauslese",notes:"Méthode Cédric Grolet (chef pâtissier 3 fois Champion du Monde) : la crème diplomate (pâtissière + mascarpone) est sa signature. Les fraises Mara des Bois ont un parfum de fraise des bois unique — irremplaçables en saison (mai-octobre). Hors saison : gariguette de Plougastel. La rosace serrée pointe au centre est la disposition Le Meurice."},
{id:"FR051",co:"France",cat:"Plat",sous:"Soufflé salé / Œufs",nom:"Soufflé au Comté 24 Mois et Truffe Noire",chef:"Michel Roux (Le Gavroche, Londres)",bp:4,prep:25,cui:25,diff:5,qual:5,ig:[["Beurre fin pommade pour les ramequins",30,"g"],["Parmesan râpé pour chemiser les ramequins",30,"g"],["Beurre fin — roux blanc",50,"g"],["Farine T45 tamisée — roux blanc",50,"g"],["Lait entier frais",35,"cl"],["Comté affiné 24 mois râpé finement",150,"g"],["Jaunes d'œufs frais bio",5,"pièces"],["Blancs d'œufs frais bio à T° ambiante",6,"pièces"],["Truffe noire fraîche du Périgord (Tuber Melanosporum)",30,"g"],["Sel fin, poivre blanc, muscade fraîche",1,"qs"],["Crème de tartre (stabilisation des blancs)",1,"pincée"]],et:"PRÉPARATION DES RAMEQUINS (étape critique) :\n1. Beurrer 4 ramequins à soufflé de 10 cm en mouvements VERTICAUX uniquement, du bas vers le haut (jamais circulaires — le soufflé monterait de travers). Geste signature de Michel Roux.\n2. Saupoudrer généreusement de parmesan râpé en faisant tourner. Tapoter pour évacuer l'excédent.\n3. Réfrigérer impérativement 30 min — le beurre froid + le parmesan = anti-adhérent professionnel qui guidera la levée droite.\nBÉCHAMEL ÉPAISSE (base du soufflé) :\n4. Faire fondre 50 g de beurre à feu moyen. Ajouter farine en pluie. Cuire le roux 2 min en remuant — il doit rester blanc (jamais coloré).\n5. Verser le lait CHAUD progressivement en fouettant énergiquement pour éviter les grumeaux.\n6. Cuire 5 min à frémissement en fouettant. La béchamel doit être très épaisse (épaisseur de pâte à crêpes très épaisse) — c'est elle qui supportera le soufflé.\n7. Hors feu : assaisonner sel + poivre blanc + 6 râpées de muscade fraîche. Incorporer le Comté râpé hors feu — il fond avec la chaleur résiduelle. Mélanger jusqu'à fondue lisse.\n8. Incorporer la truffe noire râpée à la microplane (sa diffusion sera maximale). Tiédir à 50°C — capital, plus chaud cuirait les jaunes.\n9. Incorporer les jaunes d'œufs UN PAR UN en fouettant énergiquement entre chaque (réincorporation totale avant le suivant).\nMONTAGE DES BLANCS :\n10. Monter les blancs : commencer vitesse moyenne 2 min. Ajouter la pincée de crème de tartre (stabilise les blancs).\n11. Augmenter à grande vitesse jusqu'à bec d'oiseau ferme et brillant — JAMAIS jusqu'à granuleux. Le bec doit tomber légèrement quand on retire le fouet.\nINCORPORATION (geste capital) :\n12. Incorporer 1/3 des blancs vigoureusement dans la béchamel pour la détendre — ne pas chercher à préserver à cette étape.\n13. Verser ce mélange détendu sur les 2/3 restants des blancs. Incorporer en SOULEVANT et tournant le saladier d'1/4 de tour à chaque mouvement de maryse — geste essentiel qui préserve l'air des blancs.\n14. Arrêter dès que c'est homogène — pas plus.\nCUISSON (rapide et sans intervention) :\n15. Préchauffer le four à 200°C en chaleur STATIQUE (jamais tournante — le souffle du ventilateur rabat le soufflé).\n16. Remplir les ramequins à RAS BORD. Lisser à la spatule.\n17. Passer le pouce sur le pourtour intérieur du ramequin pour créer une rigole de 5 mm — ce détail signature aide le soufflé à monter parfaitement droit en se décollant du bord.\n18. Enfourner à 200°C sur grille basse 10 min. Réduire à 190°C et cuire 4-5 min — JAMAIS OUVRIR LA PORTE.\n19. Le soufflé est prêt quand il est doré profond, levé de 5-7 cm au-dessus du bord, légèrement tremblotant au centre.\n20. Saupoudrer immédiatement de truffe râpée. Servir EN COURANT à table — le soufflé retombe en 90 secondes.",vin:"Vin Jaune du Jura (Château-Chalon AOC)",notes:"Michel Roux (Le Gavroche, première étoile britannique en 1967) : 'Un soufflé n'attend pas — c'est l'invité qui attend le soufflé.' La rigole du pouce sur le pourtour est non négociable. Le Comté 24 mois + Tuber Melanosporum est un mariage signature des frères Roux."},
{id:"FR052",co:"France",cat:"Entrée",sous:"Tarte salée",nom:"Vraie Quiche Lorraine (Sans Fromage — Tradition de Metz)",chef:"Académie Culinaire de France (AOC officielle de la Lorraine)",bp:6,prep:30,cui:50,diff:2,qual:5,ig:[["Farine T55 — pâte brisée",250,"g"],["Beurre fin demi-sel froid en dés — pâte brisée",125,"g"],["Œuf entier — pâte brisée",1,"pièce"],["Eau glacée — pâte brisée",3,"cs"],["Sel fin — pâte brisée",4,"g"],["Lard fumé maigre de Lorraine en gros lardons (5 mm)",250,"g"],["Œufs entiers — appareil",4,"pièces"],["Crème fraîche épaisse d'Isigny AOP",30,"cl"],["Crème fleurette 35% MG",10,"cl"],["Sel fin, poivre noir du moulin, muscade fraîche",1,"qs"],["Beurre demi-sel pour le moule",20,"g"]],et:"PÂTE BRISÉE LORRAINE (J-1) :\n1. Sabler du bout des doigts farine + beurre froid en dés + sel. Travailler rapidement — texture sablée.\n2. Battre l'œuf avec l'eau glacée. Ajouter au sablage. Amalgamer SANS PÉTRIR — masser à la paume jusqu'à pâte homogène (1 min max).\n3. Bouler. Aplatir en disque. Filmer. Réfrigérer 12 h (le repos détend le gluten = pâte friable, jamais caoutchouteuse).\nFONÇAGE ET PRÉ-CUISSON :\n4. Étaler la pâte sur 3 mm. Foncer un moule à tarte cannelé de 28 cm beurré. Replier proprement les bords. Piquer le fond. Réfrigérer 30 min.\n5. Cuire à blanc 20 min à 180°C avec billes de cuisson sur papier sulfurisé. Retirer les billes, dorer 5 min de plus jusqu'à fond doré pâle. Le fond doit être SEC.\nLARDONS LORRAINS :\n6. Plonger les gros lardons fumés 1 min dans l'eau bouillante (étape capitale qui élimine l'excès de sel et le goût de fumée trop agressif). Égoutter, sécher.\n7. Faire revenir à sec dans une poêle à feu moyen 5-6 min — ils doivent être fondants à cœur, légèrement dorés en surface, jamais croustillants. Égoutter sur papier absorbant.\nMIGAINE (l'appareil traditionnel lorrain) :\n8. Dans un saladier : fouetter œufs entiers + crème épaisse d'Isigny + crème fleurette jusqu'à mélange homogène.\n9. Assaisonner sel modérément (les lardons salent), poivre noir généreux, 5 râpées de muscade fraîche.\nMONTAGE :\n10. Disposer les lardons fondants régulièrement sur le fond de tarte précuit — ils doivent former un lit uniforme.\n11. Verser la migaine doucement à la louche pour éviter de déplacer les lardons. Remplir à ras bord (la migaine va légèrement gonfler puis retomber).\nCUISSON :\n12. Enfourner à 175°C grille basse 30-35 min. La quiche doit être bombée, dorée profond en surface, encore très légèrement tremblotante au centre — elle prendra parfaitement en refroidissant.\n13. Sortir, laisser tiédir 10 min sur grille — la migaine se stabilise. Démouler.\n14. Servir TIÈDE — jamais brûlante (la migaine n'a pas son onctuosité), jamais froide (graisse figée).",vin:"Pinot Gris d'Alsace ou Côtes de Toul AOC",notes:"AOC officielle Lorraine : la VRAIE quiche lorraine ne contient NI fromage NI oignons NI légumes. Les Lorrains considèrent la version au gruyère comme une trahison (c'est une 'quiche bourguignonne'). Le pochage des lardons 1 min dans l'eau bouillante est la technique traditionnelle de Metz qui élimine l'agressivité du fumage. La migaine est le terme local pour l'appareil œufs-crème."},
{id:"FR053",co:"France",cat:"Plat",sous:"Tarte flambée alsacienne",nom:"Flammekueche Authentique (Tarte Flambée au Feu de Bois)",chef:"Tradition alsacienne — Confrérie de la Tarte Flambée",bp:6,prep:30,cui:8,diff:2,qual:5,ig:[["Farine T55 (mi-blanche, mi-bise idéalement)",400,"g"],["Eau tiède",22,"cl"],["Huile de tournesol ou saindoux fondu",2,"cs"],["Sel fin",8,"g"],["Levure boulangère fraîche (facultatif)",5,"g"],["Crème fraîche épaisse d'Alsace 30% MG",25,"cl"],["Fromage blanc de campagne à 40% MG",15,"cl"],["Lard fumé maigre alsacien en lardons fins",250,"g"],["Oignons doux des Cévennes ou alsaciens",3,"pièces"],["Noix de muscade fraîche râpée",1,"qs"],["Sel fin, poivre blanc du moulin",1,"qs"],["Huile de tournesol pour la plaque",1,"qs"]],et:"PÂTE TRADITIONNELLE (sans levure ou avec une infime quantité) :\n1. La vraie pâte de flammekueche est pratiquement non levée — elle ressemble à une pâte à pizza très fine et craquante. Mélanger farine + sel.\n2. Verser eau tiède + huile + (levure dissoute si utilisée). Pétrir 8 min jusqu'à pâte LISSE et SOUPLE — un peu plus ferme qu'une pâte à pizza.\n3. Bouler, filmer, reposer 1 h à T° ambiante (sans levure : juste pour détendre le gluten ; avec levure : doit doubler).\nGARNITURE :\n4. Émincer les oignons en TRÈS FINES rondelles à la mandoline (1 mm) — texture cruciale pour la cuisson rapide.\n5. Plonger les lardons 30 sec dans l'eau bouillante (élimine l'excès de sel et adoucit le fumage). Égoutter, sécher.\n6. Mélanger crème fraîche d'Alsace + fromage blanc jusqu'à crème homogène. Saler MODÉRÉMENT (lardons), poivre blanc, 4 râpées de muscade fraîche.\nÉTALAGE (technique alsacienne) :\n7. Diviser la pâte en 4 pâtons. Sur un plan FORTEMENT fariné, étaler chaque pâton TRÈS FINEMENT au rouleau (1-2 mm) en RECTANGLE (jamais rond — c'est la signature alsacienne) de 30x20 cm.\n8. Transférer délicatement sur une plaque ou pelle bien farinée.\nGARNISSAGE :\n9. Étaler la crème en couche très fine, 2-3 mm seulement, en laissant 1 cm de bord libre.\n10. Répartir les rondelles d'oignons RÉGULIÈREMENT, sans superposition.\n11. Distribuer les lardons fondants — ne pas trop charger.\nCUISSON (au four à pain de boulanger 350°C ou pierre réfractaire chez soi 280°C) :\n12. Préchauffer le four à PUISSANCE MAXIMALE (250-280°C selon votre four) avec une PIERRE RÉFRACTAIRE pendant minimum 45 min — c'est l'élément non négociable pour reproduire le four à pain.\n13. Glisser la flammekueche directement sur la pierre brûlante (à la pelle).\n14. Cuire 6-8 min seulement. Surveiller : les bords doivent être noirs charbonneux (signature \"flammée\" qui donne son nom — flamm = flamme), la crème dorée bouillonnante, les lardons grésillants.\n15. Servir BRÛLANTE directement à table sur planche en bois, à découper en carrés et manger avec les doigts.",vin:"Riesling d'Alsace sec ou Edelzwicker frais",notes:"La vraie flammekueche alsacienne (Strasbourg-Saverne) se cuit dans un four à pain à bois à 350°C en 90 secondes — d'où son nom \"flamm-kueche\" (gâteau-flamme). À domicile, la pierre réfractaire à 280°C est indispensable. JAMAIS de fromage râpé, JAMAIS de tomate (variation moderne touristique). La pâte n'est pas une pâte à pizza — elle est plus craquante et beaucoup plus fine."},
{id:"FR054",co:"France",cat:"Dessert",sous:"Crème / Œufs",nom:"Île Flottante aux Pralines Roses, Crème Anglaise à la Vanille de Tahiti",chef:"Auguste Escoffier (Le Guide Culinaire, 1903)",bp:6,prep:35,cui:25,diff:3,qual:5,ig:[["Lait entier frais",80,"cl"],["Crème fleurette 35% MG",10,"cl"],["Vanille de Tahiti (Tahitensis)",2,"gousses"],["Jaunes d'œufs frais",8,"pièces"],["Sucre semoule — crème anglaise",100,"g"],["Blancs d'œufs frais à T° ambiante",6,"pièces"],["Sucre semoule — meringue",80,"g"],["Sel fin",1,"pincée"],["Crème de tartre",1,"pincée"],["Pralines roses de Lyon (Maison Pralus)",100,"g"],["Sucre — caramel",100,"g"],["Eau — caramel",3,"cs"],["Vinaigre blanc — caramel",5,"gouttes"],["Amandes effilées grillées",30,"g"]],et:"CRÈME ANGLAISE À LA VANILLE DE TAHITI (étape capitale — base du dessert) :\n1. Fendre les gousses de vanille, gratter les graines avec la pointe du couteau. Mettre graines + gousses fendues dans le lait + crème.\n2. Chauffer doucement à 80°C, couvrir, laisser infuser hors feu 30 min — l'extraction est progressive et profonde. Filtrer. Réchauffer.\n3. Pendant ce temps : blanchir les jaunes d'œufs avec le sucre au fouet électrique 5 min jusqu'à doublement de volume et ruban ferme. C'est le sucre qui protège les jaunes de la coagulation à la chaleur.\n4. Verser le lait infusé bouillant en filet sur les jaunes blanchis en fouettant constamment.\n5. Reverser dans la casserole. Cuire à feu DOUX en remuant constamment à la spatule en bois en formant des 8 (toujours en raclant le fond).\n6. Surveiller au thermomètre : la crème est cuite à 83°C exactement. Test du dos de cuillère : tirer le doigt sur la cuillère — la trace doit rester nette. JAMAIS dépasser 85°C — la crème tournerait.\n7. Retirer immédiatement du feu. Verser dans un récipient froid posé sur bain de glace. Filmer au contact. Réfrigérer 4 h minimum.\nÎLES (œufs en neige pochés à l'anglaise) :\n8. Sortir les blancs 1 h avant. Les fouetter à vitesse moyenne avec sel + crème de tartre 2 min.\n9. Augmenter à grande vitesse. Quand bec d'oiseau (souple), ajouter le sucre EN PLUIE en 3 fois en battant à pleine vitesse jusqu'à neige FERME et BRILLANTE — \"meringue française\".\n10. Faire frémir à 80°C une grande sauteuse remplie d'eau sucrée légère (1 cs sucre / litre).\n11. Façonner des quenelles ovales avec deux grandes cuillères trempées dans l'eau (geste pro). Déposer 4-6 quenelles à la fois — pas de surcharge.\n12. Pocher 1 min 30 d'un côté. Retourner délicatement à l'écumoire. 1 min 30 de l'autre. Égoutter sur papier absorbant. Continuer jusqu'à épuisement de la meringue.\nCARAMEL BLOND :\n13. Cuire sucre + eau + vinaigre à feu moyen sans remuer — laisser caraméliser progressivement jusqu'à ambré clair (175°C). Stopper la cuisson en plongeant le fond de la casserole 2 sec dans l'eau froide.\nDRESSAGE (présentation Escoffier) :\n14. Verser la crème anglaise glacée dans des coupes individuelles ou un grand saladier en cristal.\n15. Déposer délicatement les îles à la surface — elles flottent (d'où le nom).\n16. Concasser les pralines roses au mortier en grain moyen.\n17. Au moment du service : napper d'un filet de caramel chaud (qui forme des fils de sucre — \"cheveux d'ange\") + pluie de pralines roses + amandes effilées grillées.\n18. Servir TRÈS frais.",vin:"Champagne demi-sec ou Sauternes",notes:"Recette canonique d'Auguste Escoffier (Le Guide Culinaire, 1903) : la crème anglaise est l'épreuve du jury de tout examen culinaire français. Cuisson à 83°C exactement = crème nappante sans coagulation. Les îles sont POCHÉES à l'anglaise dans l'eau, jamais au four (qui en fait des soufflés). Les pralines roses sont la signature lyonnaise."},
{id:"FR055",co:"France",cat:"Plat",sous:"Volaille / Normandie",nom:"Poulet Vallée d'Auge au Cidre Brut, Calvados et Pommes Caramélisées",chef:"Michel Bras (Le Suquet, Laguiole)",bp:4,prep:25,cui:55,diff:3,qual:5,ig:[["Poulet de Normandie fermier (label rouge ou bio)",1800,"g"],["Calvados Pays d'Auge AOC vieux 12 ans",10,"cl"],["Cidre brut fermier de la Vallée d'Auge",30,"cl"],["Bouillon de volaille blanc",15,"cl"],["Crème fraîche d'Isigny AOP épaisse",30,"cl"],["Échalotes grises de Roscoff",6,"pièces"],["Pommes Reine des Reinettes (chair ferme)",4,"pièces"],["Champignons de Paris bruns frais",250,"g"],["Beurre fin d'Isigny AOP",80,"g"],["Sucre semoule",30,"g"],["Vinaigre de cidre artisanal",1,"cs"],["Estragon frais",1,"branche"],["Thym frais, laurier",1,"qs"],["Sel de Guérande, poivre blanc du moulin",1,"qs"]],et:"DÉCOUPAGE ET PRÉPARATION :\n1. Découper le poulet en 8 morceaux : 2 ailes, 2 hauts de cuisse, 2 pilons, 2 demi-suprêmes (technique Bras : conserver la peau partout). Réserver la carcasse pour le bouillon.\n2. Saler et poivrer les morceaux 30 min à l'avance — le sel pénètre.\nCUISSON (en deux temps) :\n3. Dans une cocotte en fonte ovale, fondre 30 g de beurre + 1 cs huile à feu moyen-vif. Faire dorer les morceaux côté peau d'abord 6-7 min jusqu'à coloration profonde et caramélisée. Retourner, dorer 4 min de l'autre côté. Réserver.\n4. Dans la même cocotte, faire fondre 30 g beurre. Suer les échalotes ciselées 5 min sans coloration.\n5. Remettre les morceaux de poulet, peau dessus. Arroser de Calvados, FLAMBER (pencher la cocotte vers la flamme) — l'alcool s'évapore en gardant les notes de pomme.\n6. Mouiller au cidre + bouillon. Ajouter thym + laurier. Couvrir.\n7. Cuire à feu très doux 25 min — les blancs en premier (les retirer après 18 min car cuisent plus vite, les laisser au chaud sous alu). Continuer pour les morceaux bruns 25 min total.\nPOMMES CARAMÉLISÉES (en parallèle) :\n8. Éplucher les pommes, retirer le cœur, couper en gros quartiers (8 par pomme).\n9. Dans une poêle, fondre 20 g beurre + sucre. Quand le sucre fume légèrement (caramel blond), ajouter les pommes côté arrondi en bas.\n10. Caraméliser 4 min sans toucher. Retourner. 4 min de l'autre côté. Les pommes doivent être dorées caramel, encore fermes au cœur. Réserver.\nCHAMPIGNONS :\n11. Nettoyer les champignons au pinceau (jamais à l'eau). Couper en quartiers.\n12. Sauter à feu vif dans 20 g beurre 4 min jusqu'à coloration. Saler en fin. Réserver.\nSAUCE FINALE (technique Bras) :\n13. Retirer tous les morceaux de poulet, les maintenir au chaud.\n14. Dégraisser légèrement le fond de cocotte. Faire bouillir vivement pour réduire de moitié, 5 min.\n15. Incorporer la crème fraîche d'Isigny. Réduire à feu moyen 5 min jusqu'à consistance nappante (la crème nappe le dos d'une cuillère).\n16. Hors feu : ajouter 1 cs vinaigre de cidre (relève la sauce, équilibre la richesse — touche Bras), 1 cs Calvados de finition, monter au beurre froid (20 g restants en dés). Filtrer si désiré.\n17. Rectifier sel + poivre blanc.\nDRESSAGE :\n18. Disposer les morceaux de poulet dans un grand plat creux. Entourer des pommes caramélisées + champignons sautés.\n19. Napper de la sauce généreusement. Effeuiller l'estragon frais dessus au dernier moment.\n20. Servir avec une purée d'Isigny ou des pommes de terre dauphine.",vin:"Cidre Brut Fermier (Manoir du Grandouet) ou Pommeau de Normandie",notes:"Selon Michel Bras : le terroir normand authentique repose sur le triptyque cidre + Calvados + crème d'Isigny. Le vinaigre de cidre en finition est la signature qui équilibre la richesse de la crème (technique pour 'tenir' la sauce sans qu'elle saoule). Le Calvados Pays d'Auge AOC vieux est non négociable — un Calvados jeune serait trop agressif."},
{id:"FR056",co:"France",cat:"Entrée",sous:"Œufs / Bourgogne",nom:"Œufs en Meurette au Pinot Noir, Réduction au Jus de Bœuf",chef:"Bernard Loiseau (La Côte d'Or, Saulieu, ★★★)",bp:4,prep:30,cui:45,diff:4,qual:5,ig:[["Œufs frais bio extra-frais",8,"pièces"],["Pinot Noir de Bourgogne (Côte de Beaune)",75,"cl"],["Fond brun de veau lié maison",30,"cl"],["Lardons fumés de Morteau (artisanaux)",200,"g"],["Petits oignons grelots blancs",24,"pièces"],["Champignons de Paris bruns",250,"g"],["Échalotes grises ciselées",4,"pièces"],["Ail",2,"gousses"],["Beurre fin d'Échiré",80,"g"],["Sucre semoule",1,"cc"],["Farine T45 (manié) ",1,"cs"],["Vinaigre de vin blanc — pochage",10,"cl"],["Pain de campagne au levain (4 belles tranches)",4,"pièces"],["Ail pour frotter le pain",1,"gousse"],["Persil plat ciselé",2,"cs"],["Bouquet garni (thym, laurier, queue de persil)",1,"pièce"],["Sel de Guérande, poivre noir concassé",1,"qs"]],et:"RÉDUCTION DE VIN — étape capitale qui prend 1 heure :\n1. Dans une casserole large, mettre vin rouge + échalotes + ail écrasé + bouquet garni + 10 grains de poivre concassés.\n2. Porter à ébullition. FLAMBER (geste signature pour brûler l'alcool éthylique et concentrer les arômes — Loiseau imposait cette étape).\n3. Réduire à feu vif jusqu'à 1/3 du volume — il doit rester environ 25 cl. Filtrer.\nGARNITURE :\n4. Glacer à blanc les oignons grelots : dans une sauteuse, eau à hauteur + 20 g beurre + 1 cc sucre + sel. Couvrir d'un disque de papier sulfurisé. Cuire à découvert jusqu'à évaporation totale et glaçage brillant (15 min). Réserver.\n5. Lardons : tailler en gros bâtonnets. Plonger 30 sec eau bouillante (déssalage). Égoutter, sécher. Faire revenir 5 min à sec à feu moyen — fondants. Réserver.\n6. Champignons : nettoyer au pinceau. Couper en quartiers. Sauter à feu vif dans 20 g beurre 3 min — légère coloration. Saler. Réserver.\nSAUCE MEURETTE (technique Loiseau) :\n7. Verser la réduction de vin filtrée dans une casserole. Ajouter le fond brun de veau lié.\n8. Faire réduire 10 min à feu moyen jusqu'à consistance NAPPANTE — la sauce doit napper le dos d'une cuillère et garder une trace nette quand on tire le doigt.\n9. Beurre manié (Loiseau) : malaxer 1 cs farine + 20 g beurre pommade jusqu'à pâte homogène. Incorporer en petits morceaux à la sauce frémissante en fouettant — apporte le brillant et la liaison parfaite.\n10. Hors feu : monter au beurre froid (40 g restants en dés) en fouettant énergiquement. Sauce devenue lustrée, brillante, profonde. Rectifier sel + poivre.\nŒUFS POCHÉS (technique perfectionniste) :\n11. Faire frémir 1,5 L d'eau + 10 cl vinaigre dans une grande sauteuse — l'eau frémit doucement, jamais à gros bouillon (T° 90°C, le bouillon disperserait les blancs).\n12. Casser chaque œuf dans un petit ramequin individuel. Faire un tourbillon dans l'eau au fouet. Faire glisser l'œuf au cœur du tourbillon.\n13. Pocher 3 min EXACTEMENT — blanc pris autour du jaune coulant. Retirer à l'écumoire. Plonger 30 sec dans un bain d'eau chaude propre (élimine le vinaigre).\n14. Égoutter sur papier absorbant. Si nécessaire : parer les filaments à l'aide d'un emporte-pièce.\nCROÛTONS :\n15. Frotter les tranches de pain de campagne avec ail. Faire dorer dans le beurre noisette 1 min de chaque côté.\nDRESSAGE LOISEAU :\n16. Sur chaque assiette chaude : 1 croûton, 2 œufs pochés posés dessus.\n17. Disposer harmonieusement la garniture autour : lardons fondants, oignons grelots glacés, champignons.\n18. Napper généreusement de sauce meurette brillante (étape théâtrale chez Loiseau).\n19. Pluie de persil plat finement ciselé. Servir IMMÉDIATEMENT — l'œuf pôché doit être brûlant et le jaune coulant.",vin:"Le même Pinot Noir Côte de Beaune (Volnay 1er Cru, Pommard)",notes:"Bernard Loiseau (La Côte d'Or, Saulieu, ★★★) avait codifié cette recette comme étant LA quintessence de la Bourgogne. Le flambage du vin est non négociable. Le beurre manié Loiseau (farine + beurre malaxés) lie sans tasser, contrairement à la maïzena qui rendrait gluant. La sauce doit être TRÈS BRILLANTE — c'est l'épreuve du miroir."},
{id:"FR057",co:"France",cat:"Plat",sous:"Viande",nom:"Andouillette à la Moutarde",chef:"Tradition lyonnaise",bp:4,prep:10,cui:20,diff:1,qual:4,ig:[["Andouillettes AAAAA",4,"pièces"],["Moutarde de Dijon",3,"cs"],["Vin blanc sec",15,"cl"],["Échalotes",3,"pièces"],["Beurre",30,"g"],["Crème fraîche",10,"cl"],["Persil",0.5,"bouquet"]],et:"1. Inciser les andouillettes en croisillon.\n2. Dorer dans beurre à feu moyen 4-5 min/face. Réserver.\n3. Suer échalotes ciselées. Déglacer vin blanc, réduire moitié.\n4. Ajouter moutarde + crème. Frémir 3 min.\n5. Remettre les andouillettes 2 min. Parsemer de persil.",vin:"Pouilly-Fuissé ou Beaujolais léger",notes:"AAAAA = Association Amicale des Amateurs d'Andouillette Authentique."},
{id:"FR058",co:"France",cat:"Plat",sous:"Charcuterie",nom:"Pot-au-Feu",chef:"Tradition française",bp:8,prep:30,cui:240,diff:2,qual:4,ig:[["Paleron de boeuf",800,"g"],["Plat de côtes demi-sel",400,"g"],["Queue de boeuf",400,"g"],["Os à moelle",4,"pièces"],["Carottes navets poireaux céleri",1,"qs"],["Oignons brûlés",2,"pièces"],["Bouquet garni poivre girofle",1,"qs"]],et:"1. Départ à l'eau froide : couvrir les viandes. Monter lentement à frémissement 30 min. Écumer méticuleusement.\n2. Ajouter oignons brûlés + bouquet garni + épices + gros sel. Frémir très doux 1h30.\n3. Ajouter légumes en morceaux. Frémir encore 1h30.\n4. Os à moelle ficelés 30 min avant la fin.\n5. Servir en 2 temps : bouillon puis viandes et légumes.",vin:"Beaujolais Villages rouge",notes:"Ne jamais bouillir. L'écumage pendant la montée est fondamental."},
{id:"FR059",co:"France",cat:"Plat",sous:"Classique",nom:"Blanquette de Veau",chef:"Tradition française",bp:6,prep:30,cui:90,diff:3,qual:4,ig:[["Épaule de veau en cubes",1200,"g"],["Oignons grelots",200,"g"],["Champignons boutons",300,"g"],["Carottes",3,"pièces"],["Bouillon de veau",80,"cl"],["Crème fraîche",25,"cl"],["Jaunes d'oeufs",3,"pièces"],["Beurre",60,"g"],["Farine",50,"g"],["Citron",1,"cs"]],et:"1. Blanchir le veau : départ eau froide, ébullition 5 min. Égoutter, rincer.\n2. Fondre 30g beurre. Singer le veau. Mouiller bouillon progressivement. Frémir à couvert 50 min.\n3. Glacer oignons grelots. Sauter champignons au beurre. Réserver.\n4. Retirer veau. Liaison : jaunes + crème. Épaissir sans bouillir. Monter au beurre. Citron.\n5. Réunir veau + oignons + champignons dans la sauce.",vin:"Meursault ou Chablis 1er Cru",notes:"La liaison à la crème et aux jaunes doit se faire hors feu."},
{id:"FR060",co:"France",cat:"Dessert",sous:"Bretagne",nom:"Far Breton aux Pruneaux",chef:"Tradition bretonne",bp:6,prep:15,cui:50,diff:1,qual:4,ig:[["Pruneaux d'Agen dénoyautés",200,"g"],["Rhum ambré",3,"cs"],["Farine T45",200,"g"],["Sucre",100,"g"],["Oeufs",4,"pièces"],["Lait entier",80,"cl"],["Beurre demi-sel fondu",30,"g"]],et:"1. Macérer pruneaux dans rhum 1 h minimum.\n2. Four 180°C. Beurrer plat en céramique.\n3. Fouetter farine + sucre + sel. Ajouter oeufs en fouettant. Verser lait en filet. Beurre fondu tiède.\n4. Disposer pruneaux dans le plat. Verser l'appareil.\n5. Four 50 min à 180°C. Doré en surface, légèrement tremblotant au centre.",vin:"Cidre demi-sec",notes:"La pâte doit être très liquide pour une texture moelleuse et crémeuse."},
{id:"FR061",co:"France",cat:"Dessert",sous:"Bretagne",nom:"Kouign-Amann",chef:"Tradition douarneniste",bp:8,prep:30,cui:40,diff:3,qual:4,ig:[["Farine T45",500,"g"],["Levure fraîche",20,"g"],["Eau tiède",30,"cl"],["Sel fin",8,"g"],["Beurre demi-sel très froid",250,"g"],["Sucre",200,"g"]],et:"1. Pâte levée : levure + eau tiède + farine + sel. Pétrir 8 min. Lever 1h.\n2. Étaler en rectangle 30x40 cm.\n3. Beurre froid en lamelles sur 2/3 de la pâte. Saupoudrer moitié du sucre. Replier en 3.\n4. Étaler. Reste du sucre. Replier en 3. Réfrigérer 20 min.\n5. Moule 28cm beurré. Étaler la pâte. Reposer 20 min.\n6. Four 200°C 35-40 min jusqu'à caramel foncé. Démouler IMMÉDIATEMENT.",vin:"Cidre brut breton",notes:"Démouler avant que le caramel refroidisse."},
{id:"FR062",co:"France",cat:"Plat",sous:"Alsace",nom:"Choucroute Garnie Alsacienne",chef:"Tradition alsacienne",bp:8,prep:30,cui:180,diff:2,qual:4,ig:[["Choucroute crue",1500,"g"],["Riesling d'Alsace",50,"cl"],["Bouillon de volaille",30,"cl"],["Lard fumé",300,"g"],["Palette fumée",600,"g"],["Saucisses de Strasbourg",8,"pièces"],["Saucisses de Montbéliard",2,"pièces"],["Pommes de terre",1000,"g"],["Genévrier",10,"baies"],["Saindoux",2,"cs"]],et:"1. Fondre saindoux, suer oignons 5 min. Ajouter choucroute lavée.\n2. Poser lard + palette sur choucroute. Genévrier + poivre + laurier + thym.\n3. Mouiller Riesling + bouillon. Porter à frémissement, couvrir.\n4. Feu très doux 2h30. 30 min avant : ajouter pommes de terre. 15 min avant : plonger les saucisses.",vin:"Riesling Alsace ou bière d'Alsace fraîche",notes:"Le Riesling est indispensable."},
{id:"FR063",co:"France",cat:"Entrée",sous:"Soupe",nom:"Soupe à l'Oignon Gratinée",chef:"Tradition parisienne",bp:4,prep:20,cui:60,diff:2,qual:4,ig:[["Oignons",1000,"g"],["Beurre",50,"g"],["Huile",2,"cs"],["Farine",1,"cs"],["Vin blanc sec",20,"cl"],["Bouillon de boeuf",120,"cl"],["Cognac",2,"cs"],["Pain de campagne",4,"tranches"],["Gruyère râpé",120,"g"]],et:"1. Émincer les oignons finement. Les faire fondre dans beurre + huile à feu moyen 40 min en remuant jusqu'à brun doré caramélisé.\n2. Singer (farine), cuire 2 min. Déglacer avec vin blanc + cognac, réduire.\n3. Mouiller avec bouillon chaud. Frémir 20 min. Assaisonner.\n4. Verser dans cocottes individuelles. Poser le pain grillé. Saupoudrer gruyère généreusement.\n5. Gratiner sous le gril jusqu'à fromage doré et bouillonnant.",vin:"Côtes du Rhône rouge léger ou Beaujolais",notes:"La caramélisation lente des oignons est la seule clé."},
{id:"FR064",co:"France",cat:"Plat",sous:"Crustacés",nom:"Bisque de Homard",chef:"Tradition française",bp:4,prep:30,cui:45,diff:3,qual:4,ig:[["Carcasses et têtes de homard",600,"g"],["Carottes",2,"pièces"],["Échalotes",3,"pièces"],["Tomates concassées",300,"g"],["Cognac",8,"cl"],["Vin blanc",20,"cl"],["Crème fraîche",30,"cl"],["Fumet de poisson",80,"cl"],["Concentré de tomates",2,"cs"],["Estragon",2,"branches"]],et:"1. Concasser grossièrement les carcasses. Les faire dorer dans l'huile à feu vif.\n2. Ajouter légumes en mirepoix. Flamber au cognac.\n3. Ajouter vin blanc + concentré + tomates + fumet. Couvrir, frémir 30 min.\n4. Mixer finement. Passer au chinois en pressant bien.\n5. Ajouter crème, réduire à consistance nappante. Rectifier assaisonnement + estragon.",vin:"Chablis Grand Cru ou Meursault",notes:"Passer deux fois au chinois pour une bisque veloutée."},
{id:"FR065",co:"France",cat:"Plat",sous:"Volaille",nom:"Magret de Canard Sauce aux Cerises",chef:"Tradition gasconne",bp:4,prep:15,cui:20,diff:2,qual:4,ig:[["Magrets de canard",2,"pièces"],["Cerises noires",300,"g"],["Vinaigre balsamique",3,"cs"],["Fond de veau",15,"cl"],["Sucre",1,"cs"],["Sel poivre",1,"qs"]],et:"1. Quadriller la peau du magret en croisillons profonds sans entamer la chair.\n2. Assaisonner généreusement. Poser côté peau dans poêle froide. Monter progressivement à feu vif.\n3. Cuire côté peau 8 min en vidant régulièrement la graisse. Retourner, cuire 4 min côté chair (rosé).\n4. Repos 5 min sous alu. Sauce : faire revenir les cerises dans la graisse + sucre. Déglacer vinaigre balsamique + fond de veau. Réduire.",vin:"Madiran ou Cahors Malbec",notes:"La peau doit être croustillante, la chair rosée."},
{id:"FR066",co:"France",cat:"Plat",sous:"Légumes",nom:"Piperade Basquaise",chef:"Tradition basque",bp:4,prep:20,cui:30,diff:1,qual:4,ig:[["Poivrons rouges et verts",4,"pièces"],["Tomates mûres",4,"pièces"],["Oignons",2,"pièces"],["Ail",3,"gousses"],["Piment d'Espelette",1,"cc"],["Huile d'olive",4,"cs"],["Jambon de Bayonne",4,"tranches"],["Oeufs",4,"pièces"]],et:"1. Suer oignons + ail dans l'huile. Ajouter poivrons en lanières. Cuire 10 min.\n2. Ajouter tomates concassées + piment d'Espelette. Compoter 15 min jusqu'à sauce épaisse.\n3. Faire revenir jambon de Bayonne à part. Réserver.\n4. Casser les oeufs dans la piperade. Brouiller à feu doux jusqu'à légèrement pris.\n5. Servir avec le jambon de Bayonne.",vin:"Irouléguy blanc ou rosé du Pays basque",notes:"La piperade est aussi délicieuse sans oeufs en accompagnement."},
{id:"FR067",co:"France",cat:"Entrée",sous:"Tartelette",nom:"Tartelettes aux Asperges et Parmesan",chef:"Tradition française",bp:4,prep:25,cui:20,diff:2,qual:4,ig:[["Asperges vertes",400,"g"],["Pâte feuilletée",200,"g"],["Parmesan râpé",80,"g"],["Crème fraîche",10,"cl"],["Oeufs",2,"pièces"],["Huile d'olive",2,"cs"],["Sel poivre",1,"qs"]],et:"1. Blanchir asperges 4 min. Rafraîchir à l'eau glacée. Égoutter.\n2. Foncer 4 moules de 12cm de pâte feuilletée. Cuire à blanc 10 min à 180°C.\n3. Mélanger crème + oeufs battus + parmesan + sel + poivre.\n4. Verser l'appareil dans les fonds. Disposer les asperges.\n5. Cuire 15 min à 180°C jusqu'à dorure.",vin:"Chablis ou Pouilly-Fumé",notes:"Utiliser des asperges de la même taille pour une cuisson uniforme."},
{id:"FR068",co:"France",cat:"Dessert",sous:"Gâteau",nom:"Gâteau Basque à la Cerise",chef:"Tradition basque",bp:8,prep:30,cui:40,diff:2,qual:4,ig:[["Farine T55",250,"g"],["Beurre pommade",150,"g"],["Sucre",150,"g"],["Oeufs",2,"pièces"],["Levure chimique",1,"cc"],["Confiture de cerises noires",150,"g"],["Rhum",2,"cs"],["Sel",1,"pincée"]],et:"1. Fouetter beurre pommade + sucre jusqu'à crémeux. Ajouter oeufs un par un.\n2. Incorporer farine + levure + sel. La pâte doit être souple.\n3. Diviser en deux. Étaler la moitié dans un moule beurré de 24cm.\n4. Étaler la confiture de cerises + rhum au centre en laissant 1cm de bord.\n5. Couvrir de l'autre moitié de pâte. Souder les bords. Dorer à l'oeuf. Inciser en croisillons.\n6. Four 180°C 35-40 min.",vin:"Irouléguy rouge ou Jurançon moelleux",notes:"La confiture de cerises noires d'Itxassou est l'originale basque."},
{id:"FR069",co:"France",cat:"Plat",sous:"Abats",nom:"Rognons de Veau à la Moutarde",chef:"Tradition française",bp:4,prep:15,cui:15,diff:2,qual:4,ig:[["Rognons de veau",600,"g"],["Moutarde de Dijon",3,"cs"],["Échalotes",3,"pièces"],["Cognac",5,"cl"],["Crème fraîche épaisse",20,"cl"],["Beurre",40,"g"],["Persil",0.5,"bouquet"]],et:"1. Parer les rognons : retirer la graisse et le nerf central. Couper en cubes de 2cm.\n2. Saisir à feu très vif dans beurre brûlant, 2 min max. Réserver (doivent rester rosés).\n3. Suer échalotes dans la même poêle. Flamber au cognac.\n4. Ajouter crème + moutarde. Réduire 3 min.\n5. Remettre les rognons hors feu. Parsemer de persil. Servir immédiatement.",vin:"Bourgogne rouge ou Côte de Nuits",notes:"Les rognons ne doivent jamais être trop cuits - ils deviendraient caoutchouteux."},
{id:"FR070",co:"France",cat:"Entrée",sous:"Salades",nom:"Salade Lyonnaise",chef:"Tradition des bouchons lyonnais",bp:4,prep:20,cui:10,diff:2,qual:4,ig:[["Frisée ou scarole",1,"pièce"],["Lardons fumés",150,"g"],["Oeufs",4,"pièces"],["Croûtons frits aillés",80,"g"],["Vinaigre de vin rouge",3,"cs"],["Huile de noix",4,"cs"],["Moutarde de Dijon",1,"cc"],["Sel poivre",1,"qs"]],et:"1. Vinaigrette : émulsionner moutarde + vinaigre + huile de noix.\n2. Faire revenir lardons à sec jusqu'à dorés croustillants.\n3. Pocher les oeufs dans eau vinaigrée frémissante 3 min. Égoutter.\n4. Assaisonner la frisée avec la vinaigrette chaude des lardons.\n5. Dresser avec lardons chauds + oeuf poché + croûtons.",vin:"Beaujolais rouge ou Mâcon blanc",notes:"La vinaigrette doit être tiède pour légèrement faner la salade."},
{id:"FR071",co:"France",cat:"Plat",sous:"Poisson",nom:"Lotte à l'Armoricaine",chef:"Tradition bretonne",bp:4,prep:20,cui:25,diff:3,qual:4,ig:[["Queue de lotte en tronçons",1000,"g"],["Échalotes",4,"pièces"],["Ail",3,"gousses"],["Tomates concassées",400,"g"],["Cognac",8,"cl"],["Vin blanc sec",20,"cl"],["Crème fraîche",15,"cl"],["Estragon",2,"branches"],["Huile d'olive",3,"cs"]],et:"1. Fariner légèrement les tronçons de lotte. Les saisir à feu vif dans l'huile. Réserver.\n2. Suer échalotes + ail. Flamber au cognac.\n3. Ajouter vin blanc + tomates + estragon. Frémir 10 min.\n4. Remettre la lotte. Cuire à couvert 12 min.\n5. Retirer la lotte. Ajouter crème, réduire légèrement. Rectifier assaisonnement.",vin:"Muscadet sur Lie ou Pouilly-Fumé",notes:"La lotte est robuste et se tient bien à la cuisson."},
{id:"FR072",co:"France",cat:"Plat",sous:"Légumes",nom:"Tartiflette Savoyarde",chef:"Tradition savoyarde",bp:6,prep:20,cui:40,diff:1,qual:4,ig:[["Pommes de terre à chair ferme",1200,"g"],["Reblochon fermier",1,"pièce"],["Lardons fumés",200,"g"],["Oignons",3,"pièces"],["Crème fraîche épaisse",20,"cl"],["Vin blanc de Savoie",10,"cl"],["Beurre",20,"g"]],et:"1. Cuire les pommes de terre entières 20 min. Peler et couper en rondelles épaisse.\n2. Faire revenir lardons + oignons émincés jusqu'à dorés. Déglacer vin blanc.\n3. Mélanger délicatement pommes de terre + lardons + oignons + crème. Assaisonner.\n4. Verser dans plat beurré. Couper le Reblochon en deux dans l'épaisseur. Poser côté croûte vers le haut.\n5. Four 200°C 25 min jusqu'à Reblochon fondu et doré.",vin:"Roussette de Savoie ou Apremont",notes:"Un Reblochon fermier au lait cru est indispensable."},
{id:"FR073",co:"France",cat:"Plat",sous:"Viande",nom:"Navarin d'Agneau Printanier",chef:"Tradition française",bp:6,prep:30,cui:90,diff:2,qual:4,ig:[["Épaule d'agneau en cubes",1200,"g"],["Petites pommes de terre nouvelles",400,"g"],["Carottes nouvelles",200,"g"],["Navets nouveaux",200,"g"],["Petits pois frais",150,"g"],["Oignons nouveaux",12,"pièces"],["Tomates concassées",200,"g"],["Fond d'agneau ou de veau",50,"cl"],["Farine",20,"g"],["Bouquet garni",1,"pièce"]],et:"1. Dorer les cubes d'agneau à feu vif. Singer (farine). Ajouter tomates + bouquet garni + fond.\n2. Frémir à couvert 45 min.\n3. Ajouter carottes + navets + oignons. Cuire 20 min.\n4. Ajouter pommes de terre. Cuire 15 min.\n5. Ajouter petits pois les 5 dernières minutes. Rectifier assaisonnement.",vin:"Côtes du Rhône rouge ou Bandol rosé",notes:"Le terme 'printanier' indique les légumes de saison : toujours frais, jamais en conserve."},
{id:"FR074",co:"France",cat:"Dessert",sous:"Pâtisserie",nom:"Paris-Brest",chef:"Tradition pâtissière française",bp:8,prep:60,cui:40,diff:4,qual:4,ig:[["Eau",25,"cl"],["Beurre",100,"g"],["Farine T55",150,"g"],["Oeufs",5,"pièces"],["Sel",1,"pincée"],["Amandes effilées",60,"g"],["Praliné noisette",150,"g"],["Crème fleurette 35%",50,"cl"],["Sucre glace",30,"g"]],et:"Pâte à choux :\n1. Porter eau + beurre + sel à ébullition. Ajouter farine d'un coup, dessécher 2 min.\n2. Hors feu, incorporer oeufs un par un jusqu'à pâte lisse et souple.\n3. Pocher une couronne de 22cm de diamètre sur plaque. Saupoudrer amandes. Four 200°C 30 min. Ne pas ouvrir.\nCrème pralinée :\n4. Monter crème très froide en chantilly ferme. Incorporer délicatement le praliné.\n5. Couper la couronne en deux. Garnir généreusement de crème pralinée. Sucre glace.",vin:"Champagne Blanc de Blancs",notes:"Créé en 1910 pour commémorer la course Paris-Brest-Paris."},
{id:"FR075",co:"France",cat:"Plat",sous:"Boeuf",nom:"Entrecôte Maître d'Hôtel",chef:"Tradition française",bp:4,prep:10,cui:10,diff:1,qual:4,ig:[["Entrecôtes",4,"pièces"],["Beurre mou",100,"g"],["Persil haché",2,"cs"],["Échalote",1,"pièce"],["Jus de citron",1,"cc"],["Sel poivre",1,"qs"],["Huile",2,"cs"]],et:"1. Beurre maître d'hôtel : mélanger beurre mou + persil haché + échalote ciselée + citron + sel + poivre. Rouler dans film alimentaire, réfrigérer.\n2. Sortir les entrecôtes 30 min avant. Assaisonner juste avant cuisson.\n3. Saisir dans poêle très chaude avec huile : 2-3 min/face pour saignant.\n4. Repos 3 min. Poser une rondelle de beurre maître d'hôtel sur chaque entrecôte chaude.",vin:"Bordeaux Saint-Estèphe ou Pomerol",notes:"Le beurre maître d'hôtel peut être préparé plusieurs jours à l'avance et congelé."},
{id:"FR076",co:"France",cat:"Dessert",sous:"Entremets",nom:"Charlotte aux Fraises",chef:"Tradition française",bp:8,prep:45,cui:0,diff:3,qual:4,ig:[["Biscuits à la cuillère",30,"pièces"],["Fraises fraîches",600,"g"],["Crème fleurette 35%",40,"cl"],["Sucre",80,"g"],["Jus de citron",2,"cs"],["Sirop de sucre + eau de fleur d'oranger",1,"qs"],["Gélatine",3,"feuilles"]],et:"1. Imbiber légèrement les biscuits de sirop. Chemiser un moule à charlotte de biscuits.\n2. Mixer 400g de fraises + sucre + citron. Passer au chinois. Chauffer légèrement, dissoudre la gélatine essorée.\n3. Monter la crème en chantilly. Incorporer délicatement le coulis refroidi.\n4. Couper le reste des fraises en morceaux. Les mélanger à la mousse.\n5. Verser dans le moule. Couvrir de biscuits. Réfrigérer 6h. Démouler.",vin:"Champagne Rosé ou Crémant d'Alsace",notes:"Choisir des fraises de qualité à pleine maturité."},
{id:"FR077",co:"France",cat:"Plat",sous:"Légumes",nom:"Endives au Jambon Gratinées",chef:"Tradition nordiste",bp:4,prep:20,cui:40,diff:1,qual:4,ig:[["Endives",8,"pièces"],["Tranches de jambon blanc",8,"pièces"],["Beurre",40,"g"],["Farine",40,"g"],["Lait entier",50,"cl"],["Gruyère râpé",100,"g"],["Muscade",1,"pincée"],["Sel poivre",1,"qs"]],et:"1. Cuire les endives à l'eau bouillante salée 15 min. Égoutter, presser pour éliminer l'eau.\n2. Enrouler chaque endive dans une tranche de jambon. Disposer dans un plat beurré.\n3. Béchamel : fondre beurre + farine 2 min. Ajouter lait chaud. Cuire en remuant jusqu'à épaississement. Assaisonner + muscade.\n4. Verser la béchamel sur les endives. Saupoudrer de gruyère.\n5. Four 200°C 20 min jusqu'à doré.",vin:"Pinot Gris Alsace ou Côtes du Rhône blanc",notes:"Presser les endives cuites est essentiel pour éviter que le gratin ne soit aqueux."},
{id:"FR078",co:"France",cat:"Dessert",sous:"Biscuit",nom:"Financiers aux Amandes",chef:"Tradition pâtissière française",bp:12,prep:15,cui:15,diff:1,qual:4,ig:[["Blancs d'oeufs",4,"pièces"],["Beurre",150,"g"],["Sucre glace",150,"g"],["Poudre d'amandes",80,"g"],["Farine T55",50,"g"],["Sel",1,"pincée"]],et:"1. Fondre le beurre jusqu'à noisette (couleur ambrée, odeur noisette). Laisser tiédir.\n2. Mélanger sucre glace + poudre d'amandes + farine + sel.\n3. Ajouter les blancs d'oeufs non montés. Mélanger.\n4. Incorporer le beurre noisette tiède.\n5. Verser dans moules à financiers beurrés. Four 200°C 12-15 min jusqu'à dorés.",vin:"Champagne ou thé Earl Grey",notes:"Le beurre noisette est l'arôme essentiel des financiers. Ne pas le faire brûler."},
{id:"FR079",co:"France",cat:"Plat",sous:"Poisson",nom:"Truite Meunière aux Amandes",chef:"Tradition française",bp:4,prep:10,cui:15,diff:1,qual:4,ig:[["Truites",4,"pièces"],["Beurre",100,"g"],["Amandes effilées",60,"g"],["Farine",50,"g"],["Citron",2,"pièces"],["Persil",0.5,"bouquet"],["Sel poivre",1,"qs"]],et:"1. Fariner légèrement les truites, secouer l'excédent.\n2. Faire fondre 60g de beurre dans une grande poêle. Cuire les truites 4 min/face à feu moyen. Réserver.\n3. Vider la poêle. Faire fondre le reste du beurre jusqu'à noisette.\n4. Ajouter les amandes effilées, laisser dorer légèrement.\n5. Jus de citron hors feu. Verser sur les truites. Parsemer de persil ciselé.",vin:"Chablis ou Sancerre blanc",notes:"Le beurre doit être noisette, pas brun foncé."},
{id:"FR080",co:"France",cat:"Entrée",sous:"Soufflé",nom:"Soufflé de Saumon Fumé",chef:"Tradition française",bp:4,prep:20,cui:15,diff:4,qual:4,ig:[["Saumon fumé",150,"g"],["Beurre",30,"g"],["Farine",30,"g"],["Lait entier",20,"cl"],["Oeufs",4,"pièces"],["Aneth",2,"cs"],["Sel poivre",1,"qs"]],et:"1. Four 190°C. Chemiser 4 ramequins de beurre + chapelure.\n2. Béchamel : fondre beurre + farine 2 min. Lait chaud. Épaissir. Ajouter saumon fumé haché + aneth. Hors feu, incorporer jaunes.\n3. Monter blancs en neige ferme. Incorporer délicatement à l'appareil.\n4. Remplir les ramequins aux 3/4.\n5. Four 190°C 12-14 min SANS OUVRIR. Servir immédiatement.",vin:"Sancerre blanc ou Champagne Blanc de Blancs",notes:"Servir en courant. Le soufflé attend personne."},
{id:"FR081",co:"France",cat:"Plat",sous:"Friture",nom:"Grenouilles à la Persillade",chef:"Tradition bressane et bourguignonne",bp:4,prep:20,cui:10,diff:2,qual:4,ig:[["Cuisses de grenouilles",32,"pièces"],["Farine",50,"g"],["Beurre",80,"g"],["Ail",4,"gousses"],["Persil plat haché",1,"bouquet"],["Jus de citron",1,"cs"],["Sel poivre",1,"qs"]],et:"1. Sécher soigneusement les cuisses de grenouilles. Fariner légèrement.\n2. Faire fondre le beurre à feu vif dans une grande poêle. Saisir les cuisses par petites quantités 2-3 min/face jusqu'à dorées croustillantes.\n3. Saler, poivrer.\n4. Beurre noisette dans la poêle vide. Ajouter ail haché finement. Faire blondir sans brûler.\n5. Jus de citron hors feu. Verser sur les grenouilles. Parsemer de persil ciselé généreusement.",vin:"Pouilly-Fuissé ou Chablis 1er Cru",notes:"Les cuisses doivent être bien séchées pour un résultat croustillant."},
{id:"FR082",co:"France",cat:"Dessert",sous:"Soufflé glacé",nom:"Soufflé Glacé au Grand Marnier",chef:"Tradition française",bp:8,prep:40,cui:0,diff:3,qual:4,ig:[["Jaunes d'oeufs",6,"pièces"],["Sucre",180,"g"],["Eau",5,"cl"],["Crème fleurette 35%",40,"cl"],["Grand Marnier",6,"cs"],["Blancs d'oeufs",4,"pièces"]],et:"1. Chemiser des ramequins de papier sulfurisé dépassant de 3cm (pour simuler la montée du soufflé).\n2. Sirop : cuire sucre + eau à 121°C. Verser en filet sur les jaunes fouettés. Continuer à fouetter jusqu'à refroidissement.\n3. Incorporer le Grand Marnier.\n4. Monter crème + blancs séparément. Incorporer délicatement à l'appareil.\n5. Verser dans les ramequins jusqu'au dessus du papier. Congeler 6h minimum. Retirer le papier avant de servir.",vin:"Champagne demi-sec ou café",notes:"Le papier sulfurisé crée l'illusion visuelle du soufflé chaud qui déborde."},
{id:"FR083",co:"France",cat:"Plat",sous:"Gibier",nom:"Civet de Lapin au Vin Rouge",chef:"Tradition française",bp:6,prep:30,cui:90,diff:2,qual:4,ig:[["Lapin découpé en morceaux",1,"pièce"],["Vin rouge corsé",75,"cl"],["Oignons grelots",200,"g"],["Lardons fumés",150,"g"],["Champignons de Paris",200,"g"],["Ail",4,"gousses"],["Bouquet garni",1,"pièce"],["Sang de lapin ou crème (liaison)",1,"qs"],["Farine",20,"g"],["Beurre",40,"g"]],et:"1. Mariner le lapin dans le vin rouge + aromates + oignons 12h au froid.\n2. Égoutter, sécher le lapin. Faire dorer dans beurre. Réserver. Suer lardons + oignons égouttés.\n3. Singer les morceaux (farine). Remettre dans la cocotte. Verser le vin de marinade filtré + bouquet garni.\n4. Frémir à couvert 1h à feu doux.\n5. Retirer le lapin. Monter la sauce au beurre froid. Ajouter champignons sautés. Remettre le lapin.",vin:"Bourgogne rouge ou Côtes du Rhône",notes:"La liaison au sang est la recette traditionnelle; la crème est le substitut moderne."},
{id:"FR084",co:"France",cat:"Dessert",sous:"Biscuit",nom:"Madeleine de Commercy",chef:"Tradition lorraine",bp:12,prep:20,cui:12,diff:2,qual:4,ig:[["Farine T45",150,"g"],["Sucre",150,"g"],["Beurre",150,"g"],["Oeufs",3,"pièces"],["Levure chimique",1,"cc"],["Zeste de citron non traité",1,"pièce"],["Miel",1,"cs"],["Sel",1,"pincée"]],et:"1. Fondre le beurre. Clarifier puis faire légèrement noisette. Laisser tiédir.\n2. Fouetter oeufs + sucre + miel jusqu'à ruban. Incorporer farine + levure + sel + zeste de citron.\n3. Incorporer le beurre noisette tiède. La pâte doit être lisse.\n4. Réfrigérer 1h minimum (la bosse de la madeleine vient du choc thermique).\n5. Beurrer et fariner les moules. Remplir aux 3/4. Four 220°C 5 min, puis 180°C 7 min. Démouler immédiatement.",vin:"Champagne ou thé Earl Grey",notes:"Le repos au froid est le secret de la bosse caractéristique de la madeleine."},
{id:"FR085",co:"France",cat:"Plat",sous:"Cervelle",nom:"Vol-au-Vent à la Financière",chef:"Tradition française",bp:4,prep:30,cui:30,diff:3,qual:4,ig:[["Croûtes à vol-au-vent",4,"pièces"],["Ris de veau",200,"g"],["Quenelles de volaille",8,"petites"],["Champignons de Paris",150,"g"],["Crêtes et rognons de coq",100,"g"],["Beurre",60,"g"],["Farine",30,"g"],["Bouillon de volaille",30,"cl"],["Crème fraîche",10,"cl"],["Madère",5,"cl"]],et:"1. Préparer les ris de veau : dégorger, blanchir, parer, saisir dans beurre. Réserver.\n2. Sauce Financière : fondre beurre + farine. Mouiller bouillon chaud. Ajouter crème + Madère. Réduire.\n3. Sauter champignons dans beurre. Pocher les quenelles 3 min dans bouillon frémissant.\n4. Réunir tous les éléments dans la sauce. Chauffer doucement.\n5. Chauffer les croûtes au four 5 min. Garnir à la dernière minute.",vin:"Meursault ou Chablis Grand Cru",notes:"La garniture Financière est la plus noble des garnitures classiques françaises."},
{id:"FR086",co:"France",cat:"Sauce / Base",sous:"Sauce mère",nom:"Sauce Velouté de Volaille",chef:"Tradition française classique",bp:4,prep:10,cui:20,diff:2,qual:4,ig:[["Beurre",40,"g"],["Farine",40,"g"],["Bouillon de volaille chaud",50,"cl"],["Crème fraîche",10,"cl"],["Jus de citron",1,"cc"],["Sel poivre blanc",1,"qs"]],et:"1. Fondre le beurre à feu moyen. Ajouter la farine, mélanger. Cuire 2 min (roux blanc).\n2. Verser le bouillon chaud progressivement en fouettant vigoureusement.\n3. Porter à frémissement en continuant à fouetter. Cuire 10-15 min à feu doux.\n4. Passer au chinois fin.\n5. Incorporer crème fraîche + jus de citron. Rectifier assaisonnement.",vin:"Accompagnement : blanquette, fricassée, quenelles, vol-au-vent",notes:"La sauce velouté est une des 5 sauces mères de la cuisine française classique."},
{id:"FR087",co:"France",cat:"Plat",sous:"Canard",nom:"Confit de Canard à la Gascon",chef:"Tradition gasconne",bp:4,prep:30,cui:150,diff:2,qual:4,ig:[["Cuisses de canard",4,"pièces"],["Gros sel",80,"g"],["Poivre noir concassé",1,"cs"],["Thym laurier",3,"branches"],["Ail",4,"gousses"],["Graisse de canard",800,"g"]],et:"1. J-1 : frotter les cuisses avec sel + poivre + thym + ail écrasé. Réfrigérer 12h.\n2. Rincer soigneusement les cuisses. Sécher avec soin.\n3. Faire fondre la graisse de canard à 85°C dans une cocotte. Plonger les cuisses. Elles doivent être entièrement recouvertes.\n4. Maintenir à 85°C (frémissement doux) 2h30. Vérifier avec thermomètre.\n5. Pour servir : retirer de la graisse. Faire dorer côté peau à la poêle à sec 7-8 min jusqu'à croustillant.",vin:"Madiran ou Cahors Malbec",notes:"Le confit se conserve recouvert de sa graisse 3 semaines au frigo."},
{id:"FR088",co:"France",cat:"Plat",sous:"Champignons",nom:"Fricassée de Champignons des Bois",chef:"Tradition française",bp:4,prep:15,cui:15,diff:1,qual:4,ig:[["Champignons des bois mélangés (girolles cèpes chanterelles)",500,"g"],["Échalotes",3,"pièces"],["Ail",2,"gousses"],["Beurre",50,"g"],["Crème fraîche",10,"cl"],["Persil plat",0.5,"bouquet"],["Jus de citron",1,"cc"],["Sel poivre",1,"qs"]],et:"1. Nettoyer les champignons avec un pinceau sec. Les couper en morceaux réguliers.\n2. Faire mousser le beurre dans une grande poêle à feu vif. Y ajouter les champignons sans les remuer pendant 2 min (ils doivent saisir).\n3. Mélanger. Ajouter échalotes + ail hachés. Cuire encore 3-4 min.\n4. Saler, poivrer. Ajouter crème fraîche. Frémir 2 min.\n5. Jus de citron. Parsemer de persil ciselé. Servir sur toast grillé ou avec oeuf poché.",vin:"Bourgogne blanc ou Côtes du Jura",notes:"Ne jamais laver les champignons à l'eau - ils se gorgeraient d'humidité."},
{id:"FR089",co:"France",cat:"Plat",sous:"Classique",nom:"Boeuf Stroganoff à la Française",chef:"Tradition franco-russe",bp:4,prep:20,cui:20,diff:2,qual:4,ig:[["Filet de boeuf en lanières",600,"g"],["Oignons",2,"pièces"],["Champignons de Paris",300,"g"],["Crème fraîche épaisse",25,"cl"],["Moutarde de Dijon",2,"cs"],["Paprika",1,"cc"],["Cognac",5,"cl"],["Beurre",40,"g"]],et:"1. Saisir les lanières de boeuf très rapidement à feu vif (elles doivent rester rosées). Réserver.\n2. Suer oignons + champignons dans beurre.\n3. Flamber au cognac. Ajouter crème + moutarde + paprika. Frémir 3 min.\n4. Remettre le boeuf hors feu. Assaisonner. Servir avec riz pilaf.",vin:"Côtes du Rhône rouge ou Bourgogne rouge",notes:"Le boeuf ne doit jamais finir de cuire dans la sauce."},
{id:"FR090",co:"France",cat:"Dessert",sous:"Bavarois",nom:"Bavarois à la Framboise",chef:"Tradition française",bp:8,prep:40,cui:10,diff:3,qual:4,ig:[["Framboises fraîches",500,"g"],["Crème fleurette 35%",40,"cl"],["Sucre",120,"g"],["Gélatine",5,"feuilles"],["Lait entier",20,"cl"],["Jaunes d'oeufs",4,"pièces"],["Biscuits à la cuillère",20,"pièces"]],et:"1. Crème anglaise : fouetter jaunes + 80g sucre. Ajouter lait chaud. Cuire à 83°C. Essorer gélatine, dissoudre dans la crème chaude.\n2. Coulis : mixer framboises + 40g sucre. Passer au chinois. Incorporer à la crème anglaise refroidie.\n3. Monter crème en chantilly. Incorporer délicatement.\n4. Chemiser moule de biscuits. Verser la mousse. Réfrigérer 6h.\n5. Démouler, décorer de framboises fraîches.",vin:"Champagne Rosé",notes:"La gélatine doit être bien dissoute sinon la texture sera granuleuse."},
{id:"FR091",co:"France",cat:"Plat",sous:"Tatin salée",nom:"Tatin d'Endives au Roquefort",chef:"Tradition française",bp:6,prep:20,cui:50,diff:2,qual:4,ig:[["Endives",8,"pièces"],["Beurre",40,"g"],["Sucre",20,"g"],["Roquefort",80,"g"],["Noix",50,"g"],["Pâte brisée",200,"g"],["Sel poivre",1,"qs"]],et:"1. Faire caraméliser légèrement le sucre dans le beurre dans une poêle allant au four.\n2. Couper les endives en deux dans la longueur. Les disposer côté coupé vers le bas dans le caramel.\n3. Cuire à feu doux 20 min. Assaisonner.\n4. Parsemer de roquefort émietté + noix.\n5. Couvrir de pâte brisée en rentrant les bords. Four 190°C 25-30 min. Retourner dès la sortie du four.",vin:"Sauternes ou Jurançon moelleux",notes:"Retourner immédiatement pour que le caramel reste sur les endives."},
{id:"FR092",co:"France",cat:"Entrée",sous:"Terrine",nom:"Terrine de Campagne Maison",chef:"Tradition française",bp:10,prep:30,cui:90,diff:2,qual:4,ig:[["Porc haché (gorge et épaule)",600,"g"],["Foie de porc haché",200,"g"],["Veau haché",200,"g"],["Lardons",100,"g"],["Oignons",2,"pièces"],["Oeufs",2,"pièces"],["Cognac",4,"cs"],["Thym laurier",1,"qs"],["Ail",3,"gousses"],["Sel poivre muscade",1,"qs"],["Barde de lard",4,"tranches"]],et:"1. Mélanger toutes les viandes + oeufs + oignons hachés + cognac + ail + épices. Assaisonner généreusement.\n2. Chemiser une terrine de bardes de lard.\n3. Remplir de farce. Tasser. Couvrir de bardes de lard. Poser une feuille de laurier.\n4. Couvrir le couvercle. Cuire au bain-marie 90 min à 165°C.\n5. Mettre sous presse pendant le refroidissement. Réfrigérer 48h avant de servir.",vin:"Beaujolais rouge ou Côtes du Rhône",notes:"La terrine est meilleure après 48h de repos. Elle se conserve une semaine au frigo."},
{id:"FR093",co:"France",cat:"Plat",sous:"Médaillon",nom:"Médaillons de Lotte au Beurre de Citron Vert",chef:"Tradition française moderne",bp:4,prep:15,cui:15,diff:2,qual:4,ig:[["Queue de lotte en médaillons",800,"g"],["Beurre très froid",100,"g"],["Citron vert jus et zeste",2,"pièces"],["Ciboulette",2,"cs"],["Échalotes",2,"pièces"],["Vin blanc sec",8,"cl"],["Huile d'olive",3,"cs"],["Sel poivre",1,"qs"]],et:"1. Assaisonner les médaillons. Les saisir dans l'huile à feu vif 2-3 min/face. Réserver au chaud.\n2. Suer les échalotes dans la même poêle. Déglacer au vin blanc. Réduire presque à sec.\n3. Hors feu : incorporer le beurre froid en dés en fouettant rapidement (beurre blanc).\n4. Ajouter zeste + jus de citron vert + ciboulette ciselée.\n5. Napper les médaillons de cette sauce beurre blanc au citron vert.",vin:"Chablis 1er Cru ou Pouilly-Fuissé",notes:"Le beurre blanc doit se faire hors feu pour ne pas se séparer."},
{id:"FR094",co:"France",cat:"Dessert",sous:"Gaufre",nom:"Gaufres de Liège au Beurre de Sucre",chef:"Tradition liégeoise",bp:8,prep:30,cui:20,diff:2,qual:4,ig:[["Farine T45",500,"g"],["Levure de boulanger fraîche",20,"g"],["Lait tiède",15,"cl"],["Beurre pommade",200,"g"],["Oeufs",2,"pièces"],["Sucre perlé belge",100,"g"],["Sel",1,"pincée"],["Vanille",1,"cc"]],et:"1. Diluer levure dans lait tiède. Mélanger farine + sel + oeufs + lait-levure. Pétrir 5 min.\n2. Incorporer le beurre pommade progressivement. Pétrir 5 min jusqu'à pâte lisse et élastique.\n3. Lever 1h à T° ambiante.\n4. Incorporer le sucre perlé délicatement à la main.\n5. Diviser en boules de 80g. Cuire au gaufrier préchauffé et beurré 4-5 min jusqu'à caramelisation du sucre perlé.",vin:"Thé ou café belge",notes:"La gaufre de Liège est radicalement différente de la gaufre bruxelloise : petite, dense, caramélisée, pas rectangulaire."},
{id:"FR095",co:"France",cat:"Plat",sous:"Saucisse",nom:"Saucisses de Morteau et Pommes de Terre à la Franc-Comtoise",chef:"Tradition franc-comtoise",bp:4,prep:15,cui:45,diff:1,qual:4,ig:[["Saucisses de Morteau",4,"pièces"],["Pommes de terre",1000,"g"],["Oignons",2,"pièces"],["Lardons fumés",100,"g"],["Vin jaune ou vin blanc du Jura",20,"cl"],["Crème fraîche",15,"cl"],["Comté râpé",80,"g"],["Moutarde de Meaux",2,"cs"]],et:"1. Cuire les saucisses de Morteau entières dans l'eau 30 min (sans percer la peau).\n2. Faire revenir oignons + lardons dans une cocotte. Ajouter pommes de terre tranchées.\n3. Déglacer avec le vin jaune. Ajouter crème + moutarde. Mélanger.\n4. Ajouter les saucisses de Morteau coupées en rondelles épaisses. Couvrir.\n5. Cuire à feu doux 20 min. Parsemer de comté. Passer sous le gril 5 min.",vin:"Vin jaune du Jura ou Savagnin ouillé",notes:"La saucisse de Morteau est AOC et se distingue par son anneau de bois de fixation."},
{id:"FR096",co:"France",cat:"Plat",sous:"Classique",nom:"Pot-au-Feu de Volaille",chef:"Tradition française",bp:6,prep:20,cui:120,diff:2,qual:4,ig:[["Poularde ou poulet fermier",2000,"g"],["Carottes",4,"pièces"],["Navets",3,"pièces"],["Poireaux",3,"pièces"],["Céleri branche",3,"branches"],["Oignon piqué de girofle",1,"pièce"],["Bouquet garni",1,"pièce"],["Os à moelle",4,"pièces"],["Gros sel",1,"qs"]],et:"1. Placer la volaille dans une grande marmite. Couvrir d'eau froide. Porter à frémissement en écumant.\n2. Ajouter tous les légumes + bouquet garni + sel. Frémir à couvert 1h30.\n3. Ficeler les os à moelle. Ajouter 30 min avant la fin.\n4. Servir en deux temps : bouillon avec vermicelles, puis volaille et légumes avec moutarde, cornichons, fleur de sel.",vin:"Chablis ou Bourgogne aligoté",notes:"Le bouillon de volaille est plus délicat que celui du bœuf. À ne pas faire bouillir."},
{id:"FR097",co:"France",cat:"Entrée",sous:"Velouté",nom:"Velouté de Champignons",chef:"Tradition française",bp:4,prep:15,cui:25,diff:1,qual:4,ig:[["Champignons de Paris",500,"g"],["Échalotes",3,"pièces"],["Beurre",40,"g"],["Bouillon de volaille",80,"cl"],["Crème fraîche",15,"cl"],["Jus de citron",1,"cc"],["Persil",0.5,"bouquet"],["Sel poivre muscade",1,"qs"]],et:"1. Émincer les champignons. Suer les échalotes dans le beurre.\n2. Ajouter les champignons, cuire à feu vif jusqu'à évaporation de l'eau.\n3. Mouiller avec le bouillon. Frémir 15 min.\n4. Mixer finement. Incorporer la crème. Assaisonner + muscade + citron.\n5. Servir avec quelques champignons sautés en garniture et persil ciselé.",vin:"Meursault ou Côtes du Jura blanc",notes:"Pour un velouté plus parfumé, ajouter quelques cèpes séchés réhydratés."},
{id:"FR098",co:"France",cat:"Plat",sous:"Gibier",nom:"Faisan à la Normande",chef:"Tradition normande",bp:4,prep:20,cui:50,diff:3,qual:4,ig:[["Faisans bridés",2,"pièces"],["Pommes Reinette",4,"pièces"],["Calvados",8,"cl"],["Cidre brut",30,"cl"],["Crème fraîche normande",25,"cl"],["Beurre",50,"g"],["Lardons",100,"g"],["Échalotes",4,"pièces"]],et:"1. Faire dorer les faisans sur toutes les faces dans le beurre avec les lardons.\n2. Ajouter échalotes hachées. Flamber au calvados.\n3. Mouiller avec le cidre. Cuire à couvert 30 min à feu doux.\n4. Peler pommes, couper en quartiers. Dorer dans beurre séparément.\n5. Retirer les faisans. Crème fraîche dans la cocotte, réduire. Remettre faisans + pommes.",vin:"Cidre brut normand ou Calvados",notes:"Le faisan a tendance à se dessécher. La cuisson à couvert est indispensable."},
{id:"FR099",co:"France",cat:"Dessert",sous:"Tarte",nom:"Tarte Bourdaloue aux Poires",chef:"Tradition pâtissière française",bp:8,prep:40,cui:35,diff:3,qual:4,ig:[["Farine T55",200,"g"],["Beurre pommade",100,"g"],["Sucre glace",60,"g"],["Œuf",1,"pièce"],["Poires Williams pochées",4,"pièces"],["Poudre d'amandes",120,"g"],["Beurre mou pour crème",120,"g"],["Sucre",120,"g"],["Œufs pour crème",2,"pièces"],["Rhum",2,"cs"]],et:"Pâte sablée :\n1. Sabler farine + beurre + sucre glace. Ajouter œuf. Réfrigérer 1h. Foncer moule 26cm. Cuire à blanc 15 min.\nCrème d'amandes :\n2. Fouetter beurre mou + sucre jusqu'à crémeux. Ajouter œufs un par un + rhum + poudre d'amandes.\nMontage :\n3. Étaler la crème d'amandes sur le fond précuit.\n4. Égoutter les poires pochées. Les trancher. Les disposer en éventail.\n5. Four 180°C 30-35 min jusqu'à crème d'amandes dorée.",vin:"Sauternes ou Monbazillac",notes:"La crème d'amandes doit être à T° ambiante pour s'étaler facilement."},
{id:"FR100",co:"France",cat:"Plat",sous:"Légumes",nom:"Timbale d'Aubergines au Coulis de Tomate",chef:"Tradition provençale",bp:4,prep:30,cui:40,diff:2,qual:4,ig:[["Aubergines",3,"pièces"],["Tomates mûres",500,"g"],["Oignon",1,"pièce"],["Ail",4,"gousses"],["Mozzarella",200,"g"],["Basilic",1,"bouquet"],["Huile d'olive",6,"cs"],["Sel poivre",1,"qs"]],et:"1. Trancher les aubergines en rondelles de 5mm. Saler, dégorger 20 min. Rincer, sécher.\n2. Faire dorer les rondelles d'aubergines à l'huile d'olive. Égoutter.\n3. Coulis : suer oignon + ail + tomates 20 min. Mixer, passer au chinois.\n4. Chemiser 4 ramequins d'aubergines en les faisant se chevaucher. Couche de mozzarella + basilic + coulis. Répéter.\n5. Four 180°C 20 min. Démouler sur assiette. Servir chaud avec coulis.",vin:"Provence rosé ou Côtes du Rhône blanc",notes:"Bien huiler les ramequins pour faciliter le démoulage."},
{id:"FR101",co:"France",cat:"Plat",sous:"Fruits de mer",nom:"Moules Marinières",chef:"Tradition bretonne et normande",bp:4,prep:15,cui:10,diff:1,qual:4,ig:[["Moules de Bouchot",2000,"g"],["Échalotes",4,"pièces"],["Beurre",40,"g"],["Vin blanc sec",20,"cl"],["Persil plat",1,"bouquet"],["Thym laurier",1,"qs"],["Poivre",1,"qs"]],et:"1. Gratter et laver les moules. Éliminer toutes celles qui ne se ferment pas.\n2. Suer les échalotes ciselées dans le beurre.\n3. Ajouter vin blanc + thym + laurier + poivre. Porter à ébullition.\n4. Verser les moules. Couvrir. Cuire à feu très vif 3-4 min en secouant régulièrement.\n5. Dès que les moules sont ouvertes, parsemer de persil. Servir immédiatement avec les jus.",vin:"Muscadet sur Lie ou bière bretonne",notes:"Ne jamais saler les moules - elles sont naturellement salées. Jeter toutes celles qui ne s'ouvrent pas."},
{id:"FR102",co:"France",cat:"Entrée",sous:"Omelette",nom:"Omelette Baveuse aux Fines Herbes",chef:"Tradition française",bp:2,prep:5,cui:3,diff:2,qual:4,ig:[["Œufs très frais",6,"pièces"],["Beurre",30,"g"],["Ciboulette",2,"cs"],["Persil plat",1,"cs"],["Cerfeuil",1,"cs"],["Estragon",1,"cc"],["Sel poivre",1,"qs"]],et:"1. Ciseler finement toutes les herbes. Battre les œufs légèrement - les jaunes et blancs doivent rester à peine mélangés.\n2. Assaisonner sel + poivre + herbes.\n3. Fondre beurre à feu vif dans poêle chaude jusqu'à mousse. Verser les œufs.\n4. Remuer rapidement avec fourchette à plat pendant 15 sec. Arrêter de remuer. Incliner la poêle.\n5. Rouler l'omelette sur elle-même quand le dessous est pris mais le dessus encore baveux. Servir immédiatement.",vin:"Chablis ou Pouilly-Fumé",notes:"L'omelette française se roule, elle ne se plie pas. Elle doit être baveuse."},
{id:"FR103",co:"France",cat:"Plat",sous:"Agneau",nom:"Épaule d'Agneau Confite à l'Ail et au Thym",chef:"Tradition provençale",bp:6,prep:15,cui:240,diff:1,qual:4,ig:[["Épaule d'agneau entière",1800,"g"],["Ail",2,"têtes entières"],["Thym romarin",8,"branches"],["Huile d'olive",5,"cs"],["Vin blanc",15,"cl"],["Sel poivre",1,"qs"]],et:"1. Piquer l'épaule de nombreuses gousses d'ail. Frotter avec huile d'olive + sel + poivre.\n2. Déposer dans plat à rôtir sur lit de thym + romarin + gousses d'ail restantes.\n3. Ajouter le vin blanc. Couvrir hermétiquement de papier alu.\n4. Four 150°C pendant 4h. L'agneau doit se détacher à la cuillère.\n5. Retirer l'alu les 20 dernières minutes pour colorer. Arroser régulièrement.",vin:"Gigondas ou Châteauneuf-du-Pape",notes:"La patience est la vertu de ce plat. À 4h, l'agneau est fondant et se détache seul."},
{id:"FR104",co:"France",cat:"Dessert",sous:"Entremets",nom:"Pêche Melba",chef:"Tradition classique française",bp:4,prep:20,cui:15,diff:2,qual:4,ig:[["Pêches jaunes mûres",4,"pièces"],["Eau",50,"cl"],["Sucre",150,"g"],["Vanille",1,"gousse"],["Framboises fraîches",300,"g"],["Sucre glace",60,"g"],["Citron",1,"cs"],["Glace vanille",400,"g"],["Amandes effilées grillées",30,"g"]],et:"1. Sirop vanille : eau + sucre + vanille, bouillir 5 min.\n2. Peler les pêches, les pocher dans le sirop 5-6 min. Laisser refroidir dans le sirop.\n3. Coulis Melba : mixer framboises + sucre glace + citron. Passer au chinois.\n4. Dans coupes : boule de glace vanille + demi-pêche pochée froide.\n5. Napper de coulis de framboises. Parsemer d'amandes grillées.",vin:"Champagne Blanc de Blancs ou Sauternes",notes:"Les pêches doivent être pochées et refroidies. La pêche chaude ferait fondre la glace."},
{id:"FR105",co:"France",cat:"Plat",sous:"Porc",nom:"Côtes de Porc Sauce Charcutière",chef:"Tradition française",bp:4,prep:10,cui:20,diff:1,qual:4,ig:[["Côtes de porc dans l'échine",4,"pièces"],["Oignons",2,"pièces"],["Cornichons",6,"pièces"],["Moutarde forte",2,"cs"],["Vin blanc sec",15,"cl"],["Fond de veau",15,"cl"],["Beurre",30,"g"],["Sel poivre",1,"qs"]],et:"1. Assaisonner les côtes. Les faire dorer dans beurre 4 min/face. Réserver au chaud.\n2. Suer les oignons émincés dans la même poêle.\n3. Déglacer au vin blanc. Réduire moitié. Ajouter fond de veau. Frémir 5 min.\n4. Ajouter moutarde + cornichons en rondelles. Frémir 2 min. Monter au beurre froid hors feu.\n5. Napper les côtes de sauce charcutière.",vin:"Beaujolais Villages ou Côtes du Rhône rouge",notes:"La sauce charcutière ne doit jamais bouillir après ajout de la moutarde."},
{id:"FR106",co:"France",cat:"Dessert",sous:"Gâteau",nom:"Gâteau Breton",chef:"Tradition bretonne",bp:8,prep:20,cui:40,diff:1,qual:4,ig:[["Farine T55",300,"g"],["Beurre demi-sel pommade",225,"g"],["Sucre",225,"g"],["Jaunes d'œufs",4,"pièces"],["Rhum",2,"cs"],["Sel",1,"pincée"]],et:"1. Fouetter beurre pommade + sucre jusqu'à crémeux.\n2. Incorporer 3 jaunes d'œufs un par un + rhum.\n3. Ajouter farine + sel. Amalgamer sans trop travailler.\n4. Étaler dans moule 24cm beurré. Lisser. Dorer avec le 4e jaune dilué d'eau. Strier en croisillons.\n5. Four 175°C 35-40 min jusqu'à doré profond. Refroidir avant de démouler.",vin:"Cidre demi-sec breton ou café fort",notes:"Le beurre demi-sel breton est indispensable. Le gâteau doit avoir une croûte dorée foncée."},
{id:"FR107",co:"France",cat:"Plat",sous:"Veau",nom:"Escalope de Veau à la Crème et Champignons",chef:"Tradition française",bp:4,prep:15,cui:15,diff:1,qual:4,ig:[["Escalopes de veau",4,"pièces"],["Champignons de Paris",300,"g"],["Crème fraîche épaisse",20,"cl"],["Beurre",50,"g"],["Échalotes",2,"pièces"],["Vin blanc",8,"cl"],["Persil",0.5,"bouquet"],["Sel poivre",1,"qs"]],et:"1. Aplatir les escalopes. Assaisonner, fariner légèrement.\n2. Saisir dans beurre à feu vif 2 min/face. Réserver au chaud.\n3. Suer échalotes + champignons émincés dans la même poêle.\n4. Déglacer au vin blanc. Réduire. Ajouter crème. Frémir 3 min.\n5. Remettre les escalopes dans la sauce 1 min. Parsemer de persil.",vin:"Meursault ou Chablis 1er Cru",notes:"Les escalopes ne doivent pas finir de cuire dans la crème - elles durciraient."},
{id:"FR108",co:"France",cat:"Sauce / Base",sous:"Sauce",nom:"Sauce Périgueux à la Truffe",chef:"Tradition française classique",bp:4,prep:15,cui:20,diff:3,qual:4,ig:[["Fond de veau réduit",30,"cl"],["Truffe noire en lamelles",30,"g"],["Jus de truffe",2,"cs"],["Madère",5,"cl"],["Beurre très froid",60,"g"],["Échalotes",2,"pièces"]],et:"1. Suer les échalotes dans un peu de beurre. Déglacer au Madère. Réduire presque à sec.\n2. Ajouter fond de veau + jus de truffe. Réduire d'un tiers à feu moyen.\n3. Passer au chinois fin.\n4. Hors feu : monter au beurre froid en dés en fouettant.\n5. Ajouter les lamelles de truffe à la dernière minute. Ne jamais faire bouillir après.",vin:"Accompagnement foie gras, tournedos, ris de veau",notes:"Cette sauce représente le summum de la gastronomie française classique."},
{id:"FR109",co:"France",cat:"Plat",sous:"Cabillaud",nom:"Dos de Cabillaud à la Vierge",chef:"Tradition française",bp:4,prep:15,cui:12,diff:2,qual:4,ig:[["Dos de cabillaud",800,"g"],["Tomates cerises variées",300,"g"],["Basilic",1,"bouquet"],["Olives noires",50,"g"],["Câpres",2,"cs"],["Citron non traité",1,"pièce"],["Huile d'olive",10,"cs"],["Sel poivre",1,"qs"],["Fleur de sel",1,"qs"]],et:"1. Sauce vierge : couper tomates cerises en deux. Mélanger avec basilic + olives dénoyautées + câpres + zeste + jus de citron + huile d'olive. Assaisonner. Laisser macérer 30 min.\n2. Assaisonner les dos de cabillaud. Les saisir côté peau dans huile d'olive très chaude 4 min.\n3. Retourner. Cuire encore 3-4 min. La chair doit se détacher en feuillets.\n4. Servir les dos de cabillaud nappés de sauce vierge tiède. Fleur de sel.",vin:"Chablis ou Sancerre blanc",notes:"La sauce vierge est toujours tiède, jamais chaude. Elle macère à T° ambiante."},
{id:"FR110",co:"France",cat:"Dessert",sous:"Meringue",nom:"Vacherin Glacé Maison",chef:"Tradition française",bp:8,prep:60,cui:90,diff:4,qual:4,ig:[["Blancs d'œufs",4,"pièces"],["Sucre",200,"g"],["Sucre glace",100,"g"],["Crème fleurette 35%",50,"cl"],["Framboises fraîches",300,"g"],["Sucre glace pour coulis",40,"g"],["Sorbet framboise",400,"g"]],et:"Meringue :\n1. Monter blancs en neige. Ajouter sucre en 3 fois, serrer jusqu'à meringue ferme et brillante. Incorporer sucre glace.\n2. Dresser 2 disques de 22cm sur papier. Four 90°C 1h30. Refroidir dans le four éteint.\nMontage :\n3. Coulis : mixer framboises + sucre glace + citron. Passer au chinois.\n4. Monter crème en chantilly ferme.\n5. Alterner : disque de meringue + chantilly + sorbet framboise + disque de meringue + chantilly. Décorer de framboises. Congeler 4h.",vin:"Champagne demi-sec",notes:"Sortir le vacherin 10 min avant de servir pour que la meringue ramollisse légèrement."},
{id:"FR111",co:"France",cat:"Plat",sous:"Abats",nom:"Langue de Veau Sauce Gribiche",chef:"Tradition française",bp:6,prep:20,cui:120,diff:2,qual:4,ig:[["Langue de veau",1,"pièce"],["Oignons",2,"pièces"],["Carottes",2,"pièces"],["Bouquet garni",1,"pièce"],["Oeufs durs",4,"pièces"],["Moutarde forte",1,"cs"],["Huile de tournesol",15,"cl"],["Vinaigre de vin",2,"cs"],["Câpres",2,"cs"],["Cornichons",6,"pièces"],["Herbes fraîches mélangées",1,"bouquet"]],et:"1. Plonger la langue dans l'eau froide. Porter à ébullition. Égoutter, rincer.\n2. Remettre à l'eau froide avec légumes + bouquet garni + sel. Frémir à couvert 2h.\n3. Retirer la langue. Peler immédiatement à chaud (la peau s'enlève facilement).\n4. Sauce gribiche : écraser jaunes durs + moutarde. Monter à l'huile. Blancs hachés + cornichons + câpres + herbes + vinaigre.\n5. Trancher la langue tiède. Servir nappée de sauce gribiche.",vin:"Beaujolais Villages ou Côtes du Rhône rouge léger",notes:"Peler la langue doit se faire immédiatement après cuisson, avant qu'elle refroidisse."},
{id:"FR112",co:"France",cat:"Plat",sous:"Veau",nom:"Osso Buco à la Parisienne",chef:"Tradition franco-italienne",bp:4,prep:20,cui:90,diff:2,qual:4,ig:[["Jarrets de veau épais",4,"pièces"],["Oignons",2,"pièces"],["Carottes",2,"pièces"],["Tomates concassées",300,"g"],["Vin blanc sec",20,"cl"],["Fond de veau",30,"cl"],["Zeste de citron",1,"pièce"],["Persil haché",2,"cs"],["Ail",2,"gousses"]],et:"1. Inciser la peau du pourtour des jarrets. Fariner, assaisonner. Dorer sur toutes les faces.\n2. Retirer. Suer légumes en brunoise dans la même cocotte.\n3. Déglacer vin blanc, réduire. Ajouter tomates + fond de veau. Remettre les jarrets.\n4. Couvrir papier + couvercle. Four 160°C 2h.\n5. Gremolata : mélanger persil + ail + zeste de citron. Parsemer à la sortie du four.",vin:"Bourgogne blanc ou Mâcon-Villages",notes:"La version française de l'osso buco milanais - sans risotto mais avec la même gremolata."},
{id:"FR113",co:"France",cat:"Dessert",sous:"Nougat",nom:"Calisson d'Aix-en-Provence",chef:"Tradition provençale",bp:20,prep:60,cui:10,diff:3,qual:4,ig:[["Poudre d'amandes",250,"g"],["Melon confit",100,"g"],["Écorces d'orange confites",50,"g"],["Sucre glace",150,"g"],["Eau de fleur d'oranger",2,"cs"],["Papier de riz (hosties)",1,"feuille"],["Fondant blanc",200,"g"],["Colorant alimentaire jaune",1,"qs"]],et:"1. Mixer melon confit + écorces d'orange confites jusqu'à pâte lisse.\n2. Mélanger avec poudre d'amandes + sucre glace + eau de fleur d'oranger.\n3. Travailler jusqu'à pâte homogène et souple.\n4. Étaler sur le papier de riz à 1cm d'épaisseur. Laisser sécher 12h.\n5. Napper de fondant blanc légèrement teinté de jaune. Découper en forme de losange (amande) caractéristique.",vin:"Muscat de Beaumes-de-Venise ou Champagne",notes:"La forme en amande évoque les calèches des cortèges royaux provençaux du XVe siècle."},
{id:"FR114",co:"France",cat:"Plat",sous:"Terrine",nom:"Galantine de Canard en Gelée",chef:"Tradition française",bp:10,prep:60,cui:90,diff:4,qual:4,ig:[["Canard entier désossé",1,"pièce"],["Foie gras cru",150,"g"],["Veau haché",300,"g"],["Cognac",5,"cl"],["Pistaches",50,"g"],["Gelée de fond de volaille",50,"cl"],["Échalotes",3,"pièces"],["Sel poivre muscade",1,"qs"],["Truffe noire (optionnel)",20,"g"]],et:"1. Désosser entièrement le canard. Réserver les filets pour la présentation.\n2. Farce : hacher la chair du canard + veau + échalotes + foie gras en dés + cognac + pistaches + assaisonnement.\n3. Étaler le canard à plat. Garnir de farce. Rouler en boudin serré, ficeler.\n4. Pocher dans bouillon 1h30 à 80°C. Refroidir dans le bouillon.\n5. Clarifier le bouillon en gelée. Napper la galantine refroidie de gelée. Réfrigérer 12h.",vin:"Champagne Rosé ou Meursault",notes:"La galantine est le summum de la charcuterie fine française. Elle demande technique et patience."},
{id:"FR115",co:"France",cat:"Dessert",sous:"Bugne",nom:"Bugnes Lyonnaises",chef:"Tradition lyonnaise de Mardi Gras",bp:8,prep:30,cui:15,diff:2,qual:4,ig:[["Farine T45",400,"g"],["Oeufs",4,"pièces"],["Beurre pommade",60,"g"],["Sucre",50,"g"],["Rhum",2,"cs"],["Fleur d'oranger",1,"cs"],["Levure chimique",1,"cc"],["Sel",1,"pincée"],["Huile d'arachide",1,"L"],["Sucre glace",60,"g"]],et:"1. Mélanger farine + sucre + sel + levure. Creuser un puits.\n2. Incorporer oeufs + beurre mou + rhum + fleur d'oranger. Pétrir jusqu'à pâte lisse.\n3. Réfrigérer 1h.\n4. Étaler très finement (2mm). Découper en losanges ou bandes torsadées.\n5. Frire à 175°C 2-3 min jusqu'à dorées et gonflées. Égoutter sur papier absorbant. Sucre glace abondant.",vin:"Beaujolais nouveau ou chocolat chaud",notes:"Les bugnes se font traditionnellement pour le Mardi Gras. Plus elles sont fines, meilleures elles sont."},
{id:"FR116",co:"France",cat:"Plat",sous:"Porc",nom:"Rôti de Porc aux Pruneaux",chef:"Tradition ligérienne",bp:6,prep:20,cui:80,diff:2,qual:4,ig:[["Rôti de porc dans l'échine",1200,"g"],["Pruneaux d'Agen",200,"g"],["Thé noir",20,"cl"],["Oignons",2,"pièces"],["Beurre",30,"g"],["Crème fraîche",15,"cl"],["Fond de veau",15,"cl"],["Sel poivre",1,"qs"]],et:"1. Réhydrater les pruneaux dans le thé tiède 30 min.\n2. Farcir le rôti en incisant profondément et en glissant des pruneaux dedans. Ficeler si nécessaire.\n3. Dorer le rôti sur toutes les faces dans le beurre.\n4. Ajouter oignons + reste de pruneaux + fond de veau. Couvrir.\n5. Cuire à 170°C 1h20. Retirer le rôti. Crème fraîche dans le jus. Servir tranché avec la sauce.",vin:"Vouvray demi-sec ou Anjou blanc",notes:"Les pruneaux d'Agen caramélisent légèrement et parfument délicatement la sauce."},
{id:"FR117",co:"France",cat:"Entrée",sous:"Asperges",nom:"Asperges Blanches Sauce Mousseline",chef:"Tradition alsacienne et champenoise",bp:4,prep:15,cui:20,diff:2,qual:4,ig:[["Asperges blanches",1200,"g"],["Jaunes d'oeufs",3,"pièces"],["Beurre clarifié",150,"g"],["Citron",1,"pièce"],["Crème fouettée",5,"cs"],["Sel poivre blanc",1,"qs"]],et:"1. Peler les asperges, couper les pieds. Cuire à la vapeur ou à l'eau bouillante salée 15-18 min selon l'épaisseur.\n2. Sauce hollandaise : fouetter jaunes + 2cs d'eau au bain-marie jusqu'à ruban épais. Incorporer beurre clarifié en filet en fouettant.\n3. Assaisonner + jus de citron.\n4. Hors feu, incorporer délicatement la crème fouettée (mousseline).\n5. Servir asperges tièdes nappées de sauce mousseline.",vin:"Gewurztraminer d'Alsace ou Champagne",notes:"La sauce mousseline est une hollandaise allégée à la crème fouettée."},
{id:"FR118",co:"France",cat:"Plat",sous:"Légumes",nom:"Petits Farcis Niçois",chef:"Tradition niçoise",bp:4,prep:40,cui:50,diff:2,qual:4,ig:[["Courgettes rondes",4,"pièces"],["Tomates rondes",4,"pièces"],["Oignons ronds",4,"pièces"],["Poivrons verts ronds",2,"pièces"],["Porc et veau hachés mélangés",300,"g"],["Riz cuit",100,"g"],["Parmesan râpé",60,"g"],["Oeufs",2,"pièces"],["Ail basilic",1,"qs"],["Huile d'olive",4,"cs"]],et:"1. Évider chapeaux de tous les légumes. Hacher la chair récupérée.\n2. Mélanger viande + riz cuit + chair hachée + parmesan + oeufs + ail haché + basilic. Assaisonner.\n3. Garnir les légumes de farce aux 3/4.\n4. Remettre les chapeaux. Arroser d'huile d'olive.\n5. Four 180°C 45-50 min jusqu'à légumes tendres et surface dorée.",vin:"Bandol rosé ou Côtes de Provence rosé",notes:"Les petits farcis se mangent aussi à T° ambiante le lendemain."},
{id:"FR119",co:"France",cat:"Dessert",sous:"Brioche",nom:"Brioche Vendômoise",chef:"Tradition du Val-de-Loire",bp:8,prep:30,cui:30,diff:3,qual:4,ig:[["Farine T45",500,"g"],["Oeufs",5,"pièces"],["Beurre pommade",250,"g"],["Sucre",60,"g"],["Levure fraîche",20,"g"],["Lait tiède",5,"cl"],["Sel",8,"g"]],et:"1. Diluer levure dans lait tiède. Mélanger farine + sel + sucre + oeufs + levure. Pétrir 15 min.\n2. Incorporer beurre progressivement en petites quantités en pétrissant jusqu'à pâte lisse et élastique.\n3. Lever 2h à T° ambiante, puis 1h au froid.\n4. Former une grosse boule ou des brioches individuelles dans des moules. Dorer à l'oeuf.\n5. Laisser pousser 1h. Four 180°C 25-30 min.",vin:"Crémant de Loire ou café du matin",notes:"La brioche est meilleure encore chaude. Le pétrissage long développe le gluten et la légèreté."},
{id:"FR120",co:"France",cat:"Plat",sous:"Poulet",nom:"Poulet Basquaise",chef:"Tradition basque",bp:6,prep:20,cui:50,diff:2,qual:4,ig:[["Poulet fermier découpé",1800,"g"],["Poivrons rouges verts",4,"pièces"],["Tomates mûres",4,"pièces"],["Oignons",2,"pièces"],["Ail",4,"gousses"],["Jambon de Bayonne en dés",80,"g"],["Piment d'Espelette",1,"cc"],["Vin blanc",15,"cl"],["Huile d'olive",4,"cs"]],et:"1. Dorer les morceaux de poulet. Réserver.\n2. Suer oignons + jambon + ail. Ajouter poivrons en lanières. Cuire 10 min.\n3. Ajouter tomates concassées + vin blanc + piment d'Espelette.\n4. Remettre le poulet. Couvrir, cuire à feu doux 35 min.\n5. Rectifier assaisonnement. Parsemer de persil et basilic.",vin:"Irouléguy rouge ou rosé ou Rioja",notes:"Le piment d'Espelette AOP est doux et parfumé. Ne pas le remplacer par du piment ordinaire."},
{id:"FR121",co:"France",cat:"Entrée",sous:"Gelée",nom:"Oeuf en Gelée à l'Estragon",chef:"Tradition charcutière française",bp:4,prep:30,cui:10,diff:3,qual:4,ig:[["Oeufs très frais",4,"pièces"],["Bouillon de volaille clarifié",50,"cl"],["Gélatine",5,"feuilles"],["Estragon frais",1,"bouquet"],["Jambon cuit",4,"tranches"],["Vinaigrette",2,"cs"]],et:"1. Pocher les oeufs dans eau vinaigrée 3 min. Réserver dans eau froide.\n2. Chauffer le bouillon. Dissoudre la gélatine essorée. Tiédir.\n3. Tapisser 4 ramequins d'une couche de gelée. Réfrigérer jusqu'à prise.\n4. Disposer quelques feuilles d'estragon + lamelle de jambon. Poser l'oeuf poché.\n5. Verser la gelée restante pour couvrir. Réfrigérer 3h minimum. Démouler.",vin:"Chablis ou Sancerre blanc",notes:"La gelée doit être légèrement tremblotante, jamais caoutchouteuse. Réfrigérer au moins 3h."},
{id:"FR122",co:"France",cat:"Plat",sous:"Boeuf",nom:"Boeuf Mironton",chef:"Tradition française de ménage",bp:4,prep:15,cui:30,diff:1,qual:4,ig:[["Restes de boeuf bouilli en tranches",600,"g"],["Oignons",4,"pièces"],["Bouillon de boeuf",30,"cl"],["Vinaigre de vin",2,"cs"],["Moutarde forte",1,"cs"],["Beurre",40,"g"],["Chapelure",3,"cs"],["Persil",0.5,"bouquet"],["Sel poivre",1,"qs"]],et:"1. Faire fondre les oignons émincés dans le beurre à feu doux 20 min jusqu'à très tendres et légèrement dorés.\n2. Déglacer vinaigre + bouillon. Frémir 5 min.\n3. Ajouter moutarde. Assaisonner.\n4. Dans plat beurré : couche d'oignons + tranches de boeuf + oignons. Saupoudrer de chapelure.\n5. Gratiner au four 200°C 15 min jusqu'à doré.",vin:"Beaujolais rouge ou vin de table",notes:"Recette traditionnelle pour accommoder les restes du pot-au-feu."},
{id:"FR123",co:"France",cat:"Dessert",sous:"Crème",nom:"Crème Brûlée à la Vanille de Tahiti",chef:"Tradition française",bp:6,prep:15,cui:35,diff:2,qual:4,ig:[["Crème fraîche liquide 35%",50,"cl"],["Jaunes d'oeufs",6,"pièces"],["Sucre",100,"g"],["Vanille de Tahiti",1,"gousse"],["Cassonade pour brûler",60,"g"]],et:"1. Infuser la vanille fendue dans la crème chaude 20 min. Filtrer.\n2. Fouetter jaunes + sucre jusqu'à blanchiment léger (pas de ruban).\n3. Verser la crème tiède sur les jaunes en mélangeant sans fouetter (pour éviter les bulles).\n4. Verser dans 6 ramequins. Bain-marie au four 150°C 30-35 min. Le centre doit trembler.\n5. Réfrigérer 4h. Saupoudrer cassonade, brûler au chalumeau.",vin:"Sauternes ou Champagne demi-sec",notes:"La vanille de Tahiti est plus florale et fruitée que la vanille de Madagascar."},
{id:"FR124",co:"France",cat:"Plat",sous:"Chasse",nom:"Terrine de Gibier",chef:"Tradition chasseresse française",bp:12,prep:40,cui:90,diff:2,qual:4,ig:[["Chair de lièvre ou chevreuil",400,"g"],["Foie de porc",200,"g"],["Gorge de porc",400,"g"],["Cognac",5,"cl"],["Baies de genévrier",8,"baies"],["Thym laurier",1,"qs"],["Oeufs",2,"pièces"],["Échalotes",3,"pièces"],["Sel poivre muscade",1,"qs"],["Barde lard",4,"tranches"]],et:"1. Hacher grossièrement toutes les viandes. Mélanger avec cognac + oeufs + échalotes + épices. Mariner 12h au froid.\n2. Chemiser la terrine de bardes de lard.\n3. Remplir de farce en tassant bien. Couvrir de bardes. Feuille de laurier.\n4. Bain-marie au four 165°C 1h30.\n5. Mettre sous presse pendant le refroidissement. Réfrigérer 48h avant de trancher.",vin:"Côtes du Rhône rouge ou Bandol rouge",notes:"La terrine doit reposer 48h pour développer ses arômes."},
{id:"FR125",co:"France",cat:"Plat",sous:"Légumes",nom:"Tarte à l'Oignon Alsacienne (Zwiebelkuche)",chef:"Tradition alsacienne",bp:6,prep:30,cui:50,diff:2,qual:4,ig:[["Oignons",1000,"g"],["Pâte brisée",1,"pièce"],["Lardons fumés",100,"g"],["Oeufs",3,"pièces"],["Crème fraîche",20,"cl"],["Beurre",40,"g"],["Cumin",1,"cc"],["Sel poivre",1,"qs"]],et:"1. Foncer moule 28cm de pâte brisée. Cuire à blanc 12 min.\n2. Émincer finement les oignons. Fondre dans le beurre avec les lardons à feu doux 30 min jusqu'à très tendres et légèrement dorés.\n3. Battre oeufs + crème + cumin + sel + poivre.\n4. Mélanger oignons + lardons avec l'appareil.\n5. Verser sur le fond. Four 180°C 30-35 min.",vin:"Pinot Gris d'Alsace ou Riesling demi-sec",notes:"Le cumin est la signature alsacienne de cette tarte. Indispensable."},
{id:"FR126",co:"France",cat:"Plat",sous:"Escargots",nom:"Escargots de Bourgogne",chef:"Tradition bourguignonne",bp:4,prep:20,cui:12,diff:1,qual:4,ig:[["Escargots en conserve",48,"pièces"],["Beurre pommade",150,"g"],["Ail",4,"gousses"],["Persil plat",1,"bouquet"],["Échalotes",2,"pièces"],["Sel poivre",1,"qs"]],et:"1. Beurre d'escargot : mixer beurre pommade + ail + persil + échalotes + sel + poivre jusqu'à pâte verte homogène.\n2. Égoutter et sécher les escargots.\n3. Placer un escargot dans chaque alvéole. Recouvrir de beurre aux herbes.\n4. Réfrigérer 30 min pour que le beurre se solidifie.\n5. Four très chaud 220°C 8-10 min. Servir en grésillant avec baguette.",vin:"Bourgogne blanc ou Chablis",notes:"Le beurre doit grésiller et être bien vert. Les escargots servent surtout de vecteur pour ce beurre exceptionnel."},
{id:"FR127",co:"France",cat:"Dessert",sous:"Macaron",nom:"Macarons à la Framboise",chef:"Tradition pâtissière française",bp:20,prep:60,cui:15,diff:4,qual:4,ig:[["Poudre d'amandes tamisée",150,"g"],["Sucre glace tamisé",150,"g"],["Blancs d'oeufs vieillis",55,"g"],["Sucre",150,"g"],["Eau",50,"g"],["Colorant rose",1,"qs"],["Coulis framboise pour ganache",100,"g"],["Chocolat blanc",150,"g"],["Crème fraîche",5,"cl"]],et:"Coques :\n1. Macaronnage : tamiser poudre d'amandes + sucre glace. Incorporer les blancs.\n2. Meringue italienne : cuire sucre + eau à 121°C. Monter blancs en neige + sirop chaud. Refroidir. Incorporer + colorant.\n3. Macaronner jusqu'à pâte qui retombe en ruban. Pocher des disques de 3.5cm. Croûter 30 min.\n4. Four 150°C 12-14 min. Refroidir AVANT de décoller.\nGanache :\n5. Chauffer crème + coulis. Verser sur chocolat blanc haché. Émulsionner. Garnir les coques.",vin:"Champagne Rosé ou thé Darjeeling",notes:"Le croûtage (repos avant enfournement) est essentiel pour que la collerette se forme."},
{id:"FR128",co:"France",cat:"Plat",sous:"Grenouilles",nom:"Grenouilles Bifidum à la Bressane",chef:"Tradition bressane",bp:4,prep:20,cui:10,diff:2,qual:4,ig:[["Cuisses de grenouilles",32,"pièces"],["Farine",50,"g"],["Beurre",80,"g"],["Ail",4,"gousses"],["Persil plat haché",1,"bouquet"],["Jus de citron",1,"cs"],["Sel poivre",1,"qs"]],et:"1. Sécher soigneusement les cuisses. Fariner légèrement.\n2. Fondre beurre à feu vif. Saisir les cuisses par petites quantités 2-3 min/face jusqu'à dorées croustillantes.\n3. Saler, poivrer.\n4. Beurre noisette dans la poêle vide. Ajouter ail haché très finement. Blondir sans brûler.\n5. Jus de citron hors feu. Verser sur les grenouilles. Persil ciselé généreusement.",vin:"Pouilly-Fuissé ou Chablis 1er Cru",notes:"Les cuisses doivent être bien séchées pour un résultat croustillant. On les déguste avec les doigts."},
{id:"FR129",co:"France",cat:"Dessert",sous:"Gaufre",nom:"Gaufres Liégeoises au Sucre Perlé",chef:"Tradition liégeoise et belge",bp:8,prep:30,cui:20,diff:2,qual:4,ig:[["Farine T45",500,"g"],["Levure fraîche",20,"g"],["Lait tiède",15,"cl"],["Beurre pommade",200,"g"],["Oeufs",2,"pièces"],["Sucre perlé belge",100,"g"],["Sel",1,"pincée"],["Vanille",1,"cc"]],et:"1. Levure + lait tiède + sucre. Mélanger avec farine + sel + oeufs + beurre mou + vanille. Pétrir 8 min. Lever 1h30.\n2. Incorporer délicatement le sucre perlé à la main sans trop travailler.\n3. Diviser en 8 boules. Lever encore 30 min.\n4. Cuire au gaufrier beurré et préchauffé 4-5 min. Le sucre perlé caramélise pendant la cuisson.\n5. Servir tièdes : l'intérieur reste moelleux, l'extérieur est caramélisé.",vin:"Café belge ou chocolat chaud",notes:"Les gaufres liégeoises sont radicalement différentes des bruxelloises : compactes, sucrées, caramélisées. Le sucre perlé doit être belge."},
{id:"FR130",co:"France",cat:"Plat",sous:"Fromage fondu",nom:"Fondue Savoyarde",chef:"Tradition savoyarde et suisse",bp:4,prep:15,cui:15,diff:1,qual:4,ig:[["Gruyère de Savoie râpé",300,"g"],["Comté râpé",200,"g"],["Beaufort râpé",200,"g"],["Vin blanc de Savoie",30,"cl"],["Ail",1,"gousse"],["Maïzena",1,"cs"],["Kirsch",3,"cs"],["Pain de campagne en cubes",1,"pièce"],["Muscade poivre blanc",1,"qs"]],et:"1. Frotter le caquelon de fondue avec l'ail coupé en deux.\n2. Verser le vin blanc. Chauffer doucement jusqu'à frémissement.\n3. Incorporer les fromages râpés mélangés progressivement en remuant en 8.\n4. Délayer la maïzena dans le kirsch. Incorporer dans la fondue. Cuire encore 2 min.\n5. Muscade + poivre blanc. Maintenir à feu doux avec le réchaud. Tremper les cubes de pain.",vin:"Apremont ou Roussette de Savoie blanc",notes:"Si la fondue tranche (huile et fromage séparés) : ajouter quelques gouttes de citron et fouetter vigoureusement."},
{id:"FR131",co:"France",cat:"Plat",sous:"Boeuf",nom:"Steak Tartare",chef:"Tradition des brasseries parisiennes",bp:4,prep:20,cui:0,diff:2,qual:4,ig:[["Boeuf (filet ou rumsteck) très frais",600,"g"],["Jaunes d'oeufs",4,"pièces"],["Moutarde de Dijon",2,"cs"],["Worcestershire",1,"cs"],["Tabasco",4,"gouttes"],["Câpres",3,"cs"],["Échalotes",2,"pièces"],["Cornichons",4,"pièces"],["Persil haché",2,"cs"],["Sel poivre",1,"qs"]],et:"1. Couper le boeuf au couteau en petits dés de 3mm (ne jamais hacher).\n2. Dans un bol : mélanger à la fourchette jaune d'oeuf + moutarde + worcestershire + tabasco + sel + poivre.\n3. Incorporer les dés de boeuf. Mélanger délicatement.\n4. Ajouter câpres + échalotes hachées très finement + cornichons en brunoise + persil.\n5. Servir immédiatement sur assiette froide avec frites et salade. Décorer d'un jaune d'oeuf cru.",vin:"Côtes du Rhône rouge ou Bordeaux léger",notes:"La viande doit être hachée au couteau, jamais au hachoir. Un bon steak tartare se prépare minute."},
{id:"FR132",co:"France",cat:"Entrée",sous:"Champignons",nom:"Champignons Farcis à la Duxelles",chef:"Tradition française",bp:4,prep:20,cui:20,diff:2,qual:4,ig:[["Gros champignons de Paris",16,"pièces"],["Champignons hachés très fin",300,"g"],["Échalotes",3,"pièces"],["Ail",2,"gousses"],["Beurre",60,"g"],["Crème fraîche",4,"cs"],["Persil haché",2,"cs"],["Parmesan râpé",60,"g"],["Sel poivre",1,"qs"]],et:"1. Retirer les pieds des champignons. Hacher les pieds + 300g champignons supplémentaires très finement.\n2. Duxelles : suer échalotes + ail dans beurre. Ajouter champignons hachés, cuire à feu vif jusqu'à toute l'eau évaporée (duxelles sèche).\n3. Incorporer crème + persil. Assaisonner.\n4. Garnir les têtes des champignons de duxelles. Parsemer de parmesan.\n5. Four 200°C 15-18 min jusqu'à dorés.",vin:"Bourgogne blanc ou Côtes du Jura",notes:"La duxelles doit être absolument sèche. Toute l'eau des champignons doit s'évaporer pour concentrer les saveurs."},
{id:"FR133",co:"France",cat:"Plat",sous:"Veau",nom:"Grenadin de Veau Poêlé aux Morilles",chef:"Tradition française",bp:4,prep:20,cui:20,diff:3,qual:4,ig:[["Grenadins de veau (tranches épaisses de filet)",4,"pièces"],["Morilles séchées",30,"g"],["Crème fraîche",25,"cl"],["Vin jaune du Jura",8,"cl"],["Échalotes",3,"pièces"],["Beurre",60,"g"],["Fond de veau",15,"cl"],["Sel poivre",1,"qs"]],et:"1. Réhydrater morilles 20 min. Filtrer l'eau précieuse.\n2. Saisir les grenadins dans beurre mousseux 3-4 min/face. Réserver au chaud.\n3. Suer échalotes dans la même poêle. Déglacer au vin jaune.\n4. Ajouter morilles + eau de réhydratation filtrée + fond de veau. Réduire.\n5. Crème fraîche. Réduire à consistance nappante. Remettre les grenadins 2 min.",vin:"Vin jaune du Jura (Château-Chalon idéalement)",notes:"Le vin jaune et les morilles sont le mariage le plus noble de la cuisine comtoise. L'eau de réhydratation des morilles est un trésor de saveur."},
{id:"FR134",co:"France",cat:"Entrée",sous:"Salade composée",nom:"Salade Périgourdine",chef:"Tradition périgourdine",bp:4,prep:20,cui:10,diff:1,qual:4,ig:[["Gésiers de canard confits",200,"g"],["Magret de canard fumé tranché",100,"g"],["Foie gras de canard mi-cuit",80,"g"],["Salade verte (mâche ou frisée)",200,"g"],["Noix de Grenoble",60,"g"],["Pains de campagne grillés",4,"tranches"],["Huile de noix",4,"cs"],["Vinaigre de framboise",2,"cs"],["Sel poivre",1,"qs"]],et:"1. Réchauffer les gésiers confits dans une poêle antiadhésive jusqu'à dorés et croustillants.\n2. Vinaigrette à la noix : émulsionner huile de noix + vinaigre de framboise + sel + poivre.\n3. Assaisonner la salade avec la vinaigrette.\n4. Griller les tranches de pain de campagne.\n5. Dresser : salade + gésiers chauds + tranches de magret fumé + noix + toast. Poser une tranche de foie gras mi-cuit sur le toast.",vin:"Bergerac rouge ou Pécharmant",notes:"La salade périgourdine est l'entrée emblématique du Périgord. Le contraste chaud-froid (gésiers chauds, foie gras froid) est sa signature."},
{id:"FR135",co:"France",cat:"Plat",sous:"Saumon",nom:"Coulibiac de Saumon",chef:"Tradition franco-russe",bp:8,prep:60,cui:40,diff:4,qual:4,ig:[["Pâte feuilletée",800,"g"],["Filet de saumon frais",800,"g"],["Riz cuit",150,"g"],["Oeufs durs",4,"pièces"],["Champignons duxelles",200,"g"],["Aneth frais",1,"bouquet"],["Échalotes",3,"pièces"],["Beurre",60,"g"],["Jaune d'oeuf pour dorure",2,"pièces"],["Sel poivre",1,"qs"]],et:"1. Préparer la duxelles : champignons hachés + échalotes + beurre, cuire jusqu'à sèche.\n2. Étaler la moitié de la pâte en rectangle. Couche de riz + aneth + saumon assaisonné + duxelles + oeufs durs tranchés.\n3. Couvrir de l'autre moitié de pâte. Souder les bords en les pinçant.\n4. Dorer à l'oeuf. Dessiner un décor. Faire une cheminée.\n5. Four 200°C 35-40 min. Reposer 10 min avant de couper.",vin:"Meursault ou Puligny-Montrachet",notes:"Le coulibiac est un plat de grande table franco-russe popularisé par Auguste Escoffier. Le repos est indispensable avant la découpe."},
{id:"FR136",co:"France",cat:"Dessert",sous:"Tarte",nom:"Tarte Tatin Solognote aux Pommes",chef:"Tradition solognote — Sœurs Tatin",bp:8,prep:20,cui:35,diff:2,qual:5,ig:[["Pommes Golden ou Reinette",1400,"g"],["Sucre",150,"g"],["Beurre demi-sel",80,"g"],["Pâte feuilletée pur beurre",250,"g"]],et:"1. Four 200°C. Dans une poêle à manche amovible (ou poêle allant au four de 26cm) : fondre beurre + sucre à feu moyen jusqu'à caramel beurré homogène.\n2. Éplucher les pommes, les couper en 4. Les disposer debout très serrées dans le caramel.\n3. Cuire à feu moyen 15-20 min — les pommes doivent compoter et le caramel brunir.\n4. Couvrir avec le disque de pâte feuilletée en rentrant les bords sous les pommes.\n5. Four 200°C 20-25 min. Démouler CHAUD en retournant d'un coup sur le plat.",vin:"Calvados ou Bonnezeaux",notes:"Le démoulage est le moment critique. Il faut le faire chaud (jamais froid). Attendre 2 min puis retourner."},
{id:"FR137",co:"France",cat:"Dessert",sous:"Entremets",nom:"Crème Caramel",chef:"Tradition française",bp:6,prep:15,cui:40,diff:1,qual:4,ig:[["Oeufs entiers",4,"pièces"],["Jaunes d'oeufs",2,"pièces"],["Lait entier",50,"cl"],["Sucre",100,"g"],["Vanille",1,"gousse"],["Sucre pour caramel",120,"g"]],et:"1. Caramel : cuire 120g sucre à sec dans une casserole sans remuer jusqu'à ambré foncé. Verser dans 6 ramequins.\n2. Infuser vanille dans lait chaud 15 min.\n3. Fouetter oeufs + jaunes + sucre sans faire mousser. Ajouter lait vanillé tiède en fouettant.\n4. Filtrer. Verser sur le caramel durci.\n5. Bain-marie au four 160°C 35-40 min. Le centre doit trembler. Réfrigérer 6h. Démouler sur assiette creuse.",vin:"Sauternes ou Pinot Gris vendanges tardives",notes:"La crème est cuite dès qu'elle tremble légèrement mais reste homogène. Surcuite, elle sera granuleuse."},
{id:"FR138",co:"France",cat:"Dessert",sous:"Gâteau",nom:"Quatre-Quarts Breton",chef:"Tradition bretonne",bp:8,prep:15,cui:50,diff:1,qual:4,ig:[["Oeufs",4,"pièces"],["Beurre demi-sel fondu",250,"g"],["Sucre",250,"g"],["Farine T45",250,"g"],["Levure chimique",1,"cc"]],et:"1. Peser les oeufs avec leur coquille — cette pesée détermine toutes les autres proportions.\n2. Four 170°C. Fouetter oeufs + sucre jusqu'à blanchiment et doublement du volume.\n3. Incorporer la farine + levure tamisées délicatement.\n4. Incorporer le beurre demi-sel fondu tiède. Mélanger.\n5. Moule à cake beurré. Four 170°C 45-50 min. Vérifier avec une pique. Refroidir 20 min avant de démouler.",vin:"Cidre breton demi-sec ou café",notes:"Le quatre-quarts traditionnel est : 1 part oeufs = 1 part beurre = 1 part sucre = 1 part farine. Le beurre demi-sel breton est indispensable."},
{id:"FR139",co:"France",cat:"Dessert",sous:"Biscuit",nom:"Sablés Normands au Beurre",chef:"Tradition normande",bp:20,prep:20,cui:12,diff:1,qual:4,ig:[["Farine T55",250,"g"],["Beurre demi-sel pommade",175,"g"],["Sucre",80,"g"],["Jaune d'oeuf",1,"pièce"],["Extrait de vanille",1,"cc"]],et:"1. Fouetter beurre pommade + sucre jusqu'à crémeux. Ajouter jaune + vanille.\n2. Incorporer la farine sans trop travailler. La pâte est meuble.\n3. Former une boule, aplatir légèrement. Réfrigérer 30 min minimum (1h idéal).\n4. Étaler à 6mm. Découper avec emporte-pièce. Disposer sur plaque.\n5. Four 170°C 10-12 min. Les bords doivent être légèrement dorés, le dessus reste pâle.",vin:"Cidre ou thé à la bergamote",notes:"Le sablé parfait ne doit pas être trop cuit. Le centre reste fondant et crumble légèrement."},
{id:"FR140",co:"France",cat:"Dessert",sous:"Entremet",nom:"Limoncello Meringuée",chef:"Tradition française",bp:8,prep:45,cui:25,diff:3,qual:5,ig:[["Farine T55",200,"g"],["Beurre pommade",100,"g"],["Sucre glace",60,"g"],["Oeuf pour pâte",1,"pièce"],["Oeufs pour crème",4,"pièces"],["Sucre",150,"g"],["Jus de citrons frais",12,"cl"],["Zeste de 3 citrons non traités",1,"qs"],["Beurre pour crème",100,"g"],["Blancs d'oeufs pour meringue",3,"pièces"],["Sucre pour meringue",180,"g"]],et:"Pâte sablée :\n1. Sabler farine + beurre + sucre glace. Ajouter oeuf. Réfrigérer 1h. Foncer moule 26cm. Cuire à blanc 20 min à 170°C.\nCrème citron :\n2. Fouetter oeufs + sucre + jus + zestes. Cuire au bain-marie jusqu'à 83°C en fouettant. Hors feu, incorporer beurre froid en dés. Verser sur fond.\nMeringue italienne :\n3. Cuire sucre + eau à 121°C. Monter blancs, verser le sirop en filet. Fouetter jusqu'à refroidissement.\n4. Pocher la meringue sur la crème. Bruler au chalumeau.",vin:"Champagne Blanc de Blancs ou Picpoul de Pinet",notes:"La crème citron doit être cuite à 83°C précisément pour rester onctueuse. Trop cuite, elle se sépare."},
{id:"FR141",co:"France",cat:"Dessert",sous:"Gâteau chocolat",nom:"Fondant au Chocolat",chef:"Tradition française",bp:6,prep:15,cui:12,diff:1,qual:5,ig:[["Chocolat noir 70%",200,"g"],["Beurre",150,"g"],["Oeufs",4,"pièces"],["Sucre",100,"g"],["Farine T45",50,"g"],["Sel",1,"pincée"]],et:"1. Fondre chocolat + beurre au bain-marie. Tiédir.\n2. Fouetter oeufs + sucre jusqu'à légèrement mousseux.\n3. Incorporer le chocolat fondu. Mélanger.\n4. Ajouter farine + sel. Mélanger jusqu'à homogène.\n5. Moule beurré 20cm ou 6 ramequins beurrés. Four préchauffé 200°C 10-12 min pour un grand moule (8 min pour ramequins). Le centre DOIT rester coulant.",vin:"Porto vintage ou Maury Grenat",notes:"Le fondant coule quand on le pique avec une baguette. Si la baguette ressort propre : surcuit. Servir immédiatement."},
{id:"FR142",co:"France",cat:"Plat",sous:"Viande",nom:"Côte de Boeuf Rôtie au Four",chef:"Tradition française",bp:4,prep:15,cui:30,diff:2,qual:5,ig:[["Côte de boeuf maturée",1400,"g"],["Beurre",40,"g"],["Ail",4,"gousses"],["Thym romarin",4,"branches"],["Sel de Guérande poivre",1,"qs"],["Huile d'arachide",2,"cs"]],et:"1. Sortir la côte 1h avant. Assaisonner généreusement des deux côtés.\n2. Saisir à feu très vif dans huile d'arachide 2-3 min/face jusqu'à croûte bien formée.\n3. Ajouter beurre + ail + herbes. Arroser en penchant la poêle. 1 min.\n4. Transférer en four à 200°C 12-15 min pour saignant (T° interne 52°C).\n5. IMPÉRATIF : repos sous alu 10 min avant de découper perpendiculairement à l'os.",vin:"Pomerol ou Saint-Estèphe ou Côte-Rôtie",notes:"La côte de boeuf se mange saignante. Bien cuite, c'est gâché. La maturation minimum est 4 semaines."},
{id:"FR143",co:"France",cat:"Plat",sous:"Volaille",nom:"Coq au Vin Classique",chef:"Tradition bourguignonne",bp:6,prep:30,cui:90,diff:2,qual:5,ig:[["Coq ou poulet fermier découpé",2000,"g"],["Pinot Noir de Bourgogne",75,"cl"],["Lardons fumés",150,"g"],["Oignons grelots",200,"g"],["Champignons de Paris",300,"g"],["Carottes",2,"pièces"],["Ail",4,"gousses"],["Bouquet garni",1,"pièce"],["Farine",30,"g"],["Cognac",5,"cl"],["Beurre",60,"g"]],et:"1. MARINADE (optionnelle mais recommandée) : coq + vin + légumes + herbes 12h au froid.\n2. Dorer les morceaux de volaille dans beurre sur toutes les faces. Réserver. Dorer lardons + oignons grelots.\n3. Flambér au cognac. Saupoudrer farine, cuire 2 min.\n4. Verser le vin (de marinade ou frais). Ajouter ail + bouquet garni. Porter à frémissement.\n5. Couvrir. Cuire à feu doux 1h pour poulet, 2h pour vrai coq. Ajouter champignons 15 min avant. Monter la sauce au beurre froid hors feu.",vin:"Gevrey-Chambertin ou Mercurey rouge",notes:"Pour un vrai coq au vin, il faut un vrai coq (2-3 ans) et un vrai Bourgogne. La liane temps/alcool transforme la viande."},
{id:"FR144",co:"France",cat:"Plat",sous:"Poisson",nom:"Sole Meunière",chef:"Tradition des grandes brasseries parisiennes",bp:2,prep:10,cui:10,diff:2,qual:5,ig:[["Soles entières vidées et habillées",2,"pièces"],["Farine",50,"g"],["Beurre clarifié",60,"g"],["Beurre frais",80,"g"],["Citron",2,"pièces"],["Persil plat ciselé",2,"cs"],["Sel poivre",1,"qs"]],et:"1. Sécher soigneusement les soles. Fariner légèrement des deux côtés. Taper pour enlever l'excédent.\n2. Chauffer beurre clarifié dans grande poêle à feu vif. Poser les soles. Cuire 3 min sans toucher.\n3. Retourner délicatement. Cuire encore 3 min.\n4. Retirer la sole, la dresser sur assiette chaude. Jeter le beurre de cuisson.\n5. Dans la poêle propre : fondre 80g beurre frais jusqu'à noisette (brun doré). Jus de citron. Persil. Verser sur la sole.",vin:"Chablis Grand Cru ou Meursault",notes:"Le beurre noisette doit être ajouté au dernier moment. Il ne doit pas cuire sur le poisson mais juste le napper."},
{id:"FR145",co:"France",cat:"Plat",sous:"Viande",nom:"Filet de Boeuf en Croûte d'Herbes",chef:"Tradition française moderne",bp:6,prep:20,cui:25,diff:2,qual:4,ig:[["Filet de boeuf paré",1200,"g"],["Persil plat",1,"bouquet"],["Estragon",2,"cs"],["Ciboulette",2,"cs"],["Moutarde de Meaux",3,"cs"],["Chapelure panko",80,"g"],["Huile d'olive",3,"cs"],["Sel poivre",1,"qs"]],et:"1. Saisir le filet à feu très vif sur toutes les faces 2-3 min. Badigeonner de moutarde. Refroidir.\n2. Mélanger herbes hachées + chapelure + huile d'olive.\n3. Presser la croûte d'herbes sur le filet enrobé de moutarde.\n4. Four 200°C 15-20 min selon épaisseur (T° interne 52°C pour saignant).\n5. Repos impératif 10 min. Trancher devant les convives.",vin:"Pomerol ou Graves rouge",notes:"La moutarde de Meaux sert de colle pour la croûte. La T° interne est le seul indicateur fiable de cuisson."},
{id:"FR146",co:"France",cat:"Plat",sous:"Veau",nom:"Blanquette de Ris de Veau",chef:"Tradition lyonnaise",bp:4,prep:30,cui:60,diff:3,qual:5,ig:[["Ris de veau",800,"g"],["Beurre",60,"g"],["Farine",40,"g"],["Bouillon de volaille",80,"cl"],["Crème fraîche",20,"cl"],["Champignons de Paris",200,"g"],["Oignons grelots",150,"g"],["Jaunes d'oeufs",2,"pièces"],["Jus de citron",1,"cs"],["Bouquet garni",1,"pièce"]],et:"1. Dégorger les ris de veau 2h dans l'eau froide. Blanchir 5 min. Retirer membranes et graisses.\n2. Cuire dans le bouillon frémissant 20 min. Réserver les ris. Filtrer le bouillon.\n3. Faire fondre beurre, ajouter farine, cuire 2 min. Mouiller avec le bouillon chaud en fouettant.\n4. Ajouter champignons et oignons grelots dorés. Mijoter 15 min.\n5. Hors feu, lier avec jaunes + crème + citron. Remettre les ris. Ne plus bouillir.",vin:"Meursault ou Puligny-Montrachet",notes:"Les ris doivent être pressés sous un poids après le blanchiment pour les raffermir."},
{id:"FR147",co:"France",cat:"Dessert",sous:"Viennoiserie",nom:"Croissants Beurre Maison",chef:"Tradition française boulangère",bp:12,prep:90,cui:20,diff:4,qual:5,ig:[["Farine T45",500,"g"],["Levure fraîche",20,"g"],["Lait tiède",28,"cl"],["Sucre",60,"g"],["Sel",10,"g"],["Beurre de tourage AOP",280,"g"],["Oeuf pour dorure",1,"pièce"]],et:"1. Pétrir farine + levure + lait + sucre + sel jusqu'à pâte souple. Réfrigérer 1h.\n2. Étaler en rectangle. Poser le beurre froid aplati au centre. Envelopper. 3 tours simples en réfrigérant 30 min entre chaque.\n3. Découper en triangles. Rouler de la base vers la pointe en allongeant.\n4. Dorer à l'oeuf. Pousser 2h à T° ambiante.\n5. Four 185°C 18-20 min jusqu'à dorés et feuilletés.",vin:"Café ou jus d'orange frais",notes:"La T° du beurre est critique : il doit être aussi souple que la détrempe (13°C). Trop froid il casse, trop chaud il fond."},
{id:"FR148",co:"France",cat:"Entrée",sous:"Soupe",nom:"Velouté de Potimarron au Gingembre",chef:"Tradition française moderne",bp:4,prep:15,cui:25,diff:1,qual:4,ig:[["Potimarron",1200,"g"],["Oignons",2,"pièces"],["Gingembre frais",3,"cm"],["Bouillon de légumes",80,"cl"],["Crème fraîche",10,"cl"],["Beurre",30,"g"],["Noix de muscade",1,"pincée"],["Sel poivre",1,"qs"]],et:"1. Éplucher et couper le potimarron en cubes. Émincer oignons et gingembre.\n2. Faire revenir oignons dans beurre. Ajouter gingembre, cuire 2 min.\n3. Ajouter potimarron + bouillon. Cuire 20 min à feu moyen.\n4. Mixer finement. Incorporer crème fraîche. Rectifier assaisonnement.\n5. Servir avec graines de courge toastées et filet d'huile de noisette.",vin:"Pinot Gris d'Alsace ou Viognier",notes:"Le potimarron n'a pas besoin d'être épluché — la peau est fine et se mixe parfaitement."},
{id:"FR149",co:"France",cat:"Plat",sous:"Tripes",nom:"Tripes à la Mode de Caen",chef:"Tradition normande classique",bp:8,prep:30,cui:480,diff:2,qual:5,ig:[["Tripes de boeuf blanchies",1500,"g"],["Pied de veau",1,"pièce"],["Oignons",3,"pièces"],["Carottes",3,"pièces"],["Cidre brut normand",75,"cl"],["Calvados",5,"cl"],["Bouquet garni clous de girofle",1,"pièce"],["Poivre en grains",1,"cc"],["Sel",1,"qs"]],et:"1. Couper les tripes en carrés de 5cm. Placer dans une triplière ou cocotte.\n2. Ajouter pied de veau + légumes + cidre + calvados + épices. Couvrir hermétiquement.\n3. Sceller le couvercle avec un cordon de pâte (tradition) ou avec du papier alu.\n4. Four 150°C 8h minimum. Ne pas ouvrir pendant la cuisson.\n5. Dégraisser le jus. Rectifier. Servir brûlant dans des bols en terre.",vin:"Cidre brut normand AOP",notes:"La cuisson longue à basse température est l'essence même du plat. Les tripes doivent être fondantes, jamais caoutchouteuses."},
{id:"FR150",co:"France",cat:"Dessert",sous:"Entremets",nom:"Baba au Rhum",chef:"Tradition française",bp:8,prep:30,cui:25,diff:3,qual:5,ig:[["Farine T45",250,"g"],["Levure fraîche",15,"g"],["Oeufs",4,"pièces"],["Beurre pommade",100,"g"],["Sucre",20,"g"],["Sel",5,"g"],["Eau",25,"cl"],["Sucre sirop",200,"g"],["Rhum brun",8,"cl"],["Crème fleurette",30,"cl"]],et:"1. Pétrir farine + levure + oeufs + sucre + sel. Incorporer beurre pommade progressivement. Pâte collante.\n2. Mouler en savarin ou petits moules à baba beurrés. Lever 1h.\n3. Four 200°C 20-25 min. Démouler chaud.\n4. Sirop : bouillir eau + sucre. Hors feu, ajouter rhum.\n5. Imbiber généreusement les babas encore chauds dans le sirop. Servir avec chantilly.",vin:"Rhum hors d'âge ou Champagne demi-sec",notes:"Les babas doivent être imbibés quand ils sont encore chauds — ils absorbent mieux le sirop."},
{id:"FR151",co:"France",cat:"Plat",sous:"Abats",nom:"Foie de Veau à la Vénitienne",chef:"Tradition lyonnaise",bp:4,prep:10,cui:10,diff:2,qual:4,ig:[["Foie de veau en tranches fines",600,"g"],["Oignons doux",4,"pièces"],["Beurre",60,"g"],["Huile d'olive",3,"cs"],["Vinaigre balsamique",2,"cs"],["Persil haché",2,"cs"],["Sel poivre",1,"qs"],["Farine",30,"g"]],et:"1. Émincer finement les oignons. Les confire à feu très doux dans beurre + huile 20 min sans colorer.\n2. Fariner légèrement les tranches de foie.\n3. Faire fondre beurre dans autre poêle à feu vif. Saisir le foie 1 min / face (doit rester rosé).\n4. Déglacer la poêle des oignons avec vinaigre balsamique. Réduire 1 min.\n5. Poser le foie sur les oignons. Parsemer persil.",vin:"Pinot Noir d'Alsace ou Côte de Nuits-Villages",notes:"Le foie de veau se cuit toujours à la dernière minute, jamais à l'avance. Trop cuit, il devient dur et amer."},
{id:"FR152",co:"France",cat:"Entrée",sous:"Salade",nom:"Salade Lyonnaise Authentique",chef:"Tradition des bouchons lyonnais",bp:4,prep:15,cui:10,diff:1,qual:5,ig:[["Frisée ou chicorée",400,"g"],["Lardons fumés",150,"g"],["Oeufs",4,"pièces"],["Vinaigre de vin rouge",3,"cs"],["Croûtons à l'ail",80,"g"],["Moutarde de Dijon",1,"cc"],["Huile de noix",4,"cs"],["Sel poivre",1,"qs"]],et:"1. Laver et essorer la frisée. Faire revenir lardons à sec jusqu'à dorés. Réserver.\n2. Vinaigrette : moutarde + vinaigre + sel + huile de noix émulsionnée.\n3. Pocher les oeufs 3 min dans eau vinaigrée frémissante. Égoutter.\n4. Assaisonner la salade. Ajouter lardons chauds et croûtons.\n5. Poser oeuf poché sur chaque assiette. Poivre. Servir immédiatement.",vin:"Beaujolais Villages ou Mâcon blanc",notes:"L'oeuf poché doit être servi immédiatement — c'est lui qui finit d'assaisonner la salade avec son jaune coulant."},
{id:"FR153",co:"France",cat:"Plat",sous:"Agneau",nom:"Épaule d'Agneau Rôtie aux Herbes Provençales",chef:"Tradition provençale",bp:6,prep:15,cui:120,diff:1,qual:4,ig:[["Épaule d'agneau",1800,"g"],["Ail",6,"gousses"],["Thym romarin sarriette",3,"branches"],["Huile d'olive",6,"cs"],["Sel de Guérande",1,"cs"],["Fleur de sel poivre",1,"qs"]],et:"1. Piquer l'épaule de gousses d'ail. Frotter généreusement d'huile d'olive et d'herbes.\n2. Saler abondamment. Laisser mariner 2h à T° ambiante.\n3. Four 180°C, plat avec un fond d'eau. Rôtir 1h45 en arrosant régulièrement.\n4. Couvrir de papier alu. Repos 15 min avant de servir.\n5. Déglacer le jus de cuisson avec un verre d'eau. Filtrer.",vin:"Bandol rouge ou Gigondas",notes:"Une épaule d'agneau se rôtit longtemps à chaleur modérée. Le collagène a besoin de temps pour fondre."},
{id:"FR154",co:"France",cat:"Dessert",sous:"Tarte",nom:"Tarte aux Pommes Fine Feuilletée",chef:"Tradition française boulangère",bp:6,prep:20,cui:30,diff:2,qual:4,ig:[["Pâte feuilletée pur beurre",300,"g"],["Pommes Golden",5,"pièces"],["Beurre fondu",40,"g"],["Sucre",3,"cs"],["Sucre glace",1,"cs"],["Confiture d'abricot",2,"cs"]],et:"1. Étaler la pâte très finement. Piquer. Réfrigérer 20 min.\n2. Éplucher et trancher les pommes en lamelles très fines à la mandoline.\n3. Disposer en rosace serrée en se chevauchant légèrement.\n4. Beurre fondu + sucre sur les pommes. Four 210°C 25-30 min.\n5. Nappage : chauffer confiture d'abricot + eau, filtrer, badigeonner à chaud.",vin:"Coteaux du Layon ou Cidre demi-sec breton",notes:"La pâte doit être très fine et très froide au moment de l'enfournement pour rester croustillante."},
{id:"FR155",co:"France",cat:"Plat",sous:"Porc",nom:"Rôti de Porc en Croûte de Sel",chef:"Tradition française",bp:6,prep:20,cui:70,diff:2,qual:4,ig:[["Filet de porc",1200,"g"],["Gros sel",1500,"g"],["Blancs d'oeufs",4,"pièces"],["Thym romarin",4,"branches"],["Moutarde de Meaux",2,"cs"],["Ail",4,"gousses"]],et:"1. Badigeonner le filet de moutarde. Insérer ail et herbes.\n2. Mélanger gros sel + blancs d'oeufs jusqu'à consistance de sable humide.\n3. Tapisser un plat de sel. Poser le filet. Envelopper entièrement de sel (3cm d'épaisseur).\n4. Four 200°C 60-70 min (T° interne 68°C).\n5. Casser la croûte de sel à table. Trancher.",vin:"Viré-Clessé ou Mâcon-Villages",notes:"La croûte de sel cuit à la vapeur et concentre les arômes. Le porc reste juteux à l'intérieur."},
{id:"FR156",co:"France",cat:"Entrée",sous:"Velouté",nom:"Velouté de Cèpes à la Crème",chef:"Tradition gasconne",bp:4,prep:15,cui:25,diff:2,qual:5,ig:[["Cèpes frais ou réhydratés",400,"g"],["Échalotes",3,"pièces"],["Beurre",50,"g"],["Bouillon de volaille",60,"cl"],["Crème fraîche",15,"cl"],["Ail",2,"gousses"],["Persil",2,"cs"],["Sel poivre",1,"qs"]],et:"1. Nettoyer les cèpes. Réserver les plus beaux entiers pour la garniture.\n2. Suer échalotes + ail dans beurre. Ajouter les cèpes hachés. Cuire 5 min.\n3. Mouiller avec bouillon. Cuire 15 min.\n4. Mixer finement. Incorporer crème. Chauffer sans bouillir.\n5. Poêler les cèpes réservés entiers dans beurre noisette. Déposer sur le velouté.",vin:"Pessac-Léognan blanc ou Hermitage blanc",notes:"L'eau de réhydratation des cèpes séchés est précieuse — la filtrer et l'ajouter au bouillon."},
{id:"FR157",co:"France",cat:"Dessert",sous:"Biscuit",nom:"Financiers aux Pistaches",chef:"Tradition française pâtissière",bp:12,prep:15,cui:15,diff:1,qual:4,ig:[["Beurre noisette",100,"g"],["Sucre glace",180,"g"],["Poudre d'amandes",80,"g"],["Poudre de pistaches",50,"g"],["Blancs d'oeufs",4,"pièces"],["Farine T45",50,"g"],["Pistaches entières",24,"pièces"]],et:"1. Faire fondre le beurre jusqu'à noisette (brun doré). Filtrer. Laisser tiédir.\n2. Mélanger sucre glace + poudres + farine. Incorporer blancs NON MONTÉS.\n3. Ajouter beurre noisette tiède. Mélanger.\n4. Remplir des moules à financiers beurrés aux 3/4. Déposer 2 pistaches entières.\n5. Four 190°C 13-15 min. Les bords doivent être dorés, le centre légèrement souple.",vin:"Champagne rosé ou Muscat de Beaumes-de-Venise",notes:"Le beurre noisette est l'âme du financier. Ne pas le cuire trop — il doit sentir la noisette, pas brûler."},
{id:"FR158",co:"France",cat:"Plat",sous:"Canard",nom:"Magret de Canard Rôti aux Figues",chef:"Tradition gasconne",bp:4,prep:15,cui:20,diff:2,qual:4,ig:[["Magrets de canard",2,"pièces"],["Figues fraîches",8,"pièces"],["Vinaigre balsamique",4,"cs"],["Miel d'acacia",2,"cs"],["Bouillon de volaille",10,"cl"],["Thym",2,"branches"],["Sel poivre",1,"qs"]],et:"1. Quadriller la peau des magrets au couteau sans atteindre la chair. Saler.\n2. Saisir côté peau à feu moyen dans poêle froide (sans matière grasse) 8-10 min. Égoutter la graisse.\n3. Retourner. Saisir côté chair 4-5 min (saignant). Reposer sous alu 5 min.\n4. Sauce : dans poêle vidée, dorer les figues coupées. Déglacer vinaigre + miel + bouillon. Réduire.\n5. Trancher en biais. Napper de sauce aux figues.",vin:"Madiran ou Cahors ou Côtes de Gascogne rouge",notes:"Démarrer la cuisson côté peau dans une poêle froide — la graisse fond progressivement sans brûler."},
{id:"FR159",co:"France",cat:"Accompagnement",sous:"Légumes",nom:"Fenouil Braisé au Citron",chef:"Tradition provençale",bp:4,prep:10,cui:40,diff:1,qual:4,ig:[["Fenouils",4,"pièces"],["Citron non traité",1,"pièce"],["Bouillon de légumes",20,"cl"],["Huile d'olive",4,"cs"],["Ail",2,"gousses"],["Thym",2,"branches"],["Sel poivre",1,"qs"]],et:"1. Couper les fenouils en deux dans le sens de la longueur. Réserver les fanes.\n2. Dorer dans l'huile d'olive des deux côtés. Ajouter ail + thym + zeste de citron.\n3. Mouiller avec bouillon. Couvrir. Mijoter 30-35 min à feu doux.\n4. Découvrir les 5 dernières minutes pour glacer les fenouils dans le jus réduit.\n5. Jus de citron. Décorer avec les fanes de fenouil.",vin:"Accompagnement idéal des poissons et viandes blanches"},
{id:"FR160",co:"France",cat:"Dessert",sous:"Gâteau",nom:"Gâteau Basque à la Crème",chef:"Tradition basque",bp:8,prep:30,cui:40,diff:2,qual:5,ig:[["Farine T55",300,"g"],["Beurre pommade",175,"g"],["Sucre",180,"g"],["Oeufs",3,"pièces"],["Levure chimique",1,"cc"],["Sel",1,"pincée"],["Lait entier",50,"cl"],["Maïzena",40,"g"],["Jaunes pour crème",4,"pièces"],["Vanille",1,"gousse"]],et:"Crème pâtissière :\n1. Infuser vanille dans lait chaud. Fouetter jaunes + sucre + maïzena. Verser lait chaud, cuire en fouettant jusqu'à épaississement. Filmer au contact. Refroidir.\nPâte :\n2. Crémer beurre + sucre. Ajouter oeufs un par un. Incorporer farine + levure + sel.\n3. Étaler 2/3 de la pâte dans un moule beurré de 24cm. Verser crème froide. Couvrir avec reste de pâte.\n4. Dorer à l'oeuf. Quadriller avec une fourchette.\n5. Four 175°C 35-40 min.",vin:"Jurançon moelleux ou Irouléguy blanc",notes:"Le gâteau basque à la crème est la version traditionnelle de Cambo-les-Bains. La version à la cerise noire est basque-navarraise."},
{id:"FR161",co:"France",cat:"Plat",sous:"Veau",nom:"Piccata de Veau au Citron Câpres",chef:"Tradition franco-italienne",bp:4,prep:10,cui:10,diff:2,qual:4,ig:[["Escalopes de veau fines",600,"g"],["Farine",40,"g"],["Beurre",80,"g"],["Jus de citron",4,"cs"],["Câpres",3,"cs"],["Vin blanc sec",8,"cl"],["Persil haché",2,"cs"],["Sel poivre",1,"qs"]],et:"1. Aplatir les escalopes à 3mm. Fariner légèrement, taper pour enlever l'excédent.\n2. Cuire dans beurre mousseux à feu vif 1-2 min/face jusqu'à dorées. Réserver.\n3. Déglacer avec vin blanc. Réduire de moitié.\n4. Ajouter jus de citron + câpres. Monter au beurre froid.\n5. Remettre les escalopes 30 sec. Parsemer persil.",vin:"Bourgogne blanc ou Chablis",notes:"Les escalopes doivent être très fines et cuites à feu très vif — 1 min max par face."},
{id:"FR162",co:"France",cat:"Entrée",sous:"Soufflé",nom:"Soufflé au Roquefort",chef:"Tradition française classique",bp:4,prep:20,cui:20,diff:3,qual:4,ig:[["Roquefort",120,"g"],["Beurre",40,"g"],["Farine",35,"g"],["Lait entier",25,"cl"],["Oeufs",4,"pièces"],["Crème fraîche",2,"cs"],["Sel poivre de Cayenne",1,"qs"],["Beurre et farine pour ramequins",1,"qs"]],et:"1. Beurrer et fariner 4 ramequins. Réfrigérer.\n2. Béchamel épaisse : beurre + farine + lait. Incorporer roquefort + crème + jaunes.\n3. Monter blancs en neige ferme. Incorporer 1/3 délicatement au mélange, puis le reste en soulevant.\n4. Remplir aux 3/4 les ramequins froids.\n5. Four préchauffé à 200°C 18-20 min. NE JAMAIS OUVRIR LE FOUR. Servir immédiatement.",vin:"Sauternes ou Monbazillac",notes:"Les ramequins froids et le four bien préchauffé sont les deux secrets du soufflé qui monte."},
{id:"FR163",co:"France",cat:"Plat",sous:"Porc",nom:"Andouille de Vire au Cidre",chef:"Tradition normande",bp:4,prep:10,cui:30,diff:1,qual:4,ig:[["Andouille de Vire",600,"g"],["Oignons",2,"pièces"],["Cidre brut",40,"cl"],["Moutarde à l'ancienne",2,"cs"],["Crème fraîche",15,"cl"],["Beurre",30,"g"],["Thym",2,"branches"],["Poivre noir",1,"qs"]],et:"1. Suer oignons dans beurre jusqu'à fondants et légèrement dorés.\n2. Ajouter les tranches d'andouille. Dorer 3 min de chaque côté.\n3. Mouiller avec cidre. Ajouter thym. Réduire de moitié.\n4. Incorporer moutarde + crème fraîche. Mijoter 10 min.\n5. Rectifier poivre. Servir avec pommes de terre vapeur.",vin:"Cidre brut normand AOP ou Calvados vieux",notes:"Ne pas saler — l'andouille est déjà bien assaisonnée."},
{id:"FR164",co:"France",cat:"Dessert",sous:"Entremet",nom:"Charlotte Royale",chef:"Tradition française classique",bp:8,prep:60,cui:20,diff:4,qual:5,ig:[["Biscuit roulé à la framboise",1,"pièce"],["Bavarois vanille",1,"qs"],["Lait entier",50,"cl"],["Jaunes d'oeufs",5,"pièces"],["Sucre",120,"g"],["Gélatine",10,"g"],["Crème fleurette",35,"cl"],["Vanille",1,"gousse"],["Framboises fraîches",200,"g"]],et:"1. Couper le biscuit roulé en tranches de 1cm. Chemiser un bol rond (22cm) en les chevauchant.\n2. Bavarois : anglaise (lait + jaunes + sucre + vanille). Hors feu, gélatine essorée. Laisser tiédir. Incorporer crème fouettée.\n3. Verser le bavarois dans la charlotte. Couvrir de framboises fraîches. Fermer avec biscuit.\n4. Réfrigérer 8h minimum.\n5. Démouler sur plat. Servir en parts.",vin:"Champagne rosé ou Muscat de Rivesaltes",notes:"Le secret est de chemiser parfaitement le bol avec les tranches de biscuit roulé serrées pour avoir un bel effet spirale au démoulage."},
{id:"FR165",co:"France",cat:"Accompagnement",sous:"Légumes",nom:"Carottes Glacées au Beurre et Miel",chef:"Tradition française",bp:4,prep:10,cui:25,diff:1,qual:4,ig:[["Carottes fanes",800,"g"],["Beurre",40,"g"],["Miel d'acacia",2,"cs"],["Bouillon de légumes",15,"cl"],["Thym",2,"branches"],["Sel poivre",1,"qs"]],et:"1. Éplucher et couper les carottes en tronçons biseautés.\n2. Dans sauteuse : carottes + beurre + miel + bouillon + thym. Assaisonner.\n3. Couvrir. Cuire à feu moyen 15 min jusqu'à carottes tendres.\n4. Découvrir. Cuire à feu vif en remuant jusqu'à évaporation complète et glaçage brillant.\n5. Parsemer persil ou cerfeuil.",vin:"Accompagnement de viandes rôties et poissons"},
{id:"FR166",co:"France",cat:"Plat",sous:"Poisson",nom:"Daurade Royale en Papillote",chef:"Tradition méditerranéenne française",bp:4,prep:15,cui:20,diff:1,qual:4,ig:[["Daurades royales entières",2,"pièces"],["Fenouil",2,"bulbes"],["Tomates cerises",200,"g"],["Olives noires",60,"g"],["Huile d'olive",6,"cs"],["Citron non traité",1,"pièce"],["Thym romarin",4,"branches"],["Sel poivre",1,"qs"]],et:"1. Préparer 2 grandes feuilles de papier sulfurisé ou alu.\n2. Sur chaque feuille : lit de fenouil émincé + tomates + olives + herbes.\n3. Poser la daurade. Arroser d'huile d'olive. Tranches de citron. Saler.\n4. Fermer hermétiquement les papillotes.\n5. Four 200°C 18-20 min selon la taille. Ouvrir à table.",vin:"Cassis blanc ou Bandol blanc",notes:"Les papillotes gonflent à la cuisson — c'est bon signe. Ouvrir devant les convives pour l'effet."},
{id:"FR167",co:"France",cat:"Sauce / Base",sous:"Sauce mère",nom:"Sauce Bordelaise au Vin Rouge",chef:"Tradition bordelaise classique",bp:4,prep:10,cui:30,diff:3,qual:5,ig:[["Échalotes",4,"pièces"],["Vin rouge de Bordeaux",35,"cl"],["Fond de veau brun",25,"cl"],["Beurre froid",60,"g"],["Moelle de boeuf",60,"g"],["Thym laurier",1,"qs"],["Sel poivre",1,"qs"]],et:"1. Suer échalotes ciselées dans un peu de beurre. Ajouter vin rouge + thym + laurier.\n2. Réduire le vin à sec (jusqu'à presque 0).\n3. Ajouter fond de veau. Réduire de 2/3 jusqu'à sauce nappante.\n4. Filtrer. Monter au beurre froid hors feu en fouettant (ne plus bouillir).\n5. Ajouter moelle pochée en rondelles. Rectifier.",vin:"Pomerol ou Saint-Émilion pour cuisiner",notes:"La réduction du vin à sec avant l'ajout du fond évite toute amertume."},
{id:"FR168",co:"France",cat:"Plat",sous:"Volaille",nom:"Suprême de Volaille Farci aux Morilles",chef:"Tradition française gastronomique",bp:4,prep:30,cui:20,diff:3,qual:5,ig:[["Suprêmes de poulet fermier",4,"pièces"],["Morilles réhydratées",40,"g"],["Beurre",80,"g"],["Crème fraîche",20,"cl"],["Foie gras cuit",60,"g"],["Échalotes",2,"pièces"],["Vin jaune",5,"cl"],["Sel poivre",1,"qs"]],et:"1. Préparer la farce : suer échalotes + morilles hachées. Déglacer vin jaune. Refroidir. Mélanger avec foie gras.\n2. Inciser les suprêmes en poche. Farcir. Ficeler ou maintenir avec pics.\n3. Saisir côté peau dans beurre mousseux 4 min. Retourner 3 min. Finir au four 180°C 8 min.\n4. Reposer 5 min. Sauce : déglacer la poêle + crème + morilles entières. Réduire.\n5. Trancher en médaillons. Napper.",vin:"Meursault ou Viré-Clessé",notes:"Les morilles doivent être soigneusement rincées plusieurs fois — elles retiennent le sable."},
{id:"FR169",co:"France",cat:"Dessert",sous:"Entremets",nom:"Pots de Crème au Chocolat",chef:"Tradition française classique",bp:6,prep:15,cui:35,diff:1,qual:5,ig:[["Chocolat noir 70%",180,"g"],["Lait entier",35,"cl"],["Crème fraîche",15,"cl"],["Oeufs",2,"pièces"],["Jaunes d'oeufs",4,"pièces"],["Sucre",60,"g"],["Sel",1,"pincée"]],et:"1. Hacher le chocolat. Chauffer lait + crème ensemble jusqu'à frémissement.\n2. Verser sur le chocolat haché. Mélanger jusqu'à fondu et lisse.\n3. Fouetter oeufs + jaunes + sucre + sel. Verser le chocolat chaud en filet en mélangeant.\n4. Filtrer. Verser dans 6 petits pots.\n5. Bain-marie au four 150°C 30-35 min. Le centre doit légèrement trembler. Réfrigérer 4h.",vin:"Porto LBV ou Maury rouge",notes:"La cuisson au bain-marie à basse température donne une texture incroyablement soyeuse."},
{id:"FR170",co:"France",cat:"Plat",sous:"Lapin",nom:"Lapin à la Moutarde",chef:"Tradition bourguignonne",bp:4,prep:15,cui:60,diff:2,qual:5,ig:[["Lapin découpé",1,"pièce"],["Moutarde de Dijon",4,"cs"],["Crème fraîche",20,"cl"],["Oignons",2,"pièces"],["Ail",3,"gousses"],["Bouillon de volaille",15,"cl"],["Thym laurier",2,"branches"],["Beurre",40,"g"]],et:"1. Badigeonner généreusement les morceaux de lapin de moutarde.\n2. Dorer dans beurre sur toutes les faces. Réserver.\n3. Suer oignons + ail. Déglacer bouillon.\n4. Remettre le lapin. Thym + laurier. Couvrir. Mijoter 45 min à feu doux.\n5. Retirer le lapin. Incorporer crème fraîche. Réduire 5 min. Remettre le lapin.",vin:"Rully blanc ou Givry blanc",notes:"Le lapin de garenne est plus goûteux mais plus ferme — ajouter 15 min de cuisson."},
{id:"FR171",co:"France",cat:"Entrée",sous:"Terrine",nom:"Terrine de Foie Gras Mi-Cuit Maison",chef:"Tradition gasconne classique",bp:10,prep:30,cui:40,diff:3,qual:5,ig:[["Foie gras de canard cru déveiné",700,"g"],["Fleur de sel",8,"g"],["Poivre blanc",2,"g"],["Sauternes ou Monbazillac",3,"cs"],["Armagnac",1,"cs"],["Sucre",1,"g"]],et:"1. Déveiner soigneusement le foie à T° ambiante. Assaisonner sel + poivre + sucre + alcools.\n2. Tasser dans une terrine en porcelaine. Couvrir de film. Réfrigérer 12h.\n3. Retirer le film. Couvrir avec papier alu ou couvercle.\n4. Bain-marie au four 80°C 40 min (T° interne 54°C au coeur).\n5. Réfrigérer 48h minimum sous poids avant de déguster.",vin:"Sauternes, Jurançon moelleux ou Champagne",notes:"La T° de cuisson est critique : 80°C four, 54°C au coeur. Au-dessus le foie fond."},
{id:"FR172",co:"France",cat:"Accompagnement",sous:"Gratins",nom:"Gratin de Crozets au Beaufort",chef:"Tradition savoyarde",bp:4,prep:10,cui:25,diff:1,qual:4,ig:[["Crozets de Savoie",300,"g"],["Beaufort râpé",150,"g"],["Crème fraîche",20,"cl"],["Lardons",100,"g"],["Oignons",1,"pièce"],["Beurre",20,"g"],["Sel poivre muscade",1,"qs"]],et:"1. Cuire les crozets dans eau bouillante salée 15 min. Égoutter en gardant un peu d'eau.\n2. Suer oignons + lardons dans beurre.\n3. Mélanger crozets + oignons + lardons + crème + muscade. Rectifier.\n4. Verser dans plat à gratin. Couvrir de Beaufort râpé.\n5. Four 200°C 20-25 min jusqu'à gratinés et dorés.",vin:"Apremont ou Chignin blanc de Savoie"},
{id:"FR173",co:"France",cat:"Plat",sous:"Agneau",nom:"Carré d'Agneau Rôti en Croûte de Pistaches",chef:"Tradition française gastronomique",bp:4,prep:20,cui:20,diff:3,qual:5,ig:[["Carrés d'agneau",2,"pièces"],["Pistaches non salées en poudre",100,"g"],["Chapelure panko",40,"g"],["Moutarde de Dijon",2,"cs"],["Beurre",30,"g"],["Persil plat",2,"cs"],["Sel poivre",1,"qs"]],et:"1. Manchonner les carrés. Assaisonner. Saisir dans beurre 2 min sur toutes les faces.\n2. Badigeonner la partie charnue de moutarde.\n3. Presser la croûte pistaches + chapelure + persil sur la moutarde.\n4. Four 200°C 12-15 min (T° interne 55°C pour rosé).\n5. Reposer 5 min sous alu. Trancher entre chaque côte.",vin:"Bandol rouge ou Côte-Rôtie",notes:"Manchonner = nettoyer les os en grattant la viande vers le bas pour un beau visuel."},
{id:"FR174",co:"France",cat:"Dessert",sous:"Gâteau régional",nom:"Kougelhopf aux Raisins et Kirsch",chef:"Tradition alsacienne",bp:8,prep:30,cui:40,diff:3,qual:4,ig:[["Farine T45",500,"g"],["Levure fraîche",20,"g"],["Lait tiède",20,"cl"],["Beurre pommade",180,"g"],["Oeufs",3,"pièces"],["Sucre",80,"g"],["Raisins secs macérés kirsch",150,"g"],["Amandes entières",30,"g"],["Sel",8,"g"]],et:"1. Mélanger farine + levure + lait tiède + oeufs + sucre + sel. Pétrir 10 min.\n2. Incorporer beurre pommade progressivement. Pétrir encore 5 min. Pâte collante.\n3. Incorporer les raisins égouttés. Lever 2h.\n4. Beurrer généreusement un moule à kougelhopf. Placer amandes dans les cannelures. Verser la pâte.\n5. Lever encore 1h. Four 180°C 35-40 min. Saupoudrer sucre glace.",vin:"Gewurztraminer vendanges tardives ou crémant d'Alsace",notes:"Le moule en terre cuite traditionnel est préférable — il donne une croûte plus fine et régulière."},
{id:"FR175",co:"France",cat:"Plat",sous:"Boeuf",nom:"Entrecôte Sauce Béarnaise Maison",chef:"Tradition des brasseries parisiennes",bp:4,prep:20,cui:15,diff:3,qual:5,ig:[["Entrecôtes",4,"pièces"],["Beurre clarifié",200,"g"],["Jaunes d'oeufs",4,"pièces"],["Vinaigre d'estragon",4,"cs"],["Échalotes",3,"pièces"],["Estragon frais",3,"cs"],["Poivre concassé",1,"cc"],["Sel",1,"qs"]],et:"1. Réduction béarnaise : vinaigre + échalotes + poivre. Réduire aux 2/3. Filtrer tiédir.\n2. Fouetter jaunes + réduction au bain-marie jusqu'à sabayon crémeux (65°C max).\n3. Incorporer beurre clarifié en filet hors bain-marie. Estragon. Ajuster.\n4. Saisir entrecôtes à feu très vif 2-3 min/face. Sel poivre.\n5. Repos 3 min. Servir avec sauce béarnaise à part.",vin:"Pomerol ou Côte de Nuits-Villages",notes:"La béarnaise doit être servie tiède, jamais chaude — sinon elle se dissocie."},
{id:"FR176",co:"France",cat:"Assaisonnement",sous:"Beurre composé",nom:"Beurre de Homard",chef:"Tradition française des grands sauces",bp:6,prep:15,cui:10,diff:2,qual:5,ig:[["Beurre doux",200,"g"],["Corail et pattes de homard",80,"g"],["Cognac",1,"cs"],["Sel",1,"pincée"],["Poivre de Cayenne",1,"pincée"]],et:"1. Piler finement les pattes et le corail de homard au mortier (ou mixer).\n2. Fondre beurre à feu très doux. Ajouter la pâte de homard.\n3. Ajouter cognac. Cuire 5 min à feu doux en mélangeant.\n4. Filtrer au travers d'un linge fin en pressant bien. Assaisonner.\n5. Verser dans un bol. Réfrigérer. Se conserve 1 semaine ou se congèle.",vin:"Usage : sauces pour poissons, bisques, riz pilaf",notes:"Ce beurre est précieux pour finir une bisque de homard ou une sauce Américaine."},
{id:"FR177",co:"France",cat:"Entrée",sous:"Oeufs",nom:"Oeufs Cocotte à la Truffe",chef:"Tradition française gastronomique",bp:4,prep:5,cui:10,diff:1,qual:5,ig:[["Oeufs",4,"pièces"],["Crème fraîche",4,"cs"],["Truffe noire",20,"g"],["Beurre",20,"g"],["Sel fleur de sel",1,"qs"],["Poivre blanc",1,"qs"]],et:"1. Préchauffer four 180°C. Beurrer 4 petits ramequins.\n2. Déposer 1cs de crème fraîche dans chaque ramequin. Quelques lamelles de truffe.\n3. Casser délicatement 1 oeuf par-dessus.\n4. Bain-marie au four 8-10 min — le blanc doit être pris, le jaune encore coulant.\n5. Fleur de sel + poivre blanc + truffe fraîchement râpée. Servir immédiatement.",vin:"Champagne blanc de blancs ou Chablis Grand Cru",notes:"La truffe peut être remplacée par de l'huile de truffe pour une version accessible."},
{id:"FR178",co:"France",cat:"Plat",sous:"Poisson",nom:"Cabillaud Rôti aux Lentilles Vertes du Puy",chef:"Tradition auvergnate",bp:4,prep:15,cui:30,diff:2,qual:4,ig:[["Dos de cabillaud",800,"g"],["Lentilles vertes du Puy",300,"g"],["Lardons fumés",100,"g"],["Carottes",2,"pièces"],["Oignons",1,"pièce"],["Bouillon de volaille",70,"cl"],["Beurre",60,"g"],["Vinaigre de xérès",1,"cs"],["Sel poivre",1,"qs"]],et:"1. Cuire lentilles avec lardons + carotte + oignon + bouillon 25 min. Assaisonner + vinaigre.\n2. Assaisonner le cabillaud. Saisir dans beurre mousseux côté peau 4 min jusqu'à croustillant.\n3. Retourner. 2 min côté chair.\n4. Déposer sur lit de lentilles.\n5. Jus de cuisson beurré sur le poisson.",vin:"Sancerre ou Menetou-Salon",notes:"Les lentilles du Puy (AOP) sont les meilleures — elles restent fermes à la cuisson."},
{id:"FR179",co:"France",cat:"Dessert",sous:"Sorbet",nom:"Sorbet au Citron de Menton",chef:"Tradition niçoise",bp:6,prep:15,cui:5,diff:2,qual:4,ig:[["Jus de citron frais",25,"cl"],["Zeste de 4 citrons non traités",1,"qs"],["Sucre",180,"g"],["Eau",15,"cl"],["Blanc d'oeuf",1,"pièce"]],et:"1. Sirop : bouillir eau + sucre 2 min. Ajouter zestes. Refroidir complètement.\n2. Mélanger sirop filtré + jus de citron. Turbiner en sorbetière 20 min.\n3. Quand le sorbet est à demi-pris, ajouter le blanc d'oeuf légèrement battu. Turbiner encore 5 min.\n4. Transférer en boîte. Congeler 2h minimum.\n5. Servir dans les demi-citrons évidés.",vin:"Champagne Blanc de Blancs ou Limoncello maison",notes:"Le blanc d'oeuf allège la texture et évite les cristaux. Le citron de Menton IGP est incomparable."},
{id:"FR180",co:"France",cat:"Plat",sous:"Canard",nom:"Confit de Cuisses de Canard Maison",chef:"Tradition gasconne",bp:4,prep:20,cui:150,diff:2,qual:5,ig:[["Cuisses de canard",4,"pièces"],["Gros sel",80,"g"],["Graisse de canard",600,"g"],["Thym laurier",4,"branches"],["Ail",4,"gousses"],["Poivre concassé",1,"cc"]],et:"1. Saler les cuisses avec gros sel + thym + laurier + ail + poivre. Réfrigérer 12h.\n2. Rincer et sécher soigneusement les cuisses.\n3. Faire fondre la graisse de canard. Immerger les cuisses entièrement.\n4. Cuire à feu très doux (85°C) 2h30 — aucun bouillonnement.\n5. Laisser refroidir dans la graisse. Conserver au froid sous graisse ou dorer à la poêle.",vin:"Madiran ou Cahors",notes:"Le confit se conserve des semaines recouvert de graisse au froid. C'était la méthode de conservation d'avant réfrigérateur."},
{id:"FR181",co:"France",cat:"Sauce / Base",sous:"Fond de sauce",nom:"Jus de Veau Réduit (Glace de Viande)",chef:"Tradition française classique",bp:4,prep:20,cui:300,diff:2,qual:5,ig:[["Os de veau rôtis",2000,"g"],["Oignons",3,"pièces"],["Carottes",2,"pièces"],["Concentré de tomates",2,"cs"],["Vin blanc",25,"cl"],["Bouquet garni",1,"pièce"],["Eau froide",3,"L"]],et:"1. Faire rôtir les os au four 220°C 40 min jusqu'à très dorés.\n2. Suer légumes. Ajouter concentré de tomates. Cuire 5 min.\n3. Déglacer avec vin blanc. Ajouter os + eau froide + bouquet garni. Porter à frémissement.\n4. Cuire 5-6h à feu doux. Écumer régulièrement.\n5. Filtrer. Réduire jusqu'à consistance sirupeuse et brillante. Se conserve congelé en cubes.",vin:"Usage : sauces brunes, jus de rôti, enrichissement",notes:"Cette glace de viande concentrée est la base de la grande cuisine française. 3 litres deviennent 15cl de glace."},
{id:"FR182",co:"France",cat:"Entrée",sous:"Tarte",nom:"Tarte Aux Poireaux et Chèvre",chef:"Tradition française",bp:6,prep:20,cui:35,diff:1,qual:4,ig:[["Pâte brisée",1,"pièce"],["Poireaux",3,"pièces"],["Fromage de chèvre frais",150,"g"],["Oeufs",3,"pièces"],["Crème fraîche",20,"cl"],["Beurre",30,"g"],["Sel poivre muscade",1,"qs"]],et:"1. Foncer un moule de 26cm avec pâte brisée. Cuire à blanc 15 min à 180°C.\n2. Émincer les poireaux. Faire fondre dans beurre 15 min jusqu'à très fondants. Assaisonner.\n3. Appareil : oeufs + crème + sel + poivre + muscade. Fouetter.\n4. Étaler poireaux sur fond. Émietter chèvre. Verser l'appareil.\n5. Four 180°C 25-30 min jusqu'à prise.",vin:"Sancerre blanc ou Quincy",notes:"Égoutter les poireaux dans une passoire avant de les mettre dans la tarte — l'excès d'eau rendrait le fond humide."},
{id:"FR183",co:"France",cat:"Plat",sous:"Agneau",nom:"Tagine d'Agneau à la Française",chef:"Tradition française d'influence orientale",bp:6,prep:20,cui:90,diff:2,qual:4,ig:[["Épaule d'agneau en cubes",1200,"g"],["Oignons",3,"pièces"],["Tomates concassées",400,"g"],["Pruneaux",150,"g"],["Amandes effilées",60,"g"],["Miel",2,"cs"],["Cannelle cumin coriandre",1,"qs"],["Safran",0.2,"g"],["Bouillon",20,"cl"]],et:"1. Dorer l'agneau en cubes sur toutes les faces. Réserver.\n2. Suer oignons. Ajouter épices + safran. Cuire 2 min.\n3. Remettre agneau + tomates + bouillon. Couvrir. Cuire 1h à feu doux.\n4. Ajouter pruneaux + miel. Cuire encore 20 min.\n5. Parsemer d'amandes effilées toastées.",vin:"Côtes du Roussillon rouge ou Corbières",notes:"Servir avec couscous de blé ou semoule fine arrosée de beurre ras-el-hanout."},
{id:"FR184",co:"France",cat:"Dessert",sous:"Viennoiserie",nom:"Pain aux Raisins à la Crème Pâtissière",chef:"Tradition française boulangère",bp:10,prep:60,cui:20,diff:3,qual:4,ig:[["Pâte feuilletée levée (détrempe)",600,"g"],["Beurre tourage",200,"g"],["Crème pâtissière",30,"cl"],["Raisins secs macérés rhum",150,"g"],["Oeuf pour dorure",1,"pièce"],["Sucre glace glaçage",4,"cs"]],et:"1. Tourage : 3 tours simples avec beurre froid. Réfrigérer entre chaque.\n2. Étaler en rectangle 40x30cm. Tartiner de crème pâtissière. Parsemer de raisins.\n3. Rouler serré en boudin. Couper en rondelles de 3cm.\n4. Dorer. Laisser pousser 1h30. Dorer à nouveau.\n5. Four 185°C 18-20 min. Glacer chaud avec sucre glace + eau.",vin:"Café noir ou chocolat chaud"},
{id:"FR185",co:"France",cat:"Accompagnement",sous:"Légumineuses",nom:"Cassoulet de Légumes Fondant",chef:"Tradition languedocienne végétarienne",bp:6,prep:20,cui:60,diff:2,qual:4,ig:[["Haricots blancs cuits",600,"g"],["Oignons",2,"pièces"],["Carottes",2,"pièces"],["Tomates concassées",400,"g"],["Concentré de tomates",2,"cs"],["Ail",4,"gousses"],["Thym laurier bouquet garni",1,"pièce"],["Chapelure",60,"g"],["Huile d'olive",5,"cs"]],et:"1. Suer oignons + carottes + ail dans l'huile.\n2. Ajouter tomates + concentré. Cuire 10 min.\n3. Ajouter haricots + bouquet garni. Couvrir d'eau à hauteur. Cuire 30 min.\n4. Verser en cassole ou plat à gratin. Saupoudrer de chapelure.\n5. Four 200°C 25-30 min en repoussant la croûte 2-3 fois.",vin:"Corbières ou Minervois blanc",notes:"Repousser la croûte 2-3 fois pendant la cuisson — c'est la tradition du cassoulet."},
{id:"FR186",co:"France",cat:"Plat",sous:"Pigeon",nom:"Pigeonneau Rôti aux Petits Pois à la Française",chef:"Tradition française gastronomique",bp:4,prep:20,cui:25,diff:3,qual:5,ig:[["Pigeonneaux",4,"pièces"],["Petits pois frais",600,"g"],["Lardons",100,"g"],["Oignons grelots",150,"g"],["Salade romaine",1,"pièce"],["Beurre",80,"g"],["Bouillon de volaille",10,"cl"],["Sel poivre",1,"qs"]],et:"1. Saisir les pigeonneaux entiers dans beurre sur toutes les faces 5 min.\n2. Four 200°C 15 min (rosé). Reposer 5 min sous alu.\n3. Petits pois à la française : faire fondre beurre. Ajouter lardons + oignons + salade en chiffonnade + pois. Mouiller légèrement. Cuire 8 min.\n4. Découper les pigeonneaux. Servir sur les petits pois.\n5. Jus de rôtissage déglacé.",vin:"Pommard ou Volnay",notes:"La salade romaine cuite dans les petits pois à la française fond et parfume délicatement la garniture."},
{id:"FR187",co:"France",cat:"Dessert",sous:"Biscuit",nom:"Langue de Chat Dorée",chef:"Tradition française classique",bp:40,prep:15,cui:10,diff:1,qual:4,ig:[["Beurre pommade",100,"g"],["Sucre glace",100,"g"],["Blancs d'oeufs",100,"g"],["Farine T45",100,"g"],["Extrait de vanille",1,"cc"]],et:"1. Crémer beurre + sucre glace + vanille jusqu'à blanchi.\n2. Incorporer les blancs légèrement battus (pas montés) progressivement.\n3. Ajouter farine tamisée. Mélanger sans travailler.\n4. Dresser en bâtonnets de 6cm avec poche lisse (n°6) sur silpat.\n5. Four 190°C 8-10 min — dorées sur les bords, claires au centre.",vin:"Champagne ou Café",notes:"Égalité parfaite beurre-sucre-blancs-farine (1-1-1-1). À conserver dans boîte hermétique."},
{id:"FR188",co:"France",cat:"Entrée",sous:"Aspic",nom:"Oeuf Parfait Mimosa Classique",chef:"Tradition française",bp:4,prep:15,cui:10,diff:1,qual:4,ig:[["Oeufs durs",8,"pièces"],["Mayonnaise maison",8,"cs"],["Moutarde de Dijon",1,"cc"],["Cornichons",4,"pièces"],["Câpres",1,"cs"],["Estragon",1,"cs"],["Sel poivre",1,"qs"],["Paprika",1,"pincée"]],et:"1. Cuire les oeufs 9 min. Écaler. Couper en deux.\n2. Extraire les jaunes. Les écraser à la fourchette.\n3. Mélanger jaunes + mayonnaise + moutarde + cornichons hachés + câpres + estragon.\n4. Remplir les blancs avec la farce à la poche ou cuillère.\n5. Parsemer de jaune d'oeuf en miettes (mimosa) + paprika.",vin:"Blanc sec fruité ou Champagne brut",notes:"La mayonnaise maison (jaune + moutarde + vinaigre + huile) est incomparable avec de l'huile de tournesol."},
{id:"FR189",co:"France",cat:"Plat",sous:"Volaille",nom:"Pintade Farcie aux Marrons",chef:"Tradition française de fête",bp:6,prep:30,cui:90,diff:2,qual:4,ig:[["Pintade entière",1800,"g"],["Marrons cuits",300,"g"],["Poitrine fumée",100,"g"],["Foie de pintade",100,"g"],["Oignons",1,"pièce"],["Cognac",3,"cs"],["Beurre",80,"g"],["Thym romarin",3,"branches"],["Sel poivre",1,"qs"]],et:"1. Farce : suer oignons + poitrine + foie haché + marrons émiettés dans beurre. Cognac. Assaisonner.\n2. Farcir la pintade. Brider.\n3. Frotter de beurre mou. Herbes sous la peau.\n4. Four 180°C 1h20 en arrosant toutes les 20 min.\n5. Reposer 15 min sous alu. Jus de rôtissage déglacé au cognac.",vin:"Pomerol ou Pommard",notes:"La pintade est plus sèche que le poulet — l'arrosage fréquent est indispensable."},
{id:"FR190",co:"France",cat:"Sauce / Base",sous:"Vinaigrette",nom:"Sauce Vierge aux Herbes",chef:"Tradition provençale moderne",bp:4,prep:10,cui:0,diff:1,qual:4,ig:[["Tomates mûres",3,"pièces"],["Olives noires",40,"g"],["Câpres",1,"cs"],["Basilic estragon ciboulette",3,"cs"],["Huile d'olive extra-vierge",6,"cs"],["Vinaigre de xérès",1,"cs"],["Citron",0.5,"pièce"],["Sel poivre",1,"qs"]],et:"1. Monder les tomates (ébouillanter 30 sec + eau glacée). Épépiner. Couper en petits dés.\n2. Hacher les olives. Ciseler finement toutes les herbes.\n3. Mélanger tomates + olives + câpres + herbes.\n4. Assaisonner avec huile + vinaigre + jus de citron + sel + poivre.\n5. Laisser mariner 15 min minimum à T° ambiante.",vin:"Usage : poissons grillés ou poêlés, légumes grillés",notes:"La sauce vierge est incomparable sur un bar ou une daurade grillée. Elle ne se cuit jamais."},
{id:"FR191",co:"France",cat:"Accompagnement",sous:"Champignons",nom:"Cèpes Sautés à la Persillade Gasconne",chef:"Tradition gasconne",bp:4,prep:10,cui:10,diff:1,qual:5,ig:[["Cèpes frais",600,"g"],["Ail",4,"gousses"],["Persil plat",4,"cs"],["Graisse de canard",3,"cs"],["Sel fleur de sel",1,"qs"],["Poivre noir",1,"qs"]],et:"1. Nettoyer les cèpes avec un pinceau. Ne jamais rincer. Couper en quartiers ou lamelles épaisses.\n2. Chauffer graisse de canard à feu très vif jusqu'à fumante.\n3. Saisir les cèpes en une seule couche sans remuer 3-4 min.\n4. Retourner. Saisir encore 2 min.\n5. Hors feu : ail haché très fin + persil. Mélanger rapidement. Fleur de sel.",vin:"Côtes de Gascogne rouge ou Bergerac rouge",notes:"La graisse de canard à feu très vif est la clé. Les cèpes ne doivent pas rendre d'eau — sinon ils bouillent au lieu de sauter."},
{id:"FR192",co:"France",cat:"Dessert",sous:"Glace",nom:"Glace à la Vanille de Madagascar",chef:"Tradition française classique",bp:6,prep:20,cui:15,diff:2,qual:5,ig:[["Lait entier frais",50,"cl"],["Crème fraîche 35%",20,"cl"],["Jaunes d'oeufs",6,"pièces"],["Sucre",150,"g"],["Gousses de vanille de Madagascar",2,"pièces"]],et:"1. Fendre et gratter les gousses. Infuser dans lait + crème chauffés 30 min à couvert.\n2. Fouetter jaunes + sucre jusqu'à ruban.\n3. Verser lait chaud sur les jaunes en fouettant. Recuire à feu doux jusqu'à 83°C (la nappe).\n4. Filtrer. Refroidir rapidement en bain glacé.\n5. Maturer 4h au froid. Turbiner 25-30 min.",vin:"Champagne Demi-sec ou Café",notes:"La maturation 4h avant de turbiner est indispensable pour une texture crémeuse."},
{id:"FR193",co:"France",cat:"Plat",sous:"Veau",nom:"Osso Buco à la Française",chef:"Tradition française inspirée de l'italienne",bp:4,prep:20,cui:90,diff:2,qual:4,ig:[["Rouelles de jarret de veau",4,"pièces"],["Oignons",2,"pièces"],["Carottes",2,"pièces"],["Vin blanc sec",25,"cl"],["Tomates concassées",400,"g"],["Bouillon de veau",20,"cl"],["Zeste d'orange non traité",1,"pièce"],["Thym laurier",2,"branches"],["Farine beurre",1,"qs"]],et:"1. Fariner les rouelles. Dorer dans beurre sur toutes les faces. Réserver.\n2. Suer oignons + carottes.\n3. Remettre veau + vin blanc + tomates + bouillon + zeste + herbes.\n4. Couvrir. Mijoter à feu doux 1h30.\n5. Gremolata française : zeste d'orange + persil + ail haché. Parsemer à la fin.",vin:"Meursault ou Côte de Beaune blanc",notes:"Le zeste d'orange remplace le citron de la version italienne — c'est la version provençale."},
{id:"FR194",co:"France",cat:"Assaisonnement",sous:"Condiment",nom:"Moutarde aux Herbes Maison",chef:"Tradition française artisanale",bp:4,prep:15,cui:0,diff:1,qual:4,ig:[["Moutarde de Dijon",150,"g"],["Estragon frais",3,"cs"],["Ciboulette",2,"cs"],["Persil plat",2,"cs"],["Cerfeuil",1,"cs"],["Échalote",1,"pièce"],["Sel poivre",1,"qs"]],et:"1. Ciseler finement toutes les herbes et l'échalote.\n2. Mélanger moutarde + herbes + échalote.\n3. Assaisonner selon goût.\n4. Laisser macérer 24h au réfrigérateur.\n5. Se conserve 2 semaines au froid.",vin:"Usage : viandes grillées, poissons, vinaigrettes, sandwichs",notes:"Cette moutarde aux herbes est incomparable avec des côtes de porc ou un poulet grillé."},
{id:"FR195",co:"France",cat:"Entrée",sous:"Gratinée",nom:"Soupe à l'Oignon Gratinée Lyonnaise",chef:"Tradition des bouchons lyonnais",bp:4,prep:20,cui:60,diff:2,qual:5,ig:[["Oignons jaunes",1200,"g"],["Beurre",60,"g"],["Vin blanc Mâcon",10,"cl"],["Bouillon de boeuf",120,"cl"],["Pain de campagne rassis",8,"tranches"],["Gruyère râpé",150,"g"],["Cognac",2,"cs"],["Sel poivre",1,"qs"]],et:"1. Émincer très finement tous les oignons. Faire fondre dans beurre à feu doux 40 min jusqu'à caramélisés dorés. Remuer souvent.\n2. Déglacer cognac + vin blanc. Réduire à sec.\n3. Mouiller avec bouillon. Frémir 15 min.\n4. Verser dans bols allant au four. Couvrir de pain rassis + gruyère râpé généreux.\n5. Four gril 250°C 5-7 min jusqu'à gratiné et bouillonnant.",vin:"Côte du Rhône blanc ou Mâcon-Villages blanc",notes:"La caramélisation des oignons pendant 40 min est le seul secret de cette soupe. Ne pas la brusquer."},
{id:"SA001",co:"France",cat:"Sauce / Base",sous:"Sauce mère",nom:"Sauce Béchamel",chef:"Tradition française classique",bp:4,prep:5,cui:10,diff:1,qual:5,ig:[["Beurre",40,"g"],["Farine T55",40,"g"],["Lait entier chaud",50,"cl"],["Sel poivre blanc",1,"qs"],["Muscade fraîche",1,"pincée"]],et:"1. Fondre le beurre à feu moyen. Ajouter la farine d'un coup. Remuer vigoureusement 2 min : le roux doit sentir la noisette.\n2. Retirer du feu. Verser le lait chaud en trois fois en fouettant énergiquement après chaque ajout pour éviter les grumeaux.\n3. Remettre sur feu moyen. Fouetter sans cesse jusqu'à épaississement (3-4 min).\n4. Assaisonner sel + poivre blanc + muscade.\n5. Filmer au contact si on ne l'utilise pas immédiatement.",vin:"Accompagnement : lasagnes, gratin, vol-au-vent",notes:"Ratio de base : 40g beurre / 40g farine / 50cl lait = béchamel classique. Doubler la farine = sauce très épaisse pour croquettes."},
{id:"SA002",co:"France",cat:"Sauce / Base",sous:"Sauce mère",nom:"Sauce Hollandaise Classique",chef:"Tradition française classique",bp:4,prep:10,cui:15,diff:3,qual:5,ig:[["Jaunes d'oeufs",4,"pièces"],["Beurre clarifié chaud",200,"g"],["Jus de citron",2,"cs"],["Eau froide",2,"cs"],["Sel poivre de Cayenne",1,"qs"]],et:"1. Fouetter jaunes + eau froide + sel dans un cul-de-poule au bain-marie à feu très doux. La T° ne doit pas dépasser 65°C.\n2. Fouetter jusqu'à la nappe : le mélange doit épaissir et faire le ruban, laisser une trace nette de fouet.\n3. Retirer du bain-marie. Incorporer le beurre clarifié chaud EN FILET TRÈS FIN en fouettant sans arrêt.\n4. Si la sauce devient trop épaisse, ajouter quelques gouttes d'eau tiède.\n5. Assaisonner jus de citron + poivre de Cayenne. Servir immédiatement.",vin:"Accompagnement : asperges, poisson poché, oeufs bénédictine",notes:"Si la sauce tranche (beurre et oeufs séparés) : commencer avec 1cs d'eau froide dans un bol propre et incorporer la sauce tranchée en filet."},
{id:"SA003",co:"France",cat:"Sauce / Base",sous:"Fond",nom:"Fond de Veau Brun",chef:"Tradition française classique",bp:8,prep:20,cui:240,diff:2,qual:5,ig:[["Os de veau et jarrets",2000,"g"],["Oignons",2,"pièces"],["Carottes",2,"pièces"],["Céleri",3,"branches"],["Concentré de tomates",2,"cs"],["Vin rouge",25,"cl"],["Bouquet garni",1,"pièce"],["Huile",3,"cs"]],et:"1. Four 220°C. Rôtir les os 30-40 min jusqu'à bien dorés et caramélisés.\n2. Dans grande marmite : dorer les légumes dans l'huile jusqu'à bien colorés.\n3. Ajouter concentré de tomates. Cuire 5 min (pinçage).\n4. Déglacer au vin rouge. Réduire à sec.\n5. Ajouter les os + 3L eau froide. Porter à frémissement. Écumer. Cuire 4-6h à feu très doux. Filtrer. Réduire si désiré.",vin:"Base : sauces brunes, jus de rôti, glace de viande",notes:"Se congèle parfaitement en cubes de glace. Un fond maison transforme radicalement la qualité de vos sauces."},
{id:"SA004",co:"France",cat:"Sauce / Base",sous:"Vinaigrette",nom:"Vinaigrette à la Moutarde",chef:"Tradition française",bp:4,prep:3,cui:0,diff:1,qual:5,ig:[["Moutarde de Dijon",1,"cc"],["Vinaigre de vin rouge",1,"cs"],["Huile d'olive extra-vierge",3,"cs"],["Sel fleur de sel",1,"qs"],["Poivre noir",1,"qs"],["Échalote",0.5,"pièce"]],et:"1. Dans un bol : moutarde + vinaigre + sel. Fouetter jusqu'à dissolution du sel.\n2. Verser l'huile EN FILET en fouettant constamment jusqu'à émulsion stable.\n3. Ajouter l'échalote ciselée très finement.\n4. Poivrer. Goûter, ajuster l'équilibre acide/gras.\n5. Utiliser immédiatement ou conserver au froid 1 semaine.",vin:"Toutes les salades vertes et composées",notes:"Ratio classique : 1 part vinaigre pour 3 parts huile. La moutarde est l'émulsifiant naturel."},
{id:"SA008",co:"France",cat:"Sauce / Base",sous:"Assaisonnement",nom:"Beurre Composé Maître d'Hôtel",chef:"Tradition française",bp:4,prep:10,cui:0,diff:1,qual:4,ig:[["Beurre doux pommade",150,"g"],["Persil plat ciselé très fin",3,"cs"],["Jus de citron",1,"cc"],["Sel fin",1,"cc"],["Poivre noir",1,"qs"]],et:"1. Sortir le beurre 1h avant pour qu'il soit en pommade parfaite.\n2. Mélanger beurre + persil + citron + sel + poivre à la fourchette jusqu'à homogène.\n3. Goûter et rectifier l'assaisonnement.\n4. Disposer sur film alimentaire, former un boudin serré, rouler. Réfrigérer 2h minimum.\n5. Trancher en rondelles de 1cm. Poser sur viandes et poissons chauds juste avant de servir.",vin:"Grillades, poissons, légumes vapeur",notes:"Se congèle 3 mois. Toujours prêt pour sublimer une grillade en quelques secondes."},
{id:"SA009",co:"France",cat:"Sauce / Base",sous:"Émulsion froide",nom:"Mayonnaise Montée à l'Ancienne",chef:"Auguste Escoffier",bp:4,prep:10,cui:0,diff:"Facile",qual:"Maison",ig:[["Jaunes d'œufs",2,""],["Huile de tournesol",200,"ml"],["Moutarde de Dijon",1,"c.s."],["Vinaigre de vin blanc",1,"c.c."],["Sel fin",1,"pincée"],["Poivre blanc",1,"pincée"]],et:"1. Sortir les ingrédients 30 min avant : jaunes et huile doivent être à température ambiante.\n2. Fouetter les jaunes avec la moutarde, le sel et le poivre jusqu'à blanchiment léger.\n3. Verser l'huile en filet très fin sans s'arrêter de fouetter — commencer goutte à goutte.\n4. Dès que l'émulsion prend, accélérer le versement de l'huile.\n5. Incorporer le vinaigre pour stabiliser et apporter l'acidité. Rectifier l'assaisonnement.\n6. Conserver au réfrigérateur. Si la mayo tourne, repartir d'un jaune neuf en incorporant le mélange raté en filet.",vin:"Pas de vin recommandé",notes:"Le secret : huile et œufs strictement à même température. La moutarde joue le rôle d'émulsifiant naturel."},
{id:"SA010",co:"France",cat:"Sauce / Base",sous:"Pâte de base",nom:"Pâte Feuilletée Rapide",chef:"Michel Roux",bp:6,prep:40,cui:0,diff:"Moyen",qual:"Maison",ig:[["Farine T55",250,"g"],["Beurre de tourage froid",200,"g"],["Eau très froide",125,"ml"],["Sel fin",5,"g"]],et:"1. Couper le beurre froid en cubes de 1 cm. Le mélanger grossièrement à la farine — technique de sablage rapide.\n2. Dissoudre le sel dans l'eau glacée. Verser sur le sablage, rassembler sans pétrir. La pâte doit rester hétérogène avec des morceaux de beurre visibles.\n3. Aplatir en rectangle, filmer et reposer 20 min au réfrigérateur.\n4. Premier tour double : étaler en rectangle 3 fois plus long que large, plier en 4. Filmer, reposer 20 min.\n5. Deuxième tour double : répéter l'opération. Reposer 20 min au frais.\n6. Troisième tour double : 6 tours au total. La pâte est prête à être abaissée.",vin:"Pas de vin recommandé",notes:"Méthode express : les morceaux de beurre visibles créent les feuillets. Ne pas trop travailler. Se congèle parfaitement après le 4e tour."},
{id:"SA011",co:"France",cat:"Sauce / Base",sous:"Beurre émulsionné",nom:"Beurre Blanc de Loire",chef:"Clémence Lefeuvre",bp:4,prep:5,cui:15,diff:"Moyen",qual:"Fine",ig:[["Beurre doux très froid",250,"g"],["Échalotes",3,""],["Muscadet ou Gros Plant",100,"ml"],["Vinaigre de vin blanc",50,"ml"],["Sel",1,"pincée"],["Poivre blanc",1,"pincée"]],et:"1. Ciseler finement les échalotes. Les placer dans une casserole avec le vin blanc et le vinaigre.\n2. Réduire à feu moyen jusqu'à quasi sec — il doit rester environ 2 c.s. de liquide.\n3. Retirer du feu. Incorporer le beurre très froid coupé en cubes, un à un, en fouettant vivement.\n4. Replacer brièvement sur feu très doux si nécessaire — maintenir entre 60 et 65 °C, jamais en ébullition.\n5. Quand tout le beurre est monté, passer au chinois fin si désiré. Assaisonner.\n6. Servir immédiatement sur poisson rôti, Saint-Jacques poêlées ou asperges blanches.",vin:"Muscadet sur lie ou Sancerre blanc",notes:"Ne jamais dépasser 70 °C sinon le beurre se clarifie et l'émulsion casse. À préparer à la dernière minute."},
{id:"SA012",co:"France",cat:"Sauce / Base",sous:"Fond et fumet",nom:"Fond Brun de Veau Maison",chef:"Auguste Escoffier",bp:8,prep:30,cui:240,diff:"Avancé",qual:"Grande cuisine",ig:[["Os de veau (jarret, cou)",2000,"g"],["Carottes",200,"g"],["Oignons",150,"g"],["Céleri branche",80,"g"],["Concentré de tomate",2,"c.s."],["Bouquet garni",1,""],["Ail",3,"gousses"],["Eau froide",3000,"ml"],["Huile neutre",2,"c.s."]],et:"1. Préchauffer le four à 220 °C. Huiler les os et les rôtir 40 min jusqu'à coloration acajou profonde, sans brûler.\n2. Couper les légumes en mirepoix grossière. Les colorer dans la rôtissoire déglacée en grattant les sucs caramélisés.\n3. Ajouter le concentré de tomate, cuire 5 min à feu vif. Déglacer à l'eau froide en raclant bien le fond.\n4. Transférer os, légumes et jus dans une grande marmite. Couvrir d'eau froide.\n5. Porter à frémissement. Écumer soigneusement. Ajouter bouquet garni et ail. Maintenir à frémissement 4 h.\n6. Passer au chinois étamine. Réduire de moitié pour obtenir un demi-glace. Dégraisser à froid.",vin:"Pas de vin recommandé",notes:"La caramélisation des os est l'étape critique : c'est le Maillard qui donne la couleur et le goût. Congeler en glaçons pour usage quotidien."}
);
